import fs from 'fs';
import path from 'path';
import { program } from 'commander';
import { FileProcessor } from './fileProcessor';
import { RegexRenameStrategy } from './strategies/regexRenameStrategy';

program
  .name('bulk-rename')
  .description('Rename files in bulk using regex patterns')
  .version('1.0.0')
  .requiredOption('-p, --pattern <pattern>', 'Regex pattern to match')
  .requiredOption('-r, --replacement <replacement>', 'Replacement string')
  .option('-d, --directory <directory>', 'Target directory', process.cwd())
  .option('-f, --filter <filter>', 'Filter files by pattern', '.*')
  .option('-n, --dry-run', 'Show what would be renamed without actually renaming', false)
  .parse(process.argv);

const options = program.opts();
const strategy = new RegexRenameStrategy(options.pattern, options.replacement);
const processor = new FileProcessor(strategy);

try {
  const files = fs.readdirSync(options.directory)
    .filter(file => new RegExp(options.filter).test(file))
    .map(file => path.join(options.directory, file));

  processor.processFiles(files, options.dryRun);
} catch (error) {
  console.error('Error:', error.message);
  process.exit(1);
}
