import fs from 'fs';
import path from 'path';
import { FileProcessStrategy } from './strategies/fileProcessStrategy';

export class FileProcessor {
  private strategy: FileProcessStrategy;

  constructor(strategy: FileProcessStrategy) {
    this.strategy = strategy;
  }

  setStrategy(strategy: FileProcessStrategy): void {
    this.strategy = strategy;
  }

  processFiles(filePaths: string[], dryRun = false): void {
    filePaths.forEach(filePath => {
      const directory = path.dirname(filePath);
      const filename = path.basename(filePath);
      const newFilename = this.strategy.process(filename);

      if (newFilename !== filename) {
        const newPath = path.join(directory, newFilename);

        if (dryRun) {
          console.log(`Would rename: ${filePath} -> ${newPath}`);
        } else {
          try {
            fs.renameSync(filePath, newPath);
            console.log(`Renamed: ${filePath} -> ${newPath}`);
          } catch (error) {
            console.error(`Failed to rename ${filePath}: ${error.message}`);
          }
        }
      }
    });
  }
}
