import { FileProcessStrategy } from './fileProcessStrategy';

export class RegexRenameStrategy implements FileProcessStrategy {
  private pattern: RegExp;
  private replacement: string;

  constructor(pattern: string, replacement: string) {
    this.pattern = new RegExp(pattern);
    this.replacement = replacement;
  }

  process(filename: string): string {
    return filename.replace(this.pattern, this.replacement);
  }
}
