import json
import networkx as nx
import matplotlib.pyplot as plt
from typing import Dict, Any, List, Set


class JsonSchemaVisualizer:
    def __init__(self, schema_file_path: str):
        self.schema_file_path = schema_file_path
        self.schema = None
        self.graph = nx.DiGraph()

    def load_schema(self) -> Dict[str, Any]:
        """Load JSON schema from file."""
        with open(self.schema_file_path, 'r') as file:
            self.schema = json.load(file)
        return self.schema

    def parse_schema(self) -> nx.DiGraph:
        """Parse JSON schema into a graph representation."""
        if not self.schema:
            self.load_schema()

        self._process_node(self.schema, "root")
        return self.graph

    def _process_node(self, node: Dict[str, Any], node_name: str) -> None:
        """Process a schema node and add it to the graph."""
        self.graph.add_node(node_name)

        if not isinstance(node, dict):
            return

        for key, value in node.items():
            if key == "properties" and isinstance(value, dict):
                self._process_properties(value, node_name)
            elif key == "items" and isinstance(value, dict):
                self._process_items(value, node_name)
            elif key == "$ref" and isinstance(value, str):
                self._process_reference(value, node_name)

    def _process_properties(self, properties: Dict[str, Any], parent_name: str) -> None:
        """Process properties of a schema object."""
        for prop_name, prop_value in properties.items():
            child_name = f"{parent_name}.{prop_name}"
            self.graph.add_node(child_name)
            self.graph.add_edge(parent_name, child_name)
            self._process_node(prop_value, child_name)

    def _process_items(self, items: Dict[str, Any], parent_name: str) -> None:
        """Process items in an array schema."""
        child_name = f"{parent_name}[]"
        self.graph.add_node(child_name)
        self.graph.add_edge(parent_name, child_name)
        self._process_node(items, child_name)

    def _process_reference(self, ref: str, parent_name: str) -> None:
        """Process a schema reference."""
        ref_name = ref.split('/')[-1]
        self.graph.add_edge(parent_name, ref_name)

    def visualize(self) -> None:
        """Visualize the schema graph."""
        if not self.graph.nodes():
            self.parse_schema()

        plt.figure(figsize=(12, 8))
        pos = nx.spring_layout(self.graph)
        nx.draw(
            self.graph,
            pos,
            with_labels=True,
            node_color="lightblue",
            node_size=1500,
            edge_color="gray",
            arrows=True
        )
        plt.title("JSON Schema Visualization")
        plt.show()

    def get_schema_summary(self) -> Dict[str, int]:
        """Generate a summary of the schema structure."""
        if not self.graph.nodes():
            self.parse_schema()

        return {
            "total_nodes": len(self.graph.nodes()),
            "total_edges": len(self.graph.edges()),
            "depth": self._calculate_max_depth()
        }

    def _calculate_max_depth(self) -> int:
        """Calculate the maximum depth of the schema."""
        depths = {}
        max_depth = 0

        for node in nx.topological_sort(self.graph):
            if node == "root":
                depths[node] = 0
            else:
                parent_depths = [depths[parent] for parent in self.graph.predecessors(node)]
                if parent_depths:
                    depths[node] = max(parent_depths) + 1
                    max_depth = max(max_depth, depths[node])

        return max_depth
