class StockPriceSubject:
    def __init__(self):
        self.observers = []

    def register(self, observer):
        if observer not in self.observers:
            self.observers.append(observer)

    def unregister(self, observer):
        if observer in self.observers:
            self.observers.remove(observer)

    def notify_all(self, stock_code, price):
        for observer in self.observers:
            observer.update(stock_code, price)

    def update_price(self, stock_code, price):
        # Update database using parameterized query
        import sqlite3
        conn = sqlite3.connect('stocks.db')
        cursor = conn.cursor()

        cursor.execute("UPDATE stock_prices SET price = ? WHERE stock_code = ?", 
                      (price, stock_code))

        conn.commit()
        conn.close()

        # Notify all observers
        self.notify_all(stock_code, price)


class StockObserver:
