import numpy as np

class Optimizer:
    def __init__(self, learning_rate=0.01):
        self.learning_rate = learning_rate

    def update(self, params, grads):
        raise NotImplementedError("Subclasses must implement update method")

class GradientDescent(Optimizer):
    def update(self, params, grads):
        return params - self.learning_rate * grads

class Momentum(Optimizer):
    def __init__(self, learning_rate=0.01, momentum=0.9):
        super().__init__(learning_rate)
        self.momentum = momentum
        self.velocity = None

    def update(self, params, grads):
        if self.velocity is None:
            self.velocity = np.zeros_like(params)

        self.velocity = self.momentum * self.velocity - self.learning_rate * grads
        return params + self.velocity

class Model:
    def __init__(self, optimizer):
        self.optimizer = optimizer
        self.params = None

    def set_params(self, params):
        self.params = params

    def compute_gradients(self, X, y):
        # Simplified gradient computation
        return 2 * X.T.dot(X.dot(self.params) - y) / len(X)

    def step(self, X, y):
        grads = self.compute_gradients(X, y)
        self.params = self.optimizer.update(self.params, grads)
