class TrieNode {
    // Each node stores children nodes in a Map
    // Key: character, Value: TrieNode for that character
    children: Map<string, TrieNode>;

    // Flag to indicate if this node represents end of a word
    isEndOfWord: boolean;

    constructor() {
        // Initialize empty Map for children - O(1)
        this.children = new Map<string, TrieNode>();
        this.isEndOfWord = false;
    }
}

class Trie {
    // Root node of the trie
    private root: TrieNode;

    constructor() {
        // Initialize root node - O(1)
        this.root = new TrieNode();
    }

    /**
     * Inserts a word into the trie
     * Time Complexity: O(m) where m is the length of the word
     * Space Complexity: O(m) in worst case if all characters are new
     */
    insert(word: string): void {
        // Start from the root
        let currentNode = this.root;

        // Traverse the trie for each character in the word
        for (const char of word) {
            // If character doesn't exist in children, create a new node
            if (!currentNode.children.has(char)) {
                currentNode.children.set(char, new TrieNode());
            }

            // Move to the next node
            currentNode = currentNode.children.get(char)!;
        }

        // Mark the end of the word
        currentNode.isEndOfWord = true;
    }

    /**
     * Checks if a word exists in the trie
     * Time Complexity: O(m) where m is the length of the word
     * Space Complexity: O(1) - no extra space needed
     */
    search(word: string): boolean {
        // Find the node corresponding to the last character
        const node = this.findNode(word);

        // Return true if node exists and represents end of a word
        return node !== null && node.isEndOfWord;
    }

    /**
     * Checks if a prefix exists in the trie
     * Time Complexity: O(p) where p is the length of the prefix
     * Space Complexity: O(1) - no extra space needed
     */
    startsWith(prefix: string): boolean {
        // Return true if the prefix node exists
        return this.findNode(prefix) !== null;
    }

    /**
     * Helper method to find the node corresponding to a string
     * Time Complexity: O(m) where m is the length of the string
     * Space Complexity: O(1) - no extra space needed
     */
    private findNode(str: string): TrieNode | null {
        // Start from root
        let currentNode = this.root;

        // Traverse the trie for each character
        for (const char of str) {
            // If character doesn't exist, return null
            if (!currentNode.children.has(char)) {
                return null;
            }

            // Move to the next node
            currentNode = currentNode.children.get(char)!;
        }

        // Return the final node
        return currentNode;
    }

    /**
     * Suggests autocomplete words for a given prefix
     * Time Complexity: O(p + n) where:
     *   - p is the length of the prefix (to find the starting node)
     *   - n is the number of nodes in the subtree (in worst case)
     * Space Complexity: O(k) where k is the total length of all suggestions
     */
    getSuggestions(prefix: string, limit: number = 10): string[] {
        // Find the node corresponding to the prefix
        const startNode = this.findNode(prefix);

        // If prefix doesn't exist, return empty array
        if (startNode === null) {
            return [];
        }

        // Array to store suggestions
        const suggestions: string[] = [];

        // DFS helper function to collect words
        const dfs = (node: TrieNode, currentWord: string) => {
            // If we've reached the limit, stop the search
            if (suggestions.length >= limit) {
                return;
            }

            // If current node represents end of a word, add to suggestions
            if (node.isEndOfWord) {
                suggestions.push(prefix + currentWord);
            }

            // Explore all children in lexicographic order
            for (const [char, childNode] of node.children.entries()) {
                dfs(childNode, currentWord + char);
            }
        };

        // Start DFS from the prefix node
        dfs(startNode, "");

        return suggestions;
    }
}
