import numpy as np
from scipy import sparse

def sparse_matrix_multiply(A, B):
    # Convert to sparse format if inputs are dense
    if not sparse.issparse(A):
        A = sparse.csr_matrix(A)
    if not sparse.issparse(B):
        B = sparse.csr_matrix(B)

    # Ensure A is in CSR format and B is in CSC format for optimal multiplication
    if not isinstance(A, sparse.csr_matrix):
        A = A.tocsr()
    if not isinstance(B, sparse.csc_matrix):
        B = B.tocsc()

    # Perform the multiplication using sparse dot product
    return A.dot(B)
