export enum PaymentStatus {
  SUCCESS = 'success',
  FAILURE = 'failure',
  TIMEOUT = 'timeout'
}

export interface PaymentResult {
  status: PaymentStatus;
  transactionId?: string;
  errorMessage?: string;
}

export interface PaymentProvider {
  processPayment(amount: number, currency: string, cardDetails: any): Promise<PaymentResult>;
}

export class PaymentProcessor {
  private provider: PaymentProvider;

  constructor(provider: PaymentProvider) {
    this.provider = provider;
  }

  async processPayment(amount: number, currency: string, cardDetails: any): Promise<PaymentResult> {
    try {
      return await this.provider.processPayment(amount, currency, cardDetails);
    } catch (error) {
      return {
        status: PaymentStatus.FAILURE,
        errorMessage: error instanceof Error ? error.message : 'Unknown error'
      };
    }
  }
}
