      status: PaymentStatus.FAILURE,
      errorMessage: 'Payment declined'
    };
    const mockProvider = new MockPaymentProvider(mockResult);
    const processor = new PaymentProcessor(mockProvider);

    const result = await processor.processPayment(100, 'USD', cardDetails);

