import { S3Client, PutObjectCommand } from '@aws-sdk/client-s3';
import { Readable } from 'stream';
import winston from 'winston';

// Configure logger
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.Console(),
    new winston.transports.File({ filename: 'file-upload.log' })
  ]
});

export interface FileUploadOptions {
  bucketName: string;
  key: string;
  file: Buffer | Readable;
  contentType?: string;
  metadata?: Record<string, string>;
  maxRetries?: number;
  retryDelay?: number;
}

export class FileUploadService {
  private s3Client: S3Client;

  constructor(region: string = 'us-east-1') {
    this.s3Client = new S3Client({ region });
  }

  async uploadFile({
    bucketName,
    key,
    file,
    contentType,
    metadata,
    maxRetries = 3,
    retryDelay = 1000
  }: FileUploadOptions): Promise<string> {
    let attempts = 0;

    while (true) {
      try {
        attempts++;

        const command = new PutObjectCommand({
          Bucket: bucketName,
          Key: key,
          Body: file,
          ContentType: contentType,
          Metadata: metadata
        });

        await this.s3Client.send(command);

        logger.info('File uploaded successfully', {
          bucket: bucketName,
          key,
          attempts
        });

        return `https://${bucketName}.s3.amazonaws.com/${key}`;
      } catch (error: any) {
        const isRetryable = this.isRetryableError(error);

        logger.error('Error uploading file', {
          bucket: bucketName,
          key,
          error: error.message,
          attempts,
          isRetryable
        });

        if (!isRetryable || attempts >= maxRetries) {
          throw new Error(`Failed to upload file after ${attempts} attempts: ${error.message}`);
        }

        logger.info('Retrying upload', {
          bucket: bucketName,
          key,
          attempt: attempts,
          nextAttemptIn: retryDelay
        });

        await new Promise(resolve => setTimeout(resolve, retryDelay * attempts));
      }
    }
  }

  private isRetryableError(error: any): boolean {
    const retryableCodes = [
      'NetworkingError',
      'TimeoutError',
      'RequestTimeout',
      'InternalError',
      'ServiceUnavailable',
      'ECONNRESET',
      'ETIMEDOUT',
      'EPIPE'
    ];

    return retryableCodes.some(code => 
      error.name === code || 
      error.code === code || 
      (error.message && error.message.includes(code))
    );
  }
}
