// Message interface
interface Message {
  id: string;
  topic: string;
  payload: any;
  timestamp: number;
}

// Pub-Sub System using Redis Streams
class PubSubSystem {
  private redis: any;
  private subscribers: Map<string, Set<Function>>;
  private consumerGroups: Map<string, string>;
  private clientId: string;

  constructor() {
    this.redis = require('redis').createClient({
      url: process.env.REDIS_URL || 'redis://localhost:6379',
      socket: {
        reconnectStrategy: (attempts: number) => Math.min(attempts * 100, 3000)
      }
    });
    this.subscribers = new Map();
    this.consumerGroups = new Map();
    this.clientId = `consumer-${Date.now()}-${Math.floor(Math.random() * 1000)}`;

    this.init();
  }

  private async init() {
    await this.redis.connect();

    // Setup error handling
    this.redis.on('error', (err: Error) => {
      console.error('Redis connection error:', err);
    });
  }

  async publish(topic: string, payload: any): Promise<string> {
    const message: Message = {
      id: Date.now().toString(),
      topic,
      payload,
      timestamp: Date.now()
    };

    // Add message to Redis Stream
    return await this.redis.xAdd(
      topic,
      '*', // Auto-generate ID
      { data: JSON.stringify(message) },
      { trimming: 'MAXLEN', limit: 10000 } // Limit stream size
    );
  }

  async subscribe(topic: string, callback: Function): Promise<void> {
    // Create subscriber set if it doesn't exist
    if (!this.subscribers.has(topic)) {
      this.subscribers.set(topic, new Set());

      // Create consumer group if it doesn't exist
      if (!this.consumerGroups.has(topic)) {
        try {
          await this.redis.xGroupCreate(topic, 'processors', '0', { MKSTREAM: true });
        } catch (err: any) {
          // Group may already exist, which is fine
          if (!err.message.includes('BUSYGROUP')) {
            throw err;
          }
        }
        this.consumerGroups.set(topic, 'processors');
      }

      // Start processing messages for this topic
      this.startConsumer(topic);
    }

    // Add callback to subscribers
    this.subscribers.get(topic)!.add(callback);
  }

  async unsubscribe(topic: string, callback: Function): Promise<void> {
    if (this.subscribers.has(topic)) {
      const topicSubscribers = this.subscribers.get(topic)!;
      topicSubscribers.delete(callback);

      if (topicSubscribers.size === 0) {
        this.subscribers.delete(topic);
      }
    }
  }

  private async startConsumer(topic: string) {
    // Process in batches for efficiency
    const BATCH_SIZE = 100;

    const processBatch = async () => {
      try {
        // Read new messages
        const results = await this.redis.xReadGroup(
          'GROUP', 'processors', this.clientId,
          'COUNT', BATCH_SIZE,
          'STREAMS', topic, '>'
        );

        if (results && results.length > 0) {
          const messages = results[0].messages;

          for (const msg of messages) {
            const message = JSON.parse(msg.message.data);

            // Notify all subscribers
            const subscribers = this.subscribers.get(topic);
            if (subscribers) {
              for (const callback of subscribers) {
                try {
                  callback(message);
                } catch (err) {
                  console.error('Error in subscriber callback:', err);
                }
              }
            }

            // Acknowledge message processing
            await this.redis.xAck(topic, 'processors', msg.id);
          }
        }
      } catch (err) {
        console.error('Error processing messages:', err);
      }

      // Continue processing if we still have subscribers
      if (this.subscribers.has(topic)) {
        setImmediate(processBatch);
      }
    };

    processBatch();
  }

  async close() {
    await this.redis.quit();
  }
}

// Horizontal scaling support with cluster mode
class ScalablePubSub {
  private instances: PubSubSystem[];
  private nodeCount: number;

  constructor(nodeCount = 4) {
    this.nodeCount = nodeCount;
    this.instances = Array(nodeCount).fill(null).map(() => new PubSubSystem());
  }

  // Shard by topic for horizontal scaling
  private getInstanceForTopic(topic: string): PubSubSystem {
    const hash = this.hashCode(topic);
    const index = Math.abs(hash % this.nodeCount);
    return this.instances[index];
  }

  private hashCode(str: string): number {
    let hash = 0;
    for (let i = 0; i < str.length; i++) {
      hash = ((hash << 5) - hash) + str.charCodeAt(i);
      hash |= 0; // Convert to 32bit integer
    }
    return hash;
  }

  async publish(topic: string, payload: any): Promise<string> {
    return this.getInstanceForTopic(topic).publish(topic, payload);
  }

  async subscribe(topic: string, callback: Function): Promise<void> {
    return this.getInstanceForTopic(topic).subscribe(topic, callback);
  }

  async unsubscribe(topic: string, callback: Function): Promise<void> {
    return this.getInstanceForTopic(topic).unsubscribe(topic, callback);
  }

  async close() {
    await Promise.all(this.instances.map(instance => instance.close()));
  }
}

// Example usage
async function example() {
  const pubSub = new ScalablePubSub();

  // Subscribe to a topic
  await pubSub.subscribe('orders', (message) => {
    console.log('Received order:', message);
  });

  // Publish a message
  await pubSub.publish('orders', { id: '12345', amount: 99.99 });
}
