import { createClient } from 'redis';
import { randomBytes, timingSafeEqual } from 'crypto';

export class RedisSessionStore {
  private client;
  private prefix: string;
  private defaultTTL: number;

  constructor(options: {
    redisUrl: string;
    prefix?: string;
    defaultTTL?: number;
  }) {
    this.client = createClient({ url: options.redisUrl });
    this.client.connect();
    this.prefix = options.prefix || 'session:';
    this.defaultTTL = options.defaultTTL || 86400; // 24 hours default
  }

  async create(data: Record<string, any>, ttl?: number): Promise<string> {
    const sessionId = randomBytes(32).toString('hex');
    const sessionKey = this.prefix + sessionId;

    await this.client.set(sessionKey, JSON.stringify(data), {
      EX: ttl || this.defaultTTL
    });

    return sessionId;
  }

  async get(sessionId: string): Promise<Record<string, any> | null> {
    const sessionKey = this.prefix + sessionId;
    const data = await this.client.get(sessionKey);

    return data ? JSON.parse(data) : null;
  }

  async verify(providedToken: string, expectedToken: string): Promise<boolean> {
    try {
      return timingSafeEqual(
        Buffer.from(providedToken), 
        Buffer.from(expectedToken)
      );
    } catch {
      return false;
    }
  }

  async update(sessionId: string, data: Record<string, any>, ttl?: number): Promise<boolean> {
    const sessionKey = this.prefix + sessionId;

    const exists = await this.client.exists(sessionKey);
    if (!exists) return false;

    await this.client.set(sessionKey, JSON.stringify(data), {
      EX: ttl || this.defaultTTL
    });

    return true;
  }

  async delete(sessionId: string): Promise<boolean> {
    const sessionKey = this.prefix + sessionId;
    const result = await this.client.del(sessionKey);
    return result > 0;
  }

  async disconnect(): Promise<void> {
    await this.client.disconnect();
  }
}
