  registerPlugin(plugin: Plugin): void {
    if (plugin.transformer) {
      this.transformers.push(plugin.transformer);
    }
    if (plugin.generator) {
      this.generators.push(plugin.generator);
    }
  }

  async processContent(markdown: string): Promise<Map<string, string>> {
    let content = markdown;

    // Apply all transformers in sequence
    for (const transformer of this.transformers) {
      content = await transformer.transform(content);
    }

    // Generate all requested output formats
    const outputs = new Map<string, string>();
    for (const generator of this.generators) {
      const output = await generator.generate(content);
      outputs.set(generator.format, output);
    }

    return outputs;
  }
}
