export class SyntaxHighlightTransformer implements MarkdownTransformer {
  async transform(content: string): Promise<string> {
    // Implementation to add syntax highlighting to code blocks
    return content.replace(/```(\w+)\n([\s\S]*?)```/g, (_, language, code) => {
      return `~~~${language}\n${code}\n~~~`;
