// src/services/orderService.js
class OrderService {
  constructor(orderRepository, productRepository) {
    this.orderRepository = orderRepository;
    this.productRepository = productRepository;
  }

  async createOrder(orderData) {
    const { customerId, items } = orderData;

    // Calculate order total
    let total = 0;
    for (const item of items) {
      const [product] = await this.productRepository.findById(item.productId);
      if (!product || product.stock < item.quantity) {
        throw new Error(`Product ${item.productId} is not available in requested quantity`);
      }
      total += product.price * item.quantity;
    }

    // Create order
    const [order] = await this.orderRepository.create({
      customerId,
      status: 'pending',
      total
    });

    // Create order items and update stock
    for (const item of items) {
      const [product] = await this.productRepository.findById(item.productId);
      await this.orderRepository.createOrderItem({
        orderId: order.id,
        productId: item.productId,
        quantity: item.quantity,
        price: product.price
      });
      await this.productRepository.updateStock(item.productId, item.quantity);
    }

    return order;
  }

  async getOrderDetails(id) {
    const [order] = await this.orderRepository.findById(id);
    if (!order) {
      throw new Error('Order not found');
    }

    const items = await this.orderRepository.getOrderItems(id);
    return { ...order, items };
  }

  async updateOrderStatus(id, status) {
    return this.orderRepository.updateStatus(id, status);
  }

  async getCustomerOrders(customerId) {
    return this.orderRepository.findByCustomerId(customerId);
  }
}

module.exports = OrderService;
