```main.js
const { app, BrowserWindow, Menu, dialog, ipcMain } = require('electron');
const path = require('path');
const fs = require('fs');
const os = require('os');
const Store = require('electron-store');

const store = new Store();
let mainWindow;

// Platform-specific file paths
const getNotesDirectory = () => {
  const platform = process.platform;
  let notesDir;

  if (platform === 'win32') {
    notesDir = path.join(app.getPath('documents'), 'ElectronNotes');
  } else if (platform === 'darwin') {
    notesDir = path.join(app.getPath('userData'), 'Notes');
  } else {
    // Linux and others
    notesDir = path.join(os.homedir(), '.electron-notes');
  }

  if (!fs.existsSync(notesDir)) {
    fs.mkdirSync(notesDir, { recursive: true });
  }

  return notesDir;
};

function createWindow() {
  mainWindow = new BrowserWindow({
    width: 900,
    height: 700,
    webPreferences: {
      nodeIntegration: true,
      contextIsolation: false
    }
  });

  mainWindow.loadFile('index.html');

  const template = [
    {
      label: 'File',
      submenu: [
        {
          label: 'New Note',
          accelerator: 'CmdOrCtrl+N',
          click: () => mainWindow.webContents.send('new-note')
        },
        {
          label: 'Save Note',
          accelerator: 'CmdOrCtrl+S',
          click: () => mainWindow.webContents.send('save-note')
        },
        {
          label: 'Open Note',
          accelerator: 'CmdOrCtrl+O',
          click: () => mainWindow.webContents.send('open-note')
        },
        { type: 'separator' },
        {
          label: 'Exit',
          accelerator: process.platform === 'darwin' ? 'Cmd+Q' : 'Alt+F4',
          click: () => app.quit()
        }
      ]
    },
    {
      label: 'Edit',
      submenu: [
        { role: 'undo' },
        { role: 'redo' },
        { type: 'separator' },
        { role: 'cut' },
        { role: 'copy' },
        { role: 'paste' }
      ]
    }
  ];

  const menu = Menu.buildFromTemplate(template);
  Menu.setApplicationMenu(menu);
}

app.whenReady().then(() => {
  createWindow();

  app.on('activate', function () {
    if (BrowserWindow.getAllWindows().length === 0) createWindow();
  });
});

app.on('window-all-closed', function () {
  if (process.platform !== 'darwin') app.quit();
});

// IPC handlers for file operations
ipcMain.handle('save-file', async (event, { title, content }) => {
  const notesDir = getNotesDirectory();
  const filePath = path.join(notesDir, `${title}.txt`);

  try {
    await fs.promises.writeFile(filePath, content, 'utf8');
    return { success: true, path: filePath };
  } catch (error) {
    return { success: false, error: error.message };
  }
});

ipcMain.handle('load-file', async (event, filePath) => {
  try {
    const content = await fs.promises.readFile(filePath, 'utf8');
    return { success: true, content };
  } catch (error) {
    return { success: false, error: error.message };
  }
});

ipcMain.handle('get-notes-list', async () => {
  const notesDir = getNotesDirectory();
  try {
    const files = await fs.promises.readdir(notesDir);
    const notes = files
      .filter(file => file.endsWith('.txt'))
      .map(file => ({
        name: file.replace('.txt', ''),
        path: path.join(notesDir, file)
      }));
    return { success: true, notes };
  } catch (error) {
    return { success: false, error: error.message };
  }
});
