```renderer.js
const { ipcRenderer } = require('electron');

let currentNote = {
  title: '',
  content: '',
  path: null
};

const notesList = document.getElementById('notes-list');
const noteTitle = document.getElementById('note-title');
const noteContent = document.getElementById('note-content');
const saveBtn = document.getElementById('save-btn');
const newNoteBtn = document.getElementById('new-note-btn');

// Load notes list on startup
loadNotesList();

// Event listeners
saveBtn.addEventListener('click', saveNote);
newNoteBtn.addEventListener('click', createNewNote);
noteTitle.addEventListener('input', updateCurrentNote);
noteContent.addEventListener('input', updateCurrentNote);

// IPC event listeners
ipcRenderer.on('new-note', createNewNote);
ipcRenderer.on('save-note', saveNote);
ipcRenderer.on('open-note', loadNotesList);

function updateCurrentNote() {
  currentNote.title = noteTitle.value;
  currentNote.content = noteContent.value;
}

async function saveNote() {
  if (!currentNote.title) {
    alert('Please enter a note title');
    return;
  }

  const result = await ipcRenderer.invoke('save-file', {
    title: currentNote.title,
    content: currentNote.content
  });

  if (result.success) {
    currentNote.path = result.path;
    loadNotesList();
  } else {
    alert(`Failed to save note: ${result.error}`);
  }
}

function createNewNote() {
  currentNote = {
    title: '',
    content: '',
    path: null
  };

  noteTitle.value = '';
  noteContent.value = '';

  // Clear active state from all notes
  const noteItems = document.querySelectorAll('.note-item');
  noteItems.forEach(item => item.classList.remove('active'));
}

async function loadNotesList() {
  const result = await ipcRenderer.invoke('get-notes-list');

  if (result.success) {
    notesList.innerHTML = '';

    result.notes.forEach(note => {
      const noteItem = document.createElement('div');
      noteItem.className = 'note-item';
      if (currentNote.path === note.path) {
        noteItem.classList.add('active');
      }

      noteItem.textContent = note.name;
      noteItem.addEventListener('click', () => loadNote(note.path));

      notesList.appendChild(noteItem);
    });
  } else {
    console.error('Failed to load notes list:', result.error);
  }
}

async function loadNote(filePath) {
  const result = await ipcRenderer.invoke('load-file', filePath);

  if (result.success) {
    const fileName = filePath.split(/[\\/]/).pop().replace('.txt', '');

    currentNote = {
      title: fileName,
      content: result.content,
      path: filePath
    };

    noteTitle.value = currentNote.title;
    noteContent.value = currentNote.content;

    // Update active state
    const noteItems = document.querySelectorAll('.note-item');
    noteItems.forEach(item => {
      item.classList.remove('active');
      if (item.textContent === fileName) {
        item.classList.add('active');
      }
    });
  } else {
    alert(`Failed to load note: ${result.error}`);
  }
