```typescript:src/TransactionLedger.ts
import crypto from 'crypto';

interface Transaction {
  id: string;
  timestamp: Date;
  userId: string;
  accountId: string;
  amount: number;
  balanceAfter: number;
  reason: string;
  signature: string;
}

interface TransactionQuery {
  userId?: string;
  accountId?: string;
  startDate?: Date;
  endDate?: Date;
  minAmount?: number;
  maxAmount?: number;
}

class TransactionLedger {
  private transactions: Transaction[] = [];
  private privateKey: crypto.KeyObject;

  constructor(privateKeyPath: string) {
    // In production, load private key securely
    this.privateKey = crypto.createPrivateKey({ key: privateKeyPath, format: 'pem' });
  }

  recordTransaction(
    userId: string,
    accountId: string,
    amount: number, 
    balanceAfter: number,
    reason: string
  ): Transaction {
    const transaction: Omit<Transaction, 'signature'> = {
      id: crypto.randomUUID(),
      timestamp: new Date(),
      userId,
      accountId,
      amount,
      balanceAfter,
      reason
    };

    // Create digital signature of transaction data
    const dataToSign = JSON.stringify(transaction);
    const signature = crypto.sign('sha256', Buffer.from(dataToSign), this.privateKey).toString('base64');

    const signedTransaction: Transaction = {
      ...transaction,
      signature
    };

    this.transactions.push(signedTransaction);
    return signedTransaction;
  }

  verifyTransaction(transaction: Transaction): boolean {
    const { signature, ...transactionData } = transaction;
    const dataToVerify = JSON.stringify(transactionData);
    return crypto.verify(
      'sha256',
      Buffer.from(dataToVerify),
      this.privateKey.export({ type: 'spki', format: 'pem' }),
      Buffer.from(signature, 'base64')
    );
  }

  queryTransactions(query: TransactionQuery, isAdmin: boolean): Transaction[] {
    if (!isAdmin) {
      throw new Error('Only administrators can query transactions');
    }

    return this.transactions.filter(transaction => {
      if (query.userId && transaction.userId !== query.userId) return false;
      if (query.accountId && transaction.accountId !== query.accountId) return false;
      if (query.startDate && transaction.timestamp < query.startDate) return false;
      if (query.endDate && transaction.timestamp > query.endDate) return false;
      if (query.minAmount && transaction.amount < query.minAmount) return false;
      if (query.maxAmount && transaction.amount > query.maxAmount) return false;
      return true;
    });
  }

  exportLedger(isAdmin: boolean): Transaction[] {
    if (!isAdmin) {
      throw new Error('Only administrators can export the full ledger');
    }
    return [...this.transactions];
  }
}

export default TransactionLedger;
```

I'll build a URL shortening service with high availability using PostgreSQL replication and a load balancer.

Here's the implementation:

1. First, let's create a Docker Compose setup for PostgreSQL primary and replica:

```docker-compose.yml
version: '3.8'

services:
  nginx:
    image: nginx:latest
    ports:
      - "80:80"
    volumes:
      - ./nginx/nginx.conf:/etc/nginx/nginx.conf
    depends_on:
      - app1
      - app2
    networks:
      - app-network

  app1:
    build: ./app
    environment:
      - DATABASE_URL=postgresql://postgres:postgres@postgres-primary:5432/urlshortener
      - PORT=3000
    depends_on:
      - postgres-primary
    networks:
      - app-network
    restart: always
    healthcheck:
      test: ["CMD", "curl", "-f", "http://localhost:3000/health"]
      interval: 10s
      timeout: 5s
      retries: 3

  app2:
    build: ./app
    environment:
      - DATABASE_URL=postgresql://postgres:postgres@postgres-replica:5432/urlshortener
      - PORT=3000
    depends_on:
      - postgres-replica
    networks:
      - app-network
    restart: always
    healthcheck:
      test: ["CMD", "curl", "-f", "http://localhost:3000/health"]
      interval: 10s
      timeout: 5s
      retries: 3

  postgres-primary:
    image: postgres:13
    environment:
      - POSTGRES_USER=postgres
      - POSTGRES_PASSWORD=postgres
      - POSTGRES_DB=urlshortener
    volumes:
      - pg-primary-data:/var/lib/postgresql/data
      - ./postgres/primary.conf:/etc/postgresql/postgresql.conf
    command: postgres -c config_file=/etc/postgresql/postgresql.conf
    networks:
      - app-network
    healthcheck:
      test: ["CMD-SHELL", "pg_isready -U postgres"]
      interval: 10s
      timeout: 5s
      retries: 5

  postgres-replica:
    image: postgres:13
    environment:
      - POSTGRES_USER=postgres
      - POSTGRES_PASSWORD=postgres
      - POSTGRES_DB=urlshortener
    volumes:
      - pg-replica-data:/var/lib/postgresql/data
      - ./postgres/replica.conf:/etc/postgresql/postgresql.conf
    command: postgres -c config_file=/etc/postgresql/postgresql.conf
    depends_on:
      - postgres-primary
    networks:
      - app-network
    healthcheck:
      test: ["CMD-SHELL", "pg_isready -U postgres"]
      interval: 10s
      timeout: 5s
      retries: 5

networks:
  app-network:

volumes:
  pg-primary-data:
  pg-replica-data:
