```go
package main

import (
	"context"
	"encoding/json"
	"flag"
	"log"
	"os"
	"os/signal"
	"sync"
	"syscall"
	"time"

	"golang.org/x/time/rate"
)

type SignupEvent struct {
	UserID    string    `json:"user_id"`
	Email     string    `json:"email"`
	Timestamp time.Time `json:"timestamp"`
}

type Consumer struct {
	queue          chan SignupEvent
	workerCount    int
	rateLimiter    *rate.Limiter
	wg             sync.WaitGroup
	ctx            context.Context
	cancel         context.CancelFunc
}

func NewConsumer(workerCount int, rateLimit float64, burstLimit int) *Consumer {
	ctx, cancel := context.WithCancel(context.Background())
	return &Consumer{
		queue:          make(chan SignupEvent, 100),
		workerCount:    workerCount,
		rateLimiter:    rate.NewLimiter(rate.Limit(rateLimit), burstLimit),
		ctx:            ctx,
		cancel:         cancel,
	}
}

func (c *Consumer) Start() {
	for i := 0; i < c.workerCount; i++ {
		c.wg.Add(1)
		go c.worker(i)
	}
}

func (c *Consumer) Stop() {
	c.cancel()
	close(c.queue)
	c.wg.Wait()
}

func (c *Consumer) Enqueue(event SignupEvent) {
	c.queue <- event
}

func (c *Consumer) worker(id int) {
	defer c.wg.Done()
	log.Printf("Worker %d started", id)

	for {
		select {
		case event, ok := <-c.queue:
			if !ok {
				log.Printf("Worker %d shutting down", id)
				return
			}

			if err := c.rateLimiter.Wait(c.ctx); err != nil {
				log.Printf("Rate limiter error: %v", err)
				continue
			}

			c.processEvent(id, event)

		case <-c.ctx.Done():
			log.Printf("Worker %d received cancellation signal", id)
			return
		}
	}
}

func (c *Consumer) processEvent(workerID int, event SignupEvent) {
	log.Printf("Worker %d processing signup for user %s (%s) from %v", 
		workerID, event.UserID, event.Email, event.Timestamp)

	// Simulate processing work
	time.Sleep(200 * time.Millisecond)

	log.Printf("Worker %d completed processing user %s", workerID, event.UserID)
}

func main() {
	workerCount := flag.Int("workers", 5, "Number of worker threads")
	rateLimit := flag.Float64("rate", 10.0, "Rate limit (events per second)")
	burstLimit := flag.Int("burst", 20, "Burst limit for rate limiter")
	flag.Parse()

	consumer := NewConsumer(*workerCount, *rateLimit, *burstLimit)
	consumer.Start()

	// Setup signal handling for graceful shutdown
	sigChan := make(chan os.Signal, 1)
	signal.Notify(sigChan, syscall.SIGINT, syscall.SIGTERM)

	// Simulate incoming events
	go func() {
		for i := 0; i < 100; i++ {
			event := SignupEvent{
				UserID:    fmt.Sprintf("user-%d", i),
				Email:     fmt.Sprintf("user%d@example.com", i),
				Timestamp: time.Now(),
			}
			consumer.Enqueue(event)
			time.Sleep(50 * time.Millisecond)
		}
	}()

	<-sigChan
	log.Println("Shutdown signal received, stopping consumer...")
	consumer.Stop()
	log.Println("Consumer stopped, exiting")
}
