```rust:src/main.rs
use clap::{App, Arg, SubCommand};
use serde::{Deserialize, Serialize};
use std::error::Error;
use std::fs::{File, OpenOptions};
use std::io::{Read, Write};
use std::path::PathBuf;

const VERSION: &str = "1.0.0";
const APP_NAME: &str = "taskrs";

#[derive(Debug, Serialize, Deserialize)]
struct Task {
    id: usize,
    description: String,
    completed: bool,
}

#[derive(Debug, Serialize, Deserialize)]
struct TaskList {
    tasks: Vec<Task>,
    next_id: usize,
}

impl TaskList {
    fn new() -> Self {
        TaskList {
            tasks: Vec::new(),
            next_id: 1,
        }
    }

    fn add_task(&mut self, description: &str) -> usize {
        let task = Task {
            id: self.next_id,
            description: description.to_string(),
            completed: false,
        };
        self.next_id += 1;
        self.tasks.push(task);
        self.next_id - 1
    }

    fn complete_task(&mut self, id: usize) -> Result<(), String> {
        if let Some(task) = self.tasks.iter_mut().find(|t| t.id == id) {
            task.completed = true;
            Ok(())
        } else {
            Err(format!("Task with ID {} not found", id))
        }
    }

    fn delete_task(&mut self, id: usize) -> Result<(), String> {
        let initial_len = self.tasks.len();
        self.tasks.retain(|t| t.id != id);

        if self.tasks.len() == initial_len {
            Err(format!("Task with ID {} not found", id))
        } else {
            Ok(())
        }
    }

    fn list_tasks(&self) -> &Vec<Task> {
        &self.tasks
    }
}

fn get_data_file() -> PathBuf {
    let mut path = dirs::data_dir().unwrap_or_else(|| PathBuf::from("."));
    path.push(APP_NAME);
    std::fs::create_dir_all(&path).unwrap_or_else(|_| {
        eprintln!("Warning: Could not create data directory");
    });
    path.push("tasks.json");
    path
}

fn load_tasks() -> TaskList {
    let file_path = get_data_file();

    match File::open(&file_path) {
        Ok(mut file) => {
            let mut contents = String::new();
            if file.read_to_string(&mut contents).is_ok() {
                match serde_json::from_str(&contents) {
                    Ok(tasks) => tasks,
                    Err(_) => {
                        eprintln!("Error parsing task data, creating new task list");
                        TaskList::new()
                    }
                }
            } else {
                eprintln!("Error reading task data, creating new task list");
                TaskList::new()
            }
        }
        Err(_) => TaskList::new(),
    }
}

fn save_tasks(task_list: &TaskList) -> Result<(), Box<dyn Error>> {
    let file_path = get_data_file();
    let json = serde_json::to_string_pretty(&task_list)?;

    let mut file = OpenOptions::new()
        .write(true)
        .create(true)
        .truncate(true)
        .open(file_path)?;

    file.write_all(json.as_bytes())?;
    Ok(())
}

fn main() {
    let app = App::new(APP_NAME)
        .version(VERSION)
        .about("A simple CLI task manager")
        .subcommand(
            SubCommand::with_name("add")
                .about("Add a new task")
                .arg(Arg::with_name("DESCRIPTION")
                    .help("Description of the task")
                    .required(true)
                    .index(1))
        )
        .subcommand(
            SubCommand::with_name("complete")
                .about("Mark a task as complete")
                .arg(Arg::with_name("ID")
                    .help("ID of the task to complete")
                    .required(true)
                    .index(1))
        )
        .subcommand(
            SubCommand::with_name("delete")
                .about("Delete a task")
                .arg(Arg::with_name("ID")
                    .help("ID of the task to delete")
                    .required(true)
                    .index(1))
        )
        .subcommand(SubCommand::with_name("list").about("List all tasks"));

    let matches = app.get_matches();

    let mut task_list = load_tasks();

    match matches.subcommand() {
        ("add", Some(add_matches)) => {
            let description = add_matches.value_of("DESCRIPTION").unwrap();
            let id = task_list.add_task(description);
            println!("Added task with ID: {}", id);
            if let Err(e) = save_tasks(&task_list) {
                eprintln!("Error saving tasks: {}", e);
            }
        }
        ("complete", Some(complete_matches)) => {
            let id_str = complete_matches.value_of("ID").unwrap();
            match id_str.parse::<usize>() {
                Ok(id) => {
                    match task_list.complete_task(id) {
                        Ok(_) => {
                            println!("Marked task {} as complete", id);
                            if let Err(e) = save_tasks(&task_list) {
                                eprintln!("Error saving tasks: {}", e);
                            }
                        }
                        Err(e) => eprintln!("Error: {}", e),
                    }
                }
                Err(_) => eprintln!("Error: Invalid task ID '{}'", id_str),
            }
        }
        ("delete", Some(delete_matches)) => {
            let id_str = delete_matches.value_of("ID").unwrap();
            match id_str.parse::<usize>() {
                Ok(id) => {
                    match task_list.delete_task(id) {
                        Ok(_) => {
                            println!("Deleted task {}", id);
                            if let Err(e) = save_tasks(&task_list) {
                                eprintln!("Error saving tasks: {}", e);
                            }
                        }
                        Err(e) => eprintln!("Error: {}", e),
                    }
                }
                Err(_) => eprintln!("Error: Invalid task ID '{}'", id_str),
            }
        }
        ("list", Some(_)) => {
            let tasks = task_list.list_tasks();
            if tasks.is_empty() {
                println!("No tasks found");
            } else {
                println!("Tasks:");
                for task in tasks {
                    let status = if task.completed { "✓" } else { " " };
                    println!("[{}] {} - {}", status, task.id, task.description);
                }
            }
        }
        _ => {
            println!("No command provided. Use --help for usage information.");
        }
    }
}
