```typescript:src/taskQueue.ts
import Redis from 'ioredis';
import { performance } from 'perf_hooks';
import { v4 as uuidv4 } from 'uuid';

// Connection pool configuration
const POOL_SIZE = 20;
const redisOptions = {
  host: process.env.REDIS_HOST || 'localhost',
  port: Number(process.env.REDIS_PORT) || 6379,
  maxRetriesPerRequest: 3,
  enableReadyCheck: false,
};

// Create connection pool
const connectionPool: Redis[] = Array(POOL_SIZE).fill(0).map(() => new Redis(redisOptions));

// Get a connection from the pool
function getConnection(): Redis {
  return connectionPool[Math.floor(Math.random() * POOL_SIZE)];
}

// Task queue implementation
export class TaskQueue {
  private queueName: string;

  constructor(queueName: string) {
    this.queueName = queueName;
  }

  // Add multiple jobs using pipelining
  async addJobs(jobs: any[]): Promise<string[]> {
    const connection = getConnection();
    const pipeline = connection.pipeline();
    const jobIds: string[] = [];

    for (const job of jobs) {
      const jobId = uuidv4();
      jobIds.push(jobId);
      const jobData = JSON.stringify({ id: jobId, data: job, createdAt: Date.now() });
      pipeline.lpush(this.queueName, jobData);
    }

    await pipeline.exec();
    return jobIds;
  }

  // Process jobs in batches
  async processBatch(batchSize: number, handler: (job: any) => Promise<void>): Promise<number> {
    const connection = getConnection();
    const pipeline = connection.pipeline();

    // Get multiple jobs at once
    const jobs = await connection.rpop(this.queueName, batchSize);
    if (!jobs || jobs.length === 0) return 0;

    const jobArray = Array.isArray(jobs) ? jobs : [jobs];
    const processedCount = jobArray.length;

    // Process jobs in parallel
    await Promise.all(jobArray.map(async (jobData) => {
      try {
        const job = JSON.parse(jobData);
        await handler(job.data);
      } catch (error) {
        console.error('Error processing job:', error);
      }
    }));

    return processedCount;
  }
}

// Worker implementation
export class Worker {
  private queue: TaskQueue;
  private handler: (job: any) => Promise<void>;
  private batchSize: number;
  private isRunning: boolean = false;

  constructor(queueName: string, handler: (job: any) => Promise<void>, batchSize: number = 100) {
    this.queue = new TaskQueue(queueName);
    this.handler = handler;
    this.batchSize = batchSize;
  }

  async start(): Promise<void> {
    this.isRunning = true;

    while (this.isRunning) {
      const processed = await this.queue.processBatch(this.batchSize, this.handler);
      if (processed === 0) {
        await new Promise(resolve => setTimeout(resolve, 10)); // Backoff when no jobs
      }
    }
  }

  stop(): void {
    this.isRunning = false;
  }
}

// Benchmark implementation
export async function runBenchmark(): Promise<void> {
  const TOTAL_JOBS = 100000;
  const BATCH_SIZES = [1, 10, 100, 1000];

  // Sample job handler
  const handler = async (job: any): Promise<void> => {
    // Simulate processing time
    await new Promise(resolve => setTimeout(resolve, 1));
  };

  console.log('Starting benchmark...');
  console.log('Jobs per second for different batch sizes:');

  // Naive implementation (batch size = 1)
  const naiveQueue = new TaskQueue('benchmark:naive');

  // Optimized implementation with different batch sizes
  for (const batchSize of BATCH_SIZES) {
    const queue = new TaskQueue(`benchmark:batch:${batchSize}`);

    // Prepare test data
    const jobs = Array(TOTAL_JOBS).fill(0).map((_, i) => ({ value: i }));

    // Add jobs
    await queue.addJobs(jobs);

    // Process jobs and measure throughput
    const startTime = performance.now();
    let processedCount = 0;

    while (processedCount < TOTAL_JOBS) {
      const processed = await queue.processBatch(batchSize, handler);
      processedCount += processed;

      if (processed === 0) {
        break;
      }
    }

    const endTime = performance.now();
    const durationSec = (endTime - startTime) / 1000;
    const jobsPerSec = Math.floor(processedCount / durationSec);

    console.log(`Batch size ${batchSize}: ${jobsPerSec} jobs/sec`);

    if (batchSize === 1) {
      console.log(`\nThroughput improvement over naive implementation:`);
    } else {
      const improvementFactor = jobsPerSec / (BATCH_SIZES[0] === 1 ? jobsPerSec : 0);
      console.log(`Batch size ${batchSize}: ${improvementFactor.toFixed(2)}x improvement`);
    }
  }
}
