// passwordPolicy.ts
import * as zxcvbn from 'zxcvbn';
import * as crypto from 'crypto';
import * as argon2 from 'argon2';
import fetch from 'node-fetch';

export class PasswordPolicy {
  async validatePassword(password: string, username: string): Promise<{ valid: boolean; message?: string }> {
    // Check minimum length (NIST recommends at least 8 characters)
    if (password.length < 8) {
      return { valid: false, message: 'Password must be at least 8 characters long' };
    }

    // Check entropy using zxcvbn
    const result = zxcvbn(password, [username]);
    if (result.score < 3) {
      return { valid: false, message: 'Password is too weak. Try a longer, more complex password' };
    }

    // Check if password has been breached
    const isPwned = await this.checkHaveIBeenPwned(password);
    if (isPwned) {
      return { valid: false, message: 'This password has appeared in a data breach. Choose a different password' };
    }

    return { valid: true };
  }

  private async checkHaveIBeenPwned(password: string): Promise<boolean> {
    const sha1 = crypto.createHash('sha1').update(password).digest('hex').toUpperCase();
    const prefix = sha1.slice(0, 5);
    const suffix = sha1.slice(5);

    try {
      const response = await fetch(`https://api.pwnedpasswords.com/range/${prefix}`);
      const text = await response.text();
      const hashes = text.split('\r\n');

      return hashes.some(line => line.startsWith(suffix));
    } catch (error) {
      console.error('Error checking HaveIBeenPwned:', error);
      return false; // Fail open in case API is unavailable
    }
  }

  async hashPassword(password: string): Promise<string> {
    return await argon2.hash(password, {
      type: argon2.argon2id,
      memoryCost: 65536, // 64 MiB
      timeCost: 3,       // 3 iterations
      parallelism: 4     // 4 parallel threads
    });
  }

  async verifyPassword(hash: string, password: string): Promise<boolean> {
    return await argon2.verify(hash, password);
  }
}
