# cloud_storage.py
import os
import abc
from typing import Optional, BinaryIO, Dict, Any
import boto3
from google.cloud import storage


class CloudStorageAdapter(abc.ABC):
    @abc.abstractmethod
    def upload_file(self, local_path: str, remote_path: str) -> bool:
        pass

    @abc.abstractmethod
    def download_file(self, remote_path: str, local_path: str) -> bool:
        pass

    @abc.abstractmethod
    def delete_file(self, remote_path: str) -> bool:
        pass

    @abc.abstractmethod
    def file_exists(self, remote_path: str) -> bool:
        pass


class LocalFileSystemAdapter(CloudStorageAdapter):
    def __init__(self, base_dir: str):
        self.base_dir = base_dir
        os.makedirs(base_dir, exist_ok=True)

    def _get_full_path(self, path: str) -> str:
        return os.path.join(self.base_dir, path)

    def upload_file(self, local_path: str, remote_path: str) -> bool:
        try:
            dest_path = self._get_full_path(remote_path)
            os.makedirs(os.path.dirname(dest_path), exist_ok=True)
            with open(local_path, 'rb') as src, open(dest_path, 'wb') as dst:
                dst.write(src.read())
            return True
        except Exception:
            return False

    def download_file(self, remote_path: str, local_path: str) -> bool:
        try:
            src_path = self._get_full_path(remote_path)
            os.makedirs(os.path.dirname(local_path), exist_ok=True)
            with open(src_path, 'rb') as src, open(local_path, 'wb') as dst:
                dst.write(src.read())
            return True
        except Exception:
            return False

    def delete_file(self, remote_path: str) -> bool:
        try:
            os.remove(self._get_full_path(remote_path))
            return True
        except Exception:
            return False

    def file_exists(self, remote_path: str) -> bool:
        return os.path.exists(self._get_full_path(remote_path))


class S3Adapter(CloudStorageAdapter):
    def __init__(self, client=None, bucket_name: str = None):
        self.client = client or boto3.client('s3')
        self.bucket_name = bucket_name

    def upload_file(self, local_path: str, remote_path: str) -> bool:
        try:
            self.client.upload_file(local_path, self.bucket_name, remote_path)
            return True
        except Exception:
            return False

    def download_file(self, remote_path: str, local_path: str) -> bool:
        try:
            os.makedirs(os.path.dirname(local_path), exist_ok=True)
            self.client.download_file(self.bucket_name, remote_path, local_path)
            return True
        except Exception:
            return False

    def delete_file(self, remote_path: str) -> bool:
        try:
            self.client.delete_object(Bucket=self.bucket_name, Key=remote_path)
            return True
        except Exception:
            return False

    def file_exists(self, remote_path: str) -> bool:
        try:
            self.client.head_object(Bucket=self.bucket_name, Key=remote_path)
            return True
        except Exception:
            return False


class GCSAdapter(CloudStorageAdapter):
    def __init__(self, client=None, bucket_name: str = None):
        self.client = client or storage.Client()
        self.bucket_name = bucket_name
        self.bucket = self.client.bucket(bucket_name)

    def upload_file(self, local_path: str, remote_path: str) -> bool:
        try:
            blob = self.bucket.blob(remote_path)
            blob.upload_from_filename(local_path)
            return True
        except Exception:
            return False

    def download_file(self, remote_path: str, local_path: str) -> bool:
        try:
            os.makedirs(os.path.dirname(local_path), exist_ok=True)
            blob = self.bucket.blob(remote_path)
            blob.download_to_filename(local_path)
            return True
        except Exception:
            return False

    def delete_file(self, remote_path: str) -> bool:
        try:
            blob = self.bucket.blob(remote_path)
            blob.delete()
            return True
        except Exception:
            return False

    def file_exists(self, remote_path: str) -> bool:
        blob = self.bucket.blob(remote_path)
        return blob.exists()


class FallbackStorageAdapter(CloudStorageAdapter):
    def __init__(self, primary: CloudStorageAdapter, fallback: CloudStorageAdapter):
        self.primary = primary
        self.fallback = fallback

    def upload_file(self, local_path: str, remote_path: str) -> bool:
        primary_success = self.primary.upload_file(local_path, remote_path)
        if primary_success:
            return True
        return self.fallback.upload_file(local_path, remote_path)

    def download_file(self, remote_path: str, local_path: str) -> bool:
        primary_success = self.primary.download_file(remote_path, local_path)
        if primary_success:
            return True
        return self.fallback.download_file(remote_path, local_path)

    def delete_file(self, remote_path: str) -> bool:
        primary_success = self.primary.delete_file(remote_path)
        fallback_success = self.fallback.delete_file(remote_path)
        return primary_success and fallback_success

    def file_exists(self, remote_path: str) -> bool:
        return self.primary.file_exists(remote_path) or self.fallback.file_exists(remote_path)
