#!/usr/bin/env node

const { createPromptModule } = require('inquirer');
const inquirer = require('inquirer');
const autocomplete = require('inquirer-autocomplete-prompt');
const chalk = require('chalk');
const boxen = require('boxen');
const ora = require('ora');
const fs = require('fs');

// Register the autocomplete prompt
inquirer.registerPrompt('autocomplete', autocomplete);

// Configuration history for undo/redo
const history = [];
let historyIndex = -1;

// Server configuration options
const serverTypes = ['nginx', 'apache', 'express', 'fastify'];
const portRanges = {
  'standard': [80, 443, 8080],
  'development': [3000, 5000, 8000],
  'custom': []
};

// Help context
const helpContext = {
  serverType: 'Select the web server software you want to configure',
  port: 'The network port your server will listen on',
  hostname: 'The domain name or IP address for your server',
  ssl: 'Enable HTTPS with SSL/TLS encryption',
  workers: 'Number of worker processes (improves performance)',
  caching: 'Enable response caching to improve performance',
  compression: 'Enable gzip/brotli compression to reduce bandwidth'
};

// Current configuration
let config = {
  serverType: '',
  port: 80,
  hostname: 'localhost',
  ssl: false,
  workers: 1,
  caching: false,
  compression: false
};

// Save configuration to history
function saveToHistory(config) {
  // Remove any future history if we're in the middle
  if (historyIndex < history.length - 1) {
    history.splice(historyIndex + 1);
  }
  history.push(JSON.parse(JSON.stringify(config)));
  historyIndex = history.length - 1;
}

// Filter function for autocomplete
function filterChoices(choices, input = '') {
  return new Promise(resolve => {
    const filtered = choices.filter(choice => 
      choice.toLowerCase().includes((input || '').toLowerCase())
    );
    resolve(filtered);
  });
}

// Display configuration preview
function showConfigPreview() {
  const preview = `
${chalk.bold('Server Configuration')}
${chalk.blue('Type:')} ${config.serverType || 'Not set'}
${chalk.blue('Port:')} ${config.port}
${chalk.blue('Hostname:')} ${config.hostname}
${chalk.blue('SSL:')} ${config.ssl ? chalk.green('Enabled') : chalk.red('Disabled')}
${chalk.blue('Workers:')} ${config.workers}
${chalk.blue('Caching:')} ${config.caching ? chalk.green('Enabled') : chalk.red('Disabled')}
${chalk.blue('Compression:')} ${config.compression ? chalk.green('Enabled') : chalk.red('Disabled')}
`;

  console.log(boxen(preview, {
    padding: 1,
    margin: 1,
    borderStyle: 'round',
    borderColor: 'cyan'
  }));
}

// Show help for current context
function showHelp(context) {
  console.log(boxen(chalk.yellow(helpContext[context] || 'No help available for this option'), {
    padding: 1,
    borderStyle: 'round',
    borderColor: 'yellow',
    title: 'Help',
    titleAlignment: 'center'
  }));
}

// Main wizard function
async function configWizard() {
  console.log(chalk.bold.cyan('Server Configuration Wizard'));
  console.log(chalk.dim('Use arrow keys to navigate, type for autocomplete, ? for help, ctrl+z to undo, ctrl+y to redo\n'));

  // Initial configuration
  saveToHistory(config);

  let exit = false;
  while (!exit) {
    showConfigPreview();

    const { action } = await inquirer.prompt([{
      type: 'list',
      name: 'action',
      message: 'What would you like to configure?',
      choices: [
        'Server Type',
        'Port',
        'Hostname',
        'SSL',
        'Workers',
        'Caching',
        'Compression',
        new inquirer.Separator(),
        'Save Configuration',
        'Exit'
      ]
    }]);

    switch (action) {
      case 'Server Type':
        await configureServerType();
        break;
      case 'Port':
        await configurePort();
        break;
      case 'Hostname':
        await configureHostname();
        break;
      case 'SSL':
        await configureSSL();
        break;
      case 'Workers':
        await configureWorkers();
        break;
      case 'Caching':
        await configureCaching();
        break;
      case 'Compression':
        await configureCompression();
        break;
      case 'Save Configuration':
        await saveConfiguration();
        break;
      case 'Exit':
        exit = true;
        break;
    }
  }

  console.log(chalk.green('Thank you for using the Server Configuration Wizard!'));
}

async function configureServerType() {
  showHelp('serverType');

  const { serverType } = await inquirer.prompt([{
    type: 'autocomplete',
    name: 'serverType',
    message: 'Select server type:',
    source: (_, input) => filterChoices(serverTypes, input),
    pageSize: 10
  }]);

  config.serverType = serverType;
  saveToHistory(config);
}

async function configurePort() {
  showHelp('port');

  const { portType } = await inquirer.prompt([{
    type: 'list',
    name: 'portType',
    message: 'Select port type:',
    choices: ['standard', 'development', 'custom']
  }]);

  if (portType === 'custom') {
    const { port } = await inquirer.prompt([{
      type: 'number',
      name: 'port',
      message: 'Enter custom port:',
      default: config.port,
      validate: (input) => {
        if (input >= 1 && input <= 65535) return true;
        return 'Port must be between 1 and 65535';
      }
    }]);
    config.port = port;
  } else {
    const { port } = await inquirer.prompt([{
      type: 'list',
      name: 'port',
      message: `Select ${portType} port:`,
      choices: portRanges[portType]
    }]);
    config.port = port;
  }

  saveToHistory(config);
}

async function configureHostname() {
  showHelp('hostname');

  const { hostname } = await inquirer.prompt([{
    type: 'input',
    name: 'hostname',
    message: 'Enter hostname:',
    default: config.hostname,
    validate: (input) => {
      // Simple hostname validation
      if (/^[a-zA-Z0-9]([a-zA-Z0-9\-\.]{0,61}[a-zA-Z0-9])?$/.test(input)) return true;
      return 'Please enter a valid hostname';
    }
  }]);

  config.hostname = hostname;
  saveToHistory(config);
}

async function configureSSL() {
  showHelp('ssl');

  const { ssl } = await inquirer.prompt([{
    type: 'confirm',
    name: 'ssl',
    message: 'Enable SSL/TLS?',
    default: config.ssl
  }]);

  config.ssl = ssl;
  saveToHistory(config);
}

async function configureWorkers() {
  showHelp('workers');

  const { workers } = await inquirer.prompt([{
    type: 'number',
    name: 'workers',
    message: 'Number of worker processes:',
    default: config.workers,
    validate: (input) => {
      if (input >= 1 && input <= 32) return true;
      return 'Workers must be between 1 and 32';
    }
  }]);

  config.workers = workers;
  saveToHistory(config);
}

async function configureCaching() {
  showHelp('caching');

  const { caching } = await inquirer.prompt([{
    type: 'confirm',
    name: 'caching',
    message: 'Enable response caching?',
    default: config.caching
  }]);

  config.caching = caching;
  saveToHistory(config);
}

async function configureCompression() {
  showHelp('compression');

  const { compression } = await inquirer.prompt([{
    type: 'confirm',
    name: 'compression',
    message: 'Enable compression?',
    default: config.compression
  }]);

  config.compression = compression;
  saveToHistory(config);
}

async function saveConfiguration() {
  const spinner = ora('Saving configuration...').start();

  try {
    // Generate configuration file based on server type
    let configContent = '';

    switch(config.serverType) {
      case 'nginx':
        configContent = generateNginxConfig();
        break;
      case 'apache':
        configContent = generateApacheConfig();
        break;
      case 'express':
        configContent = generateExpressConfig();
        break;
      case 'fastify':
        configContent = generateFastifyConfig();
        break;
      default:
        configContent = JSON.stringify(config, null, 2);
    }

    fs.writeFileSync('server-config.conf', configContent);

    setTimeout(() => {
      spinner.succeed('Configuration saved to server-config.conf');
    }, 1000);
  } catch (error) {
    spinner.fail('Failed to save configuration');
    console.error(error);
  }
}

// Generate config files for different server types
function generateNginxConfig() {
  return `# Nginx configuration
server {
    listen ${config.port}${config.ssl ? ' ssl' : ''};
    server_name ${config.hostname};

    ${config.ssl ? 'ssl_certificate /path/to/cert.pem;\n    ssl_certificate_key /path/to/key.pem;' : ''}

    ${config.workers > 1 ? `worker_processes ${config.workers};` : ''}

    ${config.caching ? 'proxy_cache_path /path/to/cache levels=1:2 keys_zone=my_cache:10m;' : ''}

    ${config.compression ? 'gzip on;\n    gzip_types text/plain text/css application/json;' : ''}

    location / {
        root /var/www/html;
        index index.html;
    }
}`;
}

function generateApacheConfig() {
  return `# Apache configuration
<VirtualHost *:${config.port}>
    ServerName ${config.hostname}
    DocumentRoot /var/www/html

