from abc import ABC, abstractmethod
from enum import Enum
import uuid
from typing import Dict, List, Any, Callable, Optional

class PlatformType(Enum):
    QT = 1
    WXPYTHON = 2
    TEXTUAL = 3

class EventBus:
    def __init__(self):
        self._subscribers: Dict[str, List[Callable]] = {}

    def subscribe(self, event_type: str, callback: Callable) -> None:
        if event_type not in self._subscribers:
            self._subscribers[event_type] = []
        self._subscribers[event_type].append(callback)

    def publish(self, event_type: str, data: Any = None) -> None:
        if event_type in self._subscribers:
            for callback in self._subscribers[event_type]:
                callback(data)

class Widget(ABC):
    def __init__(self, id: str = None):
        self.id = id or str(uuid.uuid4())
        self.event_bus = None

    def set_event_bus(self, event_bus: EventBus) -> None:
        self.event_bus = event_bus

    @abstractmethod
    def render(self) -> Any:
        pass

class Button(Widget):
    def __init__(self, label: str, id: str = None):
        super().__init__(id)
        self.label = label

class TextInput(Widget):
    def __init__(self, placeholder: str = "", id: str = None):
        super().__init__(id)
        self.placeholder = placeholder
        self.value = ""

class WidgetFactory(ABC):
    @abstractmethod
    def create_button(self, label: str, id: str = None) -> Button:
        pass

    @abstractmethod
    def create_text_input(self, placeholder: str = "", id: str = None) -> TextInput:
        pass

class RenderStrategy(ABC):
    @abstractmethod
    def render_button(self, button: Button) -> Any:
        pass

    @abstractmethod
    def render_text_input(self, text_input: TextInput) -> Any:
        pass

    @abstractmethod
    def start_ui_loop(self) -> None:
        pass

class GUIApplication:
    def __init__(self, platform: PlatformType):
        self.event_bus = EventBus()
        self.platform = platform
        self.renderer = self._create_renderer()
        self.widget_factory = self._create_widget_factory()

    def _create_renderer(self) -> RenderStrategy:
        if self.platform == PlatformType.QT:
            from gui.renderers.qt_renderer import QtRenderStrategy
            return QtRenderStrategy()
        elif self.platform == PlatformType.WXPYTHON:
            from gui.renderers.wx_renderer import WxRenderStrategy
            return WxRenderStrategy()
        elif self.platform == PlatformType.TEXTUAL:
            from gui.renderers.textual_renderer import TextualRenderStrategy
            return TextualRenderStrategy()
        else:
            raise ValueError(f"Unsupported platform: {self.platform}")

    def _create_widget_factory(self) -> WidgetFactory:
        if self.platform == PlatformType.QT:
            from gui.factories.qt_factory import QtWidgetFactory
            return QtWidgetFactory(self.event_bus)
        elif self.platform == PlatformType.WXPYTHON:
            from gui.factories.wx_factory import WxWidgetFactory
            return WxWidgetFactory(self.event_bus)
        elif self.platform == PlatformType.TEXTUAL:
            from gui.factories.textual_factory import TextualWidgetFactory
            return TextualWidgetFactory(self.event_bus)
        else:
            raise ValueError(f"Unsupported platform: {self.platform}")

    def run(self) -> None:
        self.renderer.start_ui_loop()
