from gui.core import RenderStrategy, Button, TextInput
from typing import Any

class QtRenderStrategy(RenderStrategy):
    def __init__(self):
        try:
            from PyQt5 import QtWidgets
            self.app = QtWidgets.QApplication([])
            self.QtWidgets = QtWidgets
            self.main_window = QtWidgets.QMainWindow()
            self.central_widget = QtWidgets.QWidget()
            self.layout = QtWidgets.QVBoxLayout()
            self.central_widget.setLayout(self.layout)
            self.main_window.setCentralWidget(self.central_widget)
        except ImportError:
            raise ImportError("PyQt5 is required for Qt rendering")

    def render_button(self, button: Button) -> Any:
        qt_button = self.QtWidgets.QPushButton(button.label)
        qt_button.clicked.connect(
            lambda: button.event_bus.publish(f"button_click_{button.id}")
        )
        self.layout.addWidget(qt_button)
        return qt_button

    def render_text_input(self, text_input: TextInput) -> Any:
        qt_text_input = self.QtWidgets.QLineEdit()
        qt_text_input.setPlaceholderText(text_input.placeholder)
        qt_text_input.textChanged.connect(
            lambda text: self._handle_text_change(text_input, text)
        )
        self.layout.addWidget(qt_text_input)
        return qt_text_input

    def _handle_text_change(self, text_input: TextInput, text: str) -> None:
        text_input.value = text
        if text_input.event_bus:
            text_input.event_bus.publish(f"text_change_{text_input.id}", text)

    def start_ui_loop(self) -> None:
        self.main_window.show()
        self.app.exec_()
