        wx_button = self.wx.Button(self.panel, label=button.label)
        wx_button.Bind(
            self.wx.EVT_BUTTON,
            lambda event: button.event_bus.publish(f"button_click_{button.id}")
        )
        self.sizer.Add(wx_button, 0, self.wx.ALL, 5)
        self.widgets[button.id] = wx_button
        return wx_button

    def render_text_input(self, text_input: TextInput) -> Any:
        wx_text_input = self.wx.TextCtrl(self.panel)
        wx_text_input.Bind(
            self.wx.EVT_TEXT,
            lambda event: self._handle_text_change(text_input, event.GetString())
        )
        self.sizer.Add(wx_text_input, 0, self.wx.ALL | self.wx.EXPAND, 5)
        self.widgets[text_input.id] = wx_text_input
        return wx_text_input

    def _handle_text_change(self, text_input: TextInput, text: str) -> None:
        text_input.value = text
        if text_input.event_bus:
            text_input.event_bus.publish(f"text_change_{text_input.id}", text)

    def start_ui_loop(self) -> None:
        self.frame.Show()
        self.app.MainLoop()
