from gui.core import RenderStrategy, Button, TextInput
from typing import Any, Dict

class TextualRenderStrategy(RenderStrategy):
    def __init__(self):
        try:
            from textual.app import App
            from textual.widgets import Button as TextualButton
            from textual.widgets import Input as TextualInput
            from textual.containers import Container

            self.widgets: Dict[str, Any] = {}

            class TextualApp(App):
                def __init__(self, strategy):
                    super().__init__()
                    self.strategy = strategy

                def compose(self):
                    yield Container(id="main_container")

            self.textual_module = {
                "App": App,
                "Button": TextualButton,
                "Input": TextualInput,
                "Container": Container
            }

            self.app = TextualApp(self)

        except ImportError:
            raise ImportError("Textual is required for Textual rendering")

    def render_button(self, button: Button) -> Any:
        textual_button = self.textual_module["Button"](button.label, id=button.id)

        async def on_button_click():
            if button.event_bus:
                button.event_bus.publish(f"button_click_{button.id}")

        textual_button.on_click = on_button_click
        self.widgets[button.id] = textual_button

        # Add button to main container when app is running
        if hasattr(self.app, 'query_one'):
            self.app.query_one("#main_container").mount(textual_button)

        return textual_button

    def render_text_input(self, text_input: TextInput) -> Any:
        textual_input = self.textual_module["Input"](
            placeholder=text_input.placeholder, 
            id=text_input.id
        )

        async def on_input_changed(event):
            text_input.value = event.value
            if text_input.event_bus:
                text_input.event_bus.publish(f"text_change_{text_input.id}", event.value)

        textual_input.on_change = on_input_changed
        self.widgets[text_input.id] = textual_input

        # Add input to main container when app is running
        if hasattr(self.app, 'query_one'):
            self.app.query_one("#main_container").mount(textual_input)

        return textual_input

    def start_ui_loop(self) -> None:
        self.app.run()
