// auditLogger.js
const crypto = require('crypto');
const { ENCRYPTION_KEY, HMAC_KEY, AUTH_LEVELS } = require('./config');

class AuditLogger {
  constructor() {
    this.logs = [];
  }

  encryptField(field) {
    const iv = crypto.randomBytes(12);
    const cipher = crypto.createCipheriv('aes-256-gcm', Buffer.from(ENCRYPTION_KEY, 'hex'), iv);

    let encrypted = cipher.update(field, 'utf8', 'hex');
    encrypted += cipher.final('hex');
    const authTag = cipher.getAuthTag().toString('hex');

    return {
      iv: iv.toString('hex'),
      encryptedData: encrypted,
      authTag
    };
  }

  decryptField(encryptedObj, authLevel) {
    if (authLevel < AUTH_LEVELS.ADMIN) {
      throw new Error('Insufficient authorization level for decryption');
    }

    const decipher = crypto.createDecipheriv(
      'aes-256-gcm',
      Buffer.from(ENCRYPTION_KEY, 'hex'),
      Buffer.from(encryptedObj.iv, 'hex')
    );

    decipher.setAuthTag(Buffer.from(encryptedObj.authTag, 'hex'));

    let decrypted = decipher.update(encryptedObj.encryptedData, 'hex', 'utf8');
    decrypted += decipher.final('utf8');

    return decrypted;
  }

  createHMAC(logEntry) {
    const hmac = crypto.createHmac('sha256', HMAC_KEY);
    hmac.update(JSON.stringify(logEntry));
    return hmac.digest('hex');
  }

  verifyIntegrity(logEntry, hmac) {
    const calculatedHmac = this.createHMAC(logEntry);
    return crypto.timingSafeEqual(
      Buffer.from(calculatedHmac, 'hex'),
      Buffer.from(hmac, 'hex')
    );
  }

  log(action, data, userId) {
    const timestamp = new Date().toISOString();
    const sensitiveFields = ['ssn', 'email'];

    // Deep clone to avoid modifying the original data
    const processedData = JSON.parse(JSON.stringify(data));

    // Encrypt sensitive fields
    for (const key in processedData) {
      if (sensitiveFields.includes(key.toLowerCase())) {
        processedData[key] = this.encryptField(processedData[key]);
      }
    }

    const logEntry = {
      timestamp,
      action,
      data: processedData,
      userId
    };

    // Create HMAC for log integrity
    const hmac = this.createHMAC(logEntry);

    // Store log with its HMAC
    this.logs.push({ ...logEntry, hmac });

    return logEntry;
  }

  getLog(index, authLevel = AUTH_LEVELS.BASIC) {
    if (index >= this.logs.length) {
      throw new Error('Log entry not found');
    }

    const logEntry = this.logs[index];

    // Verify log integrity
    if (!this.verifyIntegrity({ ...logEntry, hmac: undefined }, logEntry.hmac)) {
      throw new Error('Log integrity compromised');
    }

    // If sufficient auth level, decrypt sensitive fields
    if (authLevel >= AUTH_LEVELS.ADMIN) {
      const decryptedLog = JSON.parse(JSON.stringify(logEntry));
      const sensitiveFields = ['ssn', 'email'];

      for (const key in decryptedLog.data) {
        if (sensitiveFields.includes(key.toLowerCase()) && 
            decryptedLog.data[key].encryptedData) {
          try {
            decryptedLog.data[key] = this.decryptField(decryptedLog.data[key], authLevel);
          } catch (error) {
            // Keep encrypted if decryption fails
          }
        }
      }

      return decryptedLog;
    }

    return logEntry;
  }
}

module.exports = new AuditLogger();
