// redis-cache.js
const Redis = require('redis');
const { promisify } = require('util');
const { CircuitBreaker } = require('opossum');

class RedisCache {
  constructor(options = {}) {
    this.options = {
      host: options.host || 'localhost',
      port: options.port || 6379,
      maxConnections: options.maxConnections || 100,
      maxSize: options.maxSize || 10000,
      ttl: options.ttl || 3600,
      circuitOptions: {
        timeout: 3000,
        errorThresholdPercentage: 50,
        resetTimeout: 30000
      },
      ...options
    };

    this.pool = this.createConnectionPool();
    this.breaker = new CircuitBreaker(this.execute.bind(this), this.options.circuitOptions);
    this.breaker.fallback(() => null);
  }

  createConnectionPool() {
    const pool = [];
    for (let i = 0; i < this.options.maxConnections; i++) {
      const client = Redis.createClient({
        host: this.options.host,
        port: this.options.port,
        enable_offline_queue: false
      });

      client.on('error', (err) => console.error('Redis client error:', err));

      client.getAsync = promisify(client.get).bind(client);
      client.setAsync = promisify(client.set).bind(client);
      client.zaddAsync = promisify(client.zadd).bind(client);
      client.zremAsync = promisify(client.zrem).bind(client);
      client.zrangeAsync = promisify(client.zrange).bind(client);
      client.zcountAsync = promisify(client.zcount).bind(client);
      client.multiAsync = promisify(client.multi).bind(client);
      client.execAsync = promisify(client.exec).bind(client);

      pool.push(client);
    }
    return pool;
  }

  getClient() {
    return this.pool[Math.floor(Math.random() * this.pool.length)];
  }

  async execute(fn) {
    const client = this.getClient();
    return fn(client);
  }

  async get(key) {
    return this.breaker.fire(async (client) => {
      const result = await client.getAsync(key);
      if (result) {
        const now = Date.now();
        client.zaddAsync('lru', now, key);
      }
      return result ? JSON.parse(result) : null;
    });
  }

  async mget(keys) {
    if (!keys.length) return [];

    return this.breaker.fire(async (client) => {
      const pipeline = client.multi();
      keys.forEach(key => pipeline.get(key));

      const now = Date.now();
      const lruPipeline = client.multi();
      keys.forEach(key => lruPipeline.zadd('lru', now, key));

      const results = await pipeline.execAsync();
      lruPipeline.execAsync().catch(err => console.error('LRU update error:', err));

      return results.map(result => result ? JSON.parse(result) : null);
    });
  }

  async set(key, value, ttl = this.options.ttl) {
    return this.breaker.fire(async (client) => {
      const stringValue = JSON.stringify(value);
      const now = Date.now();

      const pipeline = client.multi();
      pipeline.set(key, stringValue, 'EX', ttl);
      pipeline.zadd('lru', now, key);

      await pipeline.execAsync();
      await this.enforceLimit(client);
    });
  }

  async mset(items, ttl = this.options.ttl) {
    if (!items.length) return;

    return this.breaker.fire(async (client) => {
      const pipeline = client.multi();
      const now = Date.now();

      items.forEach(({key, value}) => {
        pipeline.set(key, JSON.stringify(value), 'EX', ttl);
        pipeline.zadd('lru', now, key);
      });

      await pipeline.execAsync();
      await this.enforceLimit(client);
    });
  }

  async enforceLimit(client) {
    const count = await client.zcountAsync('lru', '-inf', '+inf');
    if (count > this.options.maxSize) {
      const toRemove = count - this.options.maxSize;
      const oldestKeys = await client.zrangeAsync('lru', 0, toRemove - 1);

      if (oldestKeys.length) {
        const pipeline = client.multi();
        oldestKeys.forEach(key => {
          pipeline.del(key);
          pipeline.zrem('lru', key);
        });
        await pipeline.execAsync();
      }
    }
  }

  async close() {
    this.pool.forEach(client => client.quit());
  }
}

module.exports = RedisCache;
