        return self.mock_data.get('reverse_geocode', {}).get(coord_key)

class GeocodingService:
    def __init__(self, provider: GeocodeProvider, cache_dir: Optional[str] = None):
        self.provider = provider
        self.cache_dir = cache_dir
        if cache_dir and not os.path.exists(cache_dir):
            os.makedirs(cache_dir)

    @lru_cache(maxsize=1000)
    def geocode(self, address: str) -> Optional[Tuple[float, float]]:
        cache_key = f"geocode_{address}"
        result = self._get_from_cache(cache_key)

        if result is None:
            result = self.provider.geocode(address)
            self._save_to_cache(cache_key, result)

        return result

    @lru_cache(maxsize=1000)
    def reverse_geocode(self, lat: float, lng: float) -> Optional[str]:
        cache_key = f"reverse_{lat}_{lng}"
        result = self._get_from_cache(cache_key)

        if result is None:
            result = self.provider.reverse_geocode(lat, lng)
            self._save_to_cache(cache_key, result)

        return result

    def _get_from_cache(self, key: str) -> Optional[any]:
        if not self.cache_dir:
            return None

        cache_file = os.path.join(self.cache_dir, f"{key}.json")
        if os.path.exists(cache_file):
            with open(cache_file, 'r') as f:
                return json.load(f)
        return None

    def _save_to_cache(self, key: str, data: any) -> None:
        if not self.cache_dir or data is None:
            return

        cache_file = os.path.join(self.cache_dir, f"{key}.json")
        with open(cache_file, 'w') as f:
            json.dump(data, f)
