from prompt_toolkit.completion import WordCompleter
from prompt_toolkit.lexers import PygmentsLexer
from pygments.lexers.sql import SqlLexer
import sqlparse
import sqlite3

console = Console()
undo_stack = []

class Migration:
    def __init__(self, name: str, query: str):
        self.name = name
        self.query = query
        self.applied = False
        self.timestamp = None

    def apply(self, conn, dry_run=False):
        if not dry_run:
            cursor = conn.cursor()
            try:
                cursor.executescript(self.query)
                conn.commit()
                self.applied = True
                self.timestamp = time.time()
                undo_stack.append(self)
                return True
            except Exception as e:
                conn.rollback()
                console.print(f"[bold red]Error:[/bold red] {e}")
                return False
        else:
            console.print("[bold yellow]Dry run - not executing query[/bold yellow]")
            return True

    def rollback(self, conn):
        # In a real implementation, this would execute a rollback script
        console.print(f"Rolling back migration: {self.name}")
        self.applied = False
        return True

def validate_query(query: str) -> bool:
    try:
        parsed = sqlparse.parse(query)
        return len(parsed) > 0
    except:
        return False

def display_migrations(migrations: List[Migration]):
    table = Table(title="Available Migrations")
    table.add_column("Name", style="cyan")
    table.add_column("Status", style="green")
    table.add_column("Applied At", style="magenta")

    for migration in migrations:
        status = "[green]Applied[/green]" if migration.applied else "[yellow]Pending[/yellow]"
        timestamp = time.strftime('%Y-%m-%d %H:%M:%S', time.localtime(migration.timestamp)) if migration.timestamp else "-"
        table.add_row(migration.name, status, timestamp)

    console.print(table)

def preview_query(query: str):
    syntax = Syntax(query, "sql", theme="monokai", line_numbers=True)
    console.print("[bold blue]Query Preview:[/bold blue]")
    console.print(syntax)

def get_connection():
    # Create or connect to SQLite database
    if not os.path.exists("migrations"):
        os.makedirs("migrations")
    conn = sqlite3.connect("migrations/migrations.db")
    conn.execute('''CREATE TABLE IF NOT EXISTS migrations
                 (name TEXT PRIMARY KEY, query TEXT, applied INTEGER, timestamp REAL)''')
    return conn

def main():
    parser = argparse.ArgumentParser(description="Database Migration CLI Tool")
    parser.add_argument("--init", action="store_true", help="Initialize migration database")
    parser.add_argument("--create", help="Create a new migration")
    parser.add_argument("--apply", help="Apply a specific migration")
    parser.add_argument("--apply-all", action="store_true", help="Apply all pending migrations")
    parser.add_argument("--rollback", help="Rollback a specific migration")
    parser.add_argument("--list", action="store_true", help="List all migrations")
    parser.add_argument("--dry-run", action="store_true", help="Preview migrations without applying them")

    args = parser.parse_args()
    conn = get_connection()

    # Load existing migrations
    migrations: Dict[str, Migration] = {}
    cursor = conn.cursor()
    for row in cursor.execute("SELECT name, query, applied, timestamp FROM migrations"):
        migration = Migration(row[0], row[1])
        migration.applied = bool(row[2])
        migration.timestamp = row[3]
        migrations[migration.name] = migration

    if args.init:
        console.print("[bold green]Migration database initialized[/bold green]")

