        query = '\n'.join(lines)

        if validate_query(query):
            migration = Migration(args.create, query)
            cursor.execute("INSERT INTO migrations VALUES (?, ?, ?, ?)", 
                          (migration.name, migration.query, migration.applied, migration.timestamp))
            conn.commit()
            console.print(f"[bold green]Migration '{args.create}' created successfully[/bold green]")
            preview_query(query)
        else:
            console.print("[bold red]Invalid SQL query[/bold red]")

    elif args.apply:
        if args.apply in migrations:
            migration = migrations[args.apply]
            preview_query(migration.query)

            if args.dry_run or Confirm.ask("Apply this migration?"):
                with Progress() as progress:
                    task = progress.add_task("[green]Applying migration...", total=100)

                    for i in range(0, 101, 10):
                        progress.update(task, completed=i)
                        time.sleep(0.1)

                    if migration.apply(conn, args.dry_run):
                        if not args.dry_run:
                            cursor.execute("UPDATE migrations SET applied=?, timestamp=? WHERE name=?", 
