// auth.js
import { generateSecureRandom, sha256, base64UrlEncode } from './crypto-utils';

class OAuth2Client {
  constructor(config) {
    this.config = config;
    this.storage = window.sessionStorage;
  }

  async initiateLogin() {
    // Generate PKCE code verifier and challenge
    const codeVerifier = generateSecureRandom(64);
    const codeChallenge = base64UrlEncode(await sha256(codeVerifier));

    // Store code verifier for later verification
    this.storage.setItem('code_verifier', codeVerifier);

    // Generate and store CSRF token
    const state = generateSecureRandom(32);
    this.storage.setItem('oauth_state', state);

    // Construct authorization URL
    const authUrl = new URL(this.config.authorizationEndpoint);
    authUrl.searchParams.append('client_id', this.config.clientId);
    authUrl.searchParams.append('redirect_uri', this.config.redirectUri);
    authUrl.searchParams.append('response_type', 'code');
    authUrl.searchParams.append('scope', this.config.scope);
    authUrl.searchParams.append('state', state);
    authUrl.searchParams.append('code_challenge', codeChallenge);
    authUrl.searchParams.append('code_challenge_method', 'S256');

    // Redirect to authorization server
    window.location.href = authUrl.toString();
  }

  async handleRedirect() {
    const params = new URLSearchParams(window.location.search);
    const code = params.get('code');
    const state = params.get('state');

    // Verify state to prevent CSRF
    const storedState = this.storage.getItem('oauth_state');
    if (!state || state !== storedState) {
      throw new Error('Invalid state parameter, possible CSRF attack');
    }

    // Clear state from storage
    this.storage.removeItem('oauth_state');

    // Exchange code for tokens
    const codeVerifier = this.storage.getItem('code_verifier');
    this.storage.removeItem('code_verifier');

    return this.exchangeCodeForTokens(code, codeVerifier);
  }

  async exchangeCodeForTokens(code, codeVerifier) {
    const tokenUrl = this.config.tokenEndpoint;
    const params = new URLSearchParams();
    params.append('grant_type', 'authorization_code');
    params.append('client_id', this.config.clientId);
    params.append('redirect_uri', this.config.redirectUri);
    params.append('code', code);
    params.append('code_verifier', codeVerifier);

    const response = await fetch(tokenUrl, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'X-CSRF-Token': document.querySelector('meta[name="csrf-token"]').content
      },
      credentials: 'include',
      body: params
    });

    if (!response.ok) {
      throw new Error('Token exchange failed');
    }

    // Tokens are handled by the backend and stored in HTTP-only cookies
    return true;
  }

  async refreshTokens() {
    const refreshUrl = this.config.refreshEndpoint;

    // CSRF token from the meta tag
    const csrfToken = document.querySelector('meta[name="csrf-token"]').content;

    const response = await fetch(refreshUrl, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'X-CSRF-Token': csrfToken
      },
      credentials: 'include'
    });

    if (!response.ok) {
      throw new Error('Token refresh failed');
    }

    // Refresh handled by backend with new HTTP-only cookies
    return true;
  }
}
