const config = {
  clientId: process.env.OAUTH_CLIENT_ID,
  clientSecret: process.env.OAUTH_CLIENT_SECRET,
  redirectUri: process.env.OAUTH_REDIRECT_URI,
  authorizationEndpoint: process.env.OAUTH_AUTH_ENDPOINT,
  tokenEndpoint: process.env.OAUTH_TOKEN_ENDPOINT,
  scope: 'openid profile email'
};

// Token exchange endpoint
app.post('/api/token', async (req, res) => {
  const { code, code_verifier } = req.body;

  try {
    const params = new URLSearchParams();
    params.append('grant_type', 'authorization_code');
    params.append('client_id', config.clientId);
    params.append('client_secret', config.clientSecret);
    params.append('redirect_uri', config.redirectUri);
    params.append('code', code);
    params.append('code_verifier', code_verifier);

    const tokenResponse = await fetch(config.tokenEndpoint, {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: params
    });

    const tokens = await tokenResponse.json();

    if (tokenResponse.status !== 200) {
      throw new Error(tokens.error || 'Failed to exchange token');
    }

    // Store tokens in secure HTTP-only cookies
    setAuthCookies(res, tokens);

    // Return success but don't expose tokens to the frontend
    res.status(200).json({ success: true });
  } catch (error) {
    res.status(401).json({ error: 'Authentication failed' });
  }
});

// Token refresh endpoint
app.post('/api/refresh', async (req, res) => {
  try {
    const refreshToken = req.signedCookies.refresh_token;

    if (!refreshToken) {
      return res.status(401).json({ error: 'No refresh token' });
    }

    const params = new URLSearchParams();
    params.append('grant_type', 'refresh_token');
    params.append('client_id', config.clientId);
    params.append('client_secret', config.clientSecret);
    params.append('refresh_token', refreshToken);

    const tokenResponse = await fetch(config.tokenEndpoint, {
      method: 'POST',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: params
    });

    const tokens = await tokenResponse.json();

    if (tokenResponse.status !== 200) {
      throw new Error(tokens.error || 'Failed to refresh token');
    }

    // Update tokens in cookies
    setAuthCookies(res, tokens);

    res.status(200).json({ success: true });
  } catch (error) {
    // Clear invalid cookies
    clearAuthCookies(res);
    res.status(401).json({ error: 'Token refresh failed' });
  }
});

// Function to set secure auth cookies
function setAuthCookies(res, tokens) {
  const cookieOptions = {
    httpOnly: true,
    secure: true,
    sameSite: 'strict',
    signed: true,
    path: '/'
  };

  // Access token - shorter expiry
  res.cookie('access_token', tokens.access_token, {
    ...cookieOptions,
    maxAge: tokens.expires_in * 1000
  });

  // Refresh token - longer expiry
  if (tokens.refresh_token) {
    res.cookie('refresh_token', tokens.refresh_token, {
      ...cookieOptions,
      maxAge: 30 * 24 * 60 * 60 * 1000 // 30 days
    });
  }
}

// Function to clear auth cookies
function clearAuthCookies(res) {
  const cookieOptions = {
    httpOnly: true,
    secure: true,
    sameSite: 'strict',
    signed: true,
    path: '/'
  };

  res.cookie('access_token', '', { ...cookieOptions, maxAge: 0 });
  res.cookie('refresh_token', '', { ...cookieOptions, maxAge: 0 });
}

