```typescript:src/RulesEngine.ts
import { execSync } from 'child_process';
import * as fs from 'fs';

// Specification interface
interface Specification<T> {
  isSatisfiedBy(candidate: T): boolean;
  and(other: Specification<T>): Specification<T>;
  or(other: Specification<T>): Specification<T>;
  not(): Specification<T>;
}

// Abstract specification with default implementations
abstract class AbstractSpecification<T> implements Specification<T> {
  abstract isSatisfiedBy(candidate: T): boolean;

  and(other: Specification<T>): Specification<T> {
    return new AndSpecification<T>(this, other);
  }

  or(other: Specification<T>): Specification<T> {
    return new OrSpecification<T>(this, other);
  }

  not(): Specification<T> {
    return new NotSpecification<T>(this);
  }
}

// Composite specifications
class AndSpecification<T> extends AbstractSpecification<T> {
  constructor(
    private readonly left: Specification<T>,
    private readonly right: Specification<T>
  ) {
    super();
  }

  isSatisfiedBy(candidate: T): boolean {
    return this.left.isSatisfiedBy(candidate) && this.right.isSatisfiedBy(candidate);
  }
}

class OrSpecification<T> extends AbstractSpecification<T> {
  constructor(
    private readonly left: Specification<T>,
    private readonly right: Specification<T>
  ) {
    super();
  }

  isSatisfiedBy(candidate: T): boolean {
    return this.left.isSatisfiedBy(candidate) || this.right.isSatisfiedBy(candidate);
  }
}

class NotSpecification<T> extends AbstractSpecification<T> {
  constructor(private readonly specification: Specification<T>) {
    super();
  }

  isSatisfiedBy(candidate: T): boolean {
    return !this.specification.isSatisfiedBy(candidate);
  }
}

// Business rule specification
class BusinessRuleSpecification<T> extends AbstractSpecification<T> {
  constructor(
    private readonly rule: (candidate: T) => boolean,
    public readonly name: string,
    public readonly description: string
  ) {
    super();
  }

  isSatisfiedBy(candidate: T): boolean {
    return this.rule(candidate);
  }
}

// Rule result with action
interface RuleResult<T> {
  readonly specification: Specification<T>;
  readonly action: (candidate: T) => T;
  readonly name: string;
}

// Rule visualizer using Graphviz
class RuleVisualizer<T> {
  private idCounter = 0;
  private nodes: Map<Specification<T>, number> = new Map();
  private edges: Array<[number, number, string]> = [];

  generateId(spec: Specification<T>): number {
    if (!this.nodes.has(spec)) {
      this.nodes.set(spec, ++this.idCounter);
    }
    return this.nodes.get(spec)!;
  }

  buildGraph(spec: Specification<T>): string {
    const dot = ['digraph BusinessRules {', 'rankdir=TB;', 'node [shape=box];'];

    this.traverseSpecification(spec);

    // Add nodes
    for (const [spec, id] of this.nodes.entries()) {
      const label = this.getSpecificationLabel(spec);
      dot.push(`  ${id} [label="${label}"];`);
    }

    // Add edges
    for (const [from, to, label] of this.edges) {
      dot.push(`  ${from} -> ${to} [label="${label}"];`);
    }

    dot.push('}');
    return dot.join('\n');
  }

  private traverseSpecification(spec: Specification<T>): void {
    const id = this.generateId(spec);

    if (spec instanceof AndSpecification) {
      const leftId = this.generateId((spec as any).left);
      const rightId = this.generateId((spec as any).right);

      this.edges.push([id, leftId, 'AND']);
      this.edges.push([id, rightId, 'AND']);

      this.traverseSpecification((spec as any).left);
      this.traverseSpecification((spec as any).right);
    } else if (spec instanceof OrSpecification) {
      const leftId = this.generateId((spec as any).left);
      const rightId = this.generateId((spec as any).right);

      this.edges.push([id, leftId, 'OR']);
      this.edges.push([id, rightId, 'OR']);

      this.traverseSpecification((spec as any).left);
      this.traverseSpecification((spec as any).right);
    } else if (spec instanceof NotSpecification) {
      const innerSpecId = this.generateId((spec as any).specification);

      this.edges.push([id, innerSpecId, 'NOT']);

      this.traverseSpecification((spec as any).specification);
    }
  }

  private getSpecificationLabel(spec: Specification<T>): string {
    if (spec instanceof BusinessRuleSpecification) {
      return (spec as any).name;
    } else if (spec instanceof AndSpecification) {
      return 'AND';
    } else if (spec instanceof OrSpecification) {
      return 'OR';
    } else if (spec instanceof NotSpecification) {
      return 'NOT';
    }
    return 'Unknown';
  }

  visualize(spec: Specification<T>, outputPath: string): void {
    const dotContent = this.buildGraph(spec);
    const dotFile = `${outputPath}.dot`;
    const pngFile = `${outputPath}.png`;

    fs.writeFileSync(dotFile, dotContent);
    execSync(`dot -Tpng ${dotFile} -o ${pngFile}`);

    console.log(`Decision tree visualized at ${pngFile}`);
  }
}

// Rules engine implementation
export class RulesEngine<T> {
  private rules: Array<RuleResult<T>> = [];

  addRule(rule: RuleResult<T>): RulesEngine<T> {
    const newEngine = new RulesEngine<T>();
    newEngine.rules = [...this.rules, rule];
    return newEngine;
  }

  evaluate(candidate: T): T {
    let result = candidate;

    for (const rule of this.rules) {
      if (rule.specification.isSatisfiedBy(result)) {
        result = rule.action(result);
      }
    }

    return result;
  }

  visualizeRules(outputPath: string): void {
    if (this.rules.length === 0) return;

    // Combine all rules into a single specification for visualization
    let combinedSpec = this.rules[0].specification;

    for (let i = 1; i < this.rules.length; i++) {
      combinedSpec = combinedSpec.or(this.rules[i].specification);
    }

    const visualizer = new RuleVisualizer<T>();
    visualizer.visualize(combinedSpec, outputPath);
  }
}

// DSL for creating business rules
export class RuleBuilder<T> {
  static create<T>(name: string, description: string): RuleBuilder<T> {
    return new RuleBuilder<T>(name, description);
  }

  private spec: Specification<T> | null = null;
  private actionFn: ((t: T) => T) | null = null;

  private constructor(private readonly name: string, private readonly description: string) {}

  when(predicate: (t: T) => boolean): RuleBuilder<T> {
    this.spec = new BusinessRuleSpecification<T>(predicate, this.name, this.description);
    return this;
  }

  and(predicate: (t: T) => boolean): RuleBuilder<T> {
    if (!this.spec) throw new Error("Rule condition not set");
    const newSpec = new BusinessRuleSpecification<T>(predicate, `${this.name}_and`, this.description);
    this.spec = this.spec.and(newSpec);
    return this;
  }

  or(predicate: (t: T) => boolean): RuleBuilder<T> {
    if (!this.spec) throw new Error("Rule condition not set");
    const newSpec = new BusinessRuleSpecification<T>(predicate, `${this.name}_or`, this.description);
    this.spec = this.spec.or(newSpec);
    return this;
  }

  not(): RuleBuilder<T> {
    if (!this.spec) throw new Error("Rule condition not set");
    this.spec = this.spec.not();
    return this;
  }

  then(action: (t: T) => T): RuleResult<T> {
    if (!this.spec) throw new Error("Rule condition not set");
    this.actionFn = action;

    return {
      specification: this.spec,
      action: this.actionFn,
      name: this.name
    };
  }
}
