		return err
	}
	defer file.Close()

	gzipWriter := gzip.NewWriter(file)
	defer gzipWriter.Close()

	ips := []string{"192.168.1.1", "10.0.0.1", "172.16.0.1", "127.0.0.1"}
	methods := []string{"GET", "POST", "PUT", "DELETE"}
	paths := []string{"/index.html", "/api/users", "/login", "/static/css/main.css"}
	protocols := []string{"HTTP/1.0", "HTTP/1.1", "HTTP/2.0"}
	statuses := []string{"200", "201", "301", "404", "500"}
	bytes := []string{"1024", "2048", "4096", "8192"}

	r := rand.New(rand.NewSource(time.Now().UnixNano()))

	for i := 0; i < numLines; i++ {
		ip := ips[r.Intn(len(ips))]
		method := methods[r.Intn(len(methods))]
		path := paths[r.Intn(len(paths))]
		protocol := protocols[r.Intn(len(protocols))]
		status := statuses[r.Intn(len(statuses))]
		bytesSent := bytes[r.Intn(len(bytes))]

		timestamp := time.Now().Format("02/Jan/2006:15:04:05 -0700")

		logLine := fmt.Sprintf("%s - - [%s] \"%s %s %s\" %s %s\n", 
			ip, timestamp, method, path, protocol, status, bytesSent)

		if _, err := io.WriteString(gzipWriter, logLine); err != nil {
			return err
		}
	}

	return nil
}

func BenchmarkParser(b *testing.B) {
	sizes := []int{10000, 100000, 1000000}

	for _, size := range sizes {
		filename := fmt.Sprintf("testlog_%d.gz", size)

		// Generate test file once
		if err := generateTestLogFile(filename, size); err != nil {
			b.Fatalf("Failed to generate test file: %v", err)
		}
		defer os.Remove(filename)

		// Benchmark with different numbers of workers
		for workers := 1; workers <= runtime.NumCPU()*2; workers *= 2 {
			b.Run(fmt.Sprintf("Size=%d_Workers=%d", size, workers), func(b *testing.B) {
				parser := NewParser(workers)

				b.ResetTimer()
				for i := 0; i < b.N; i++ {
					count, err := parser.ParseFile(filename)
					if err != nil {
						b.Fatalf("Parser failed: %v", err)
					}
					b.ReportMetric(float64(count)/b.Elapsed().Seconds(), "lines/sec")
