func main() {
	workers := flag.Int("workers", runtime.NumCPU(), "Number of worker goroutines")
	flag.Parse()

	if flag.NArg() < 1 {
		fmt.Println("Usage: httplogparser [-workers=N] <gzipped-log-file>")
		os.Exit(1)
	}

	filename := flag.Arg(0)
	parser := httplogparser.NewParser(*workers)

	start := time.Now()
	count, err := parser.ParseFile(filename)
	elapsed := time.Since(start)

	if err != nil {
		fmt.Fprintf(os.Stderr, "Error parsing file: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Processed %d lines in %v\n", count, elapsed)
	fmt.Printf("Throughput: %.2f lines/second\n", float64(count)/elapsed.Seconds())
}
