const jwt = require('jsonwebtoken');
const crypto = require('crypto');
const fs = require('fs');
const path = require('path');

// Key management
const KEYS_DIR = path.join(__dirname, '../keys');
const ACTIVE_KEY_FILE = path.join(KEYS_DIR, 'active_key_id.txt');
const ROTATION_INTERVAL = 24 * 60 * 60 * 1000; // 24 hours

// Token configuration
const ACCESS_TOKEN_EXPIRY = '15m';
const REFRESH_TOKEN_EXPIRY = '7d';

// Blacklist for revoked tokens
const tokenBlacklist = new Map();

// Used tokens to prevent replay attacks
const usedTokens = new Set();

// Initialize keys directory
if (!fs.existsSync(KEYS_DIR)) {
  fs.mkdirSync(KEYS_DIR, { recursive: true });
}

// Generate a new key pair
function generateKeyPair(keyId) {
  const { privateKey, publicKey } = crypto.generateKeyPairSync('rsa', {
    modulusLength: 2048,
    publicKeyEncoding: {
      type: 'spki',
      format: 'pem'
    },
    privateKeyEncoding: {
      type: 'pkcs8',
      format: 'pem'
    }
  });

  fs.writeFileSync(path.join(KEYS_DIR, `private_${keyId}.pem`), privateKey);
  fs.writeFileSync(path.join(KEYS_DIR, `public_${keyId}.pem`), publicKey);
  return { privateKey, publicKey };
}

// Get current active key ID
function getActiveKeyId() {
  try {
    if (fs.existsSync(ACTIVE_KEY_FILE)) {
      return fs.readFileSync(ACTIVE_KEY_FILE, 'utf8').trim();
    }
  } catch (err) {
    console.error('Error reading active key ID:', err);
  }

  // If no active key, create one
  const newKeyId = Date.now().toString();
  fs.writeFileSync(ACTIVE_KEY_FILE, newKeyId);
  generateKeyPair(newKeyId);
  return newKeyId;
}

// Get private key for signing
function getPrivateKey() {
  const keyId = getActiveKeyId();
  const keyPath = path.join(KEYS_DIR, `private_${keyId}.pem`);
  return { key: fs.readFileSync(keyPath), keyId };
}

// Get public key for verification
function getPublicKey(keyId) {
  const keyPath = path.join(KEYS_DIR, `public_${keyId}.pem`);
  return fs.readFileSync(keyPath);
}

// Rotate keys on schedule
setInterval(() => {
  const newKeyId = Date.now().toString();
  generateKeyPair(newKeyId);
  fs.writeFileSync(ACTIVE_KEY_FILE, newKeyId);
  console.log(`Key rotated: ${newKeyId}`);
}, ROTATION_INTERVAL);

// Generate tokens
function generateTokens(payload) {
  const { key, keyId } = getPrivateKey();

  // Generate nonce for the token
  const jti = crypto.randomBytes(16).toString('hex');

  const accessToken = jwt.sign(
    { ...payload, type: 'access', jti },
    key,
    { 
      expiresIn: ACCESS_TOKEN_EXPIRY,
      algorithm: 'RS256',
      header: { kid: keyId }
    }
  );

  const refreshToken = jwt.sign(
    { ...payload, type: 'refresh', jti: crypto.randomBytes(16).toString('hex') },
    key,
    { 
      expiresIn: REFRESH_TOKEN_EXPIRY,
      algorithm: 'RS256',
      header: { kid: keyId }
    }
  );

  return { accessToken, refreshToken };
}

// Verify token
function verifyToken(token) {
  try {
    const decoded = jwt.decode(token, { complete: true });
    if (!decoded || !decoded.header || !decoded.header.kid) {
      throw new Error('Invalid token format');
    }

    const keyId = decoded.header.kid;
    const publicKey = getPublicKey(keyId);

    const verified = jwt.verify(token, publicKey, { algorithms: ['RS256'] });

    // Check if token is blacklisted
    if (tokenBlacklist.has(verified.jti)) {
      throw new Error('Token has been revoked');
    }

    // Check for replay attacks with nonce
    if (usedTokens.has(verified.jti)) {
      throw new Error('Token has already been used');
    }

    // Mark token as used if it's an access token
    if (verified.type === 'access') {
      usedTokens.add(verified.jti);

      // Clean up used tokens periodically (in a real implementation, use Redis with TTL)
      setTimeout(() => {
        usedTokens.delete(verified.jti);
      }, 15 * 60 * 1000); // 15 minutes
    }

    return verified;
  } catch (err) {
    throw err;
  }
}

// Refresh tokens
function refreshTokens(refreshToken) {
  try {
    const decoded = verifyToken(refreshToken);

    if (decoded.type !== 'refresh') {
      throw new Error('Not a refresh token');
    }

    // Generate new tokens
    const payload = { 
      userId: decoded.userId,
      role: decoded.role
    };

    // Blacklist the old refresh token
    tokenBlacklist.set(decoded.jti, true);

    return generateTokens(payload);
  } catch (err) {
    throw err;
  }
}

// Revoke token
function revokeToken(token) {
  try {
    const decoded = jwt.decode(token, { complete: true });
    if (decoded && decoded.payload && decoded.payload.jti) {
      tokenBlacklist.set(decoded.payload.jti, true);
      return true;
    }
    return false;
  } catch (err) {
    return false;
  }
}

module.exports = {
  generateTokens,
  verifyToken,
  refreshTokens,
  revokeToken
};
