const tokenService = require('../auth/tokenService');
const crypto = require('crypto');

// CSRF protection with double submit cookie pattern
function generateCsrfToken(req, res, next) {
  const csrfToken = crypto.randomBytes(32).toString('hex');

  // Set the CSRF token in a cookie with HttpOnly and SameSite flags
  res.cookie('XSRF-TOKEN', csrfToken, {
    httpOnly: false, // Readable by JS to include in headers
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'strict',
    path: '/',
    maxAge: 24 * 60 * 60 * 1000 // 24 hours
  });

  req.csrfToken = csrfToken;
  next();
}

// Validate CSRF token
function validateCsrfToken(req, res, next) {
  // Skip CSRF validation for GET, HEAD, OPTIONS
  if (['GET', 'HEAD', 'OPTIONS'].includes(req.method)) {
    return next();
  }

  const csrfCookie = req.cookies['XSRF-TOKEN'];
  const csrfHeader = req.headers['x-xsrf-token'];

  if (!csrfCookie || !csrfHeader || csrfCookie !== csrfHeader) {
    return res.status(403).json({ error: 'CSRF token validation failed' });
  }

  next();
}

// Authenticate request using JWT in Authorization header
function authenticate(req, res, next) {
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'No token provided' });
  }

  const token = authHeader.split(' ')[1];

  try {
    const decoded = tokenService.verifyToken(token);
    req.user = decoded;
    next();
  } catch (err) {
    if (err.name === 'TokenExpiredError') {
      return res.status(401).json({ error: 'Token expired', code: 'TOKEN_EXPIRED' });
    }
    return res.status(401).json({ error: 'Invalid token' });
  }
}

// Check role-based permissions
function authorize(roles = []) {
  if (typeof roles === 'string') {
    roles = [roles];
  }

  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json({ error: 'Unauthorized' });
    }

    if (roles.length && !roles.includes(req.user.role)) {
      return res.status(403).json({ error: 'Forbidden: insufficient permissions' });
    }

    next();
  };
}

module.exports = {
  generateCsrfToken,
  validateCsrfToken,
  authenticate,
  authorize
};
