package com.example.kafka.consumer;

import org.apache.kafka.clients.consumer.ConsumerRecords;
import org.apache.kafka.clients.consumer.KafkaConsumer;

import java.time.Duration;
import java.util.Collections;
import java.util.Properties;
import java.util.concurrent.ExecutorService;
import java.util.concurrent.Executors;
import java.util.concurrent.atomic.AtomicBoolean;
import java.util.function.Consumer;

public class KafkaEventConsumer implements EventConsumer {
    private final KafkaConsumer<String, String> consumer;
    private final String topic;
    private final AtomicBoolean running = new AtomicBoolean(false);
    private ExecutorService executor;
    private Consumer<String> eventHandler;

    public KafkaEventConsumer(Properties config, String topic) {
        this.consumer = new KafkaConsumer<>(config);
        this.topic = topic;
    }

    @Override
    public void subscribe(Consumer<String> eventHandler) {
        this.eventHandler = eventHandler;
        running.set(true);
        consumer.subscribe(Collections.singletonList(topic));

        executor = Executors.newSingleThreadExecutor();
        executor.submit(() -> {
            try {
                while (running.get()) {
                    ConsumerRecords<String, String> records = consumer.poll(Duration.ofMillis(100));
                    records.forEach(record -> eventHandler.accept(record.value()));
                }
            } finally {
                consumer.close();
            }
        });
    }

    @Override
    public void unsubscribe() {
        running.set(false);
        if (executor != null) {
            executor.shutdown();
        }
    }

    @Override
    public void close() {
        unsubscribe();
        consumer.close();
    }
}
