import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicReference;

import static org.junit.jupiter.api.Assertions.assertEquals;

@Testcontainers
class KafkaEventProcessorIntegrationTest {
    private static final String INPUT_TOPIC = "input-topic";
    private static final String OUTPUT_TOPIC = "output-topic";

    @Container
    private static final KafkaContainer kafka = new KafkaContainer(DockerImageName.parse("confluentinc/cp-kafka:latest"));

    private KafkaEventProcessor processor;
    private KafkaEventProducer testProducer;
    private KafkaEventConsumer outputConsumer;
    private AdminClient adminClient;

    @BeforeEach
    void setUp() throws Exception {
        // Create topics
        Properties adminProps = new Properties();
        adminProps.put(ProducerConfig.BOOTSTRAP_SERVERS_CONFIG, kafka.getBootstrapServers());
        adminClient = AdminClient.create(adminProps);
        adminClient.createTopics(
                Collections.singletonList(new NewTopic(INPUT_TOPIC, 1, (short) 1)))
                .all().get(30, TimeUnit.SECONDS);
        adminClient.createTopics(
                Collections.singletonList(new NewTopic(OUTPUT_TOPIC, 1, (short) 1)))
                .all().get(30, TimeUnit.SECONDS);

        // Set up the processor
        Properties producerProps = new Properties();
        producerProps.put(ProducerConfig.BOOTSTRAP_SERVERS_CONFIG, kafka.getBootstrapServers());
        producerProps.put(ProducerConfig.KEY_SERIALIZER_CLASS_CONFIG, StringSerializer.class.getName());
        producerProps.put(ProducerConfig.VALUE_SERIALIZER_CLASS_CONFIG, StringSerializer.class.getName());

        Properties consumerProps = new Properties();
        consumerProps.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, kafka.getBootstrapServers());
        consumerProps.put(ConsumerConfig.GROUP_ID_CONFIG, "test-" + UUID.randomUUID());
        consumerProps.put(ConsumerConfig.AUTO_OFFSET_RESET_CONFIG, "earliest");
        consumerProps.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class.getName());
        consumerProps.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class.getName());

        KafkaEventProducer producer = new KafkaEventProducer(producerProps);
        KafkaEventConsumer consumer = new KafkaEventConsumer(consumerProps, INPUT_TOPIC);

        processor = new KafkaEventProcessor(consumer, producer, OUTPUT_TOPIC);
        processor.start();

        // Set up test producer and consumer
        testProducer = new KafkaEventProducer(producerProps);
        outputConsumer = new KafkaEventConsumer(consumerProps, OUTPUT_TOPIC);
    }

    @AfterEach
    void tearDown() {
        processor.stop();
        testProducer.close();
        outputConsumer.close();
        adminClient.close();
    }

    @Test
    void shouldProcessEventEndToEnd() throws InterruptedException {
        // Given
        String testEvent = "hello world";
        String expectedOutput = "HELLO WORLD";
        AtomicReference<String> actualOutput = new AtomicReference<>();
        CountDownLatch latch = new CountDownLatch(1);

        // Set up the output consumer
        outputConsumer.subscribe(event -> {
            actualOutput.set(event);
            latch.countDown();
        });

        // When
        testProducer.send(INPUT_TOPIC, testEvent);

        // Then
        latch.await(10, TimeUnit.SECONDS);
        assertEquals(expectedOutput, actualOutput.get());
    }
}
