```rust:src/main.rs
use actix_multipart::{Field, Multipart};
use actix_web::{middleware, web, App, Error, HttpResponse, HttpServer};
use futures::{StreamExt, TryStreamExt};
use log::{error, info, warn};
use rusqlite::{params, Connection};
use serde::{Deserialize, Serialize};
use std::io::Write;
use std::path::Path;
use std::sync::Mutex;
use tokio::fs;
use tokio::time::{sleep, Duration};
use uuid::Uuid;

struct AppState {
    db: Mutex<Connection>,
    upload_dir: String,
}

#[derive(Debug, Serialize, Deserialize)]
struct UploadMeta {
    id: String,
    filename: String,
    content_type: String,
    size: i64,
    chunks_received: i64,
    complete: bool,
    created_at: i64,
    updated_at: i64,
}

async fn init_db(db_path: &str) -> Result<Connection, rusqlite::Error> {
    let conn = Connection::open(db_path)?;
    conn.execute(
        "CREATE TABLE IF NOT EXISTS uploads (
            id TEXT PRIMARY KEY,
            filename TEXT NOT NULL,
            content_type TEXT NOT NULL,
            size INTEGER NOT NULL,
            chunks_received INTEGER NOT NULL,
            complete BOOLEAN NOT NULL,
            created_at INTEGER NOT NULL,
            updated_at INTEGER NOT NULL
        )",
        [],
    )?;
    Ok(conn)
}

async fn save_chunk(
    field: Field,
    state: web::Data<AppState>,
    upload_id: &str,
    chunk_index: i64,
) -> Result<usize, Error> {
    let upload_dir = &state.upload_dir;
    let chunk_dir = format!("{}/{}", upload_dir, upload_id);

    // Ensure directory exists
    fs::create_dir_all(&chunk_dir).await.map_err(|e| {
        error!("Failed to create chunk directory: {}", e);
        actix_web::error::ErrorInternalServerError(e)
    })?;

    let chunk_path = format!("{}/{}.chunk", chunk_dir, chunk_index);
    let mut file = fs::File::create(&chunk_path).await.map_err(|e| {
        error!("Failed to create chunk file: {}", e);
        actix_web::error::ErrorInternalServerError(e)
    })?;

    let mut size = 0;

    // Process stream with retry logic
    let mut data_stream = field;
    while let Some(chunk_result) = data_stream.next().await {
        // Retry logic for failed chunk
        let mut retry_count = 0;
        let max_retries = 3;
        let mut chunk_data = None;

        while retry_count < max_retries {
            match chunk_result.clone() {
                Ok(data) => {
                    chunk_data = Some(data);
                    break;
                }
                Err(err) => {
                    warn!("Error processing chunk (attempt {}/{}): {}", 
                          retry_count + 1, max_retries, err);
                    retry_count += 1;
                    if retry_count < max_retries {
                        sleep(Duration::from_millis(500 * retry_count)).await;
                    } else {
                        return Err(actix_web::error::ErrorInternalServerError(err));
                    }
                }
            }
        }

        if let Some(chunk_data) = chunk_data {
            file.write_all(&chunk_data).await.map_err(|e| {
                error!("Failed to write chunk data: {}", e);
                actix_web::error::ErrorInternalServerError(e)
            })?;
            size += chunk_data.len();
        }
    }

    // Update database
    let db = state.db.lock().unwrap();
    db.execute(
        "UPDATE uploads SET 
         chunks_received = chunks_received + 1,
         updated_at = ?
         WHERE id = ?",
        params![chrono::Utc::now().timestamp(), upload_id],
    )
    .map_err(|e| {
        error!("Database error updating chunks received: {}", e);
        actix_web::error::ErrorInternalServerError(e)
    })?;

    Ok(size)
}

async fn start_upload(
    state: web::Data<AppState>,
    filename: String,
    content_type: String,
    expected_size: i64,
) -> Result<String, Error> {
    let upload_id = Uuid::new_v4().to_string();
    let now = chrono::Utc::now().timestamp();

    let upload = UploadMeta {
        id: upload_id.clone(),
        filename,
        content_type,
        size: expected_size,
        chunks_received: 0,
        complete: false,
        created_at: now,
        updated_at: now,
    };

    let db = state.db.lock().unwrap();
    db.execute(
        "INSERT INTO uploads 
         (id, filename, content_type, size, chunks_received, complete, created_at, updated_at) 
         VALUES (?, ?, ?, ?, ?, ?, ?, ?)",
        params![
            upload.id,
            upload.filename,
            upload.content_type,
            upload.size,
            upload.chunks_received,
            upload.complete,
            upload.created_at,
            upload.updated_at
        ],
    )
    .map_err(|e| {
        error!("Database error creating upload record: {}", e);
        actix_web::error::ErrorInternalServerError(e)
    })?;

    Ok(upload_id)
}

async fn finish_upload(
    state: web::Data<AppState>,
    upload_id: &str,
) -> Result<(), Error> {
    let upload_dir = &state.upload_dir;
    let chunk_dir = format!("{}/{}", upload_dir, upload_id);
    let final_path = format!("{}/{}.final", upload_dir, upload_id);

    // Get upload info
    let db = state.db.lock().unwrap();
    let upload: UploadMeta = db
        .query_row(
            "SELECT * FROM uploads WHERE id = ?",
            params![upload_id],
            |row| {
                Ok(UploadMeta {
                    id: row.get(0)?,
                    filename: row.get(1)?,
                    content_type: row.get(2)?,
                    size: row.get(3)?,
                    chunks_received: row.get(4)?,
                    complete: row.get(5)?,
                    created_at: row.get(6)?,
                    updated_at: row.get(7)?,
                })
            },
        )
        .map_err(|e| {
            error!("Database error retrieving upload record: {}", e);
            actix_web::error::ErrorInternalServerError(e)
        })?;

    // Create final file by combining chunks
    let mut final_file = fs::File::create(&final_path).await.map_err(|e| {
        error!("Failed to create final file: {}", e);
        actix_web::error::ErrorInternalServerError(e)
    })?;

    for i in 0..upload.chunks_received {
        let chunk_path = format!("{}/{}.chunk", chunk_dir, i);
        let chunk_data = fs::read(&chunk_path).await.map_err(|e| {
            error!("Failed to read chunk file {}: {}", chunk_path, e);
            actix_web::error::ErrorInternalServerError(e)
        })?;

        final_file.write_all(&chunk_data).await.map_err(|e| {
            error!("Failed to write to final file: {}", e);
            actix_web::error::ErrorInternalServerError(e)
        })?;
    }

    // Mark upload as complete
    db.execute(
        "UPDATE uploads SET complete = 1, updated_at = ? WHERE id = ?",
        params![chrono::Utc::now().timestamp(), upload_id],
    )
    .map_err(|e| {
        error!("Database error marking upload as complete: {}", e);
        actix_web::error::ErrorInternalServerError(e)
    })?;

    Ok(())
}

async fn upload(
    mut payload: Multipart,
    state: web::Data<AppState>,
) -> Result<HttpResponse, Error> {
    let mut upload_id = String::new();
    let mut chunk_index = 0;

    while let Some(item) = payload.next().await {
        let field = item?;
        let content_disposition = field.content_disposition().ok_or_else(|| {
            error!("Missing content disposition");
            actix_web::error::ErrorBadRequest("Missing content disposition")
        })?;

        let name = content_disposition.get_name().ok_or_else(|| {
            error!("Missing field name");
            actix_web::error::ErrorBadRequest("Missing field name")
        })?;

        match name {
            "upload_id" => {
                let mut id = String::new();
                let mut field_stream = field;
                while let Some(chunk) = field_stream.next().await {
                    let data = chunk?;
                    id.push_str(std::str::from_utf8(&data).map_err(|e| {
                        error!("Invalid UTF-8 in upload_id: {}", e);
                        actix_web::error::ErrorBadRequest("Invalid UTF-8 in upload_id")
                    })?);
                }
                upload_id = id;
            }
            "file" => {
                let filename = content_disposition
                    .get_filename()
                    .map(|f| Path::new(f).file_name().unwrap().to_string_lossy().to_string())
                    .unwrap_or_else(|| "unknown".to_string());

                let content_type = field
                    .content_type()
                    .map(|t| t.to_string())
                    .unwrap_or_else(|| "application/octet-stream".to_string());

                if upload_id.is_empty() {
                    upload_id = start_upload(
                        state.clone(),
                        filename,
                        content_type,
                        content_disposition.get_size().unwrap_or(0),
                    )
                    .await?;
                }

                save_chunk(field, state.clone(), &upload_id, chunk_index).await?;
                chunk_index += 1;
            }
            "finish" => {
                if !upload_id.is_empty() {
                    finish_upload(state.clone(), &upload_id).await?;
                }
            }
            _ => {
                warn!("Unhandled field: {}", name);
            }
        }
    }

    Ok(HttpResponse::Ok().json(serde_json::json!({
        "upload_id": upload_id,
        "chunks_processed": chunk_index
    })))
}

async fn get_upload_status(
    path: web::Path<String>,
    state: web::Data<AppState>,
) -> Result<HttpResponse, Error> {
    let upload_id = path.into_inner();
    let db = state.db.lock().unwrap();

    match db.query_row(
        "SELECT * FROM uploads WHERE id = ?",
        params![upload_id],
        |row| {
            Ok(UploadMeta {
                id: row.get(0)?,
                filename: row.get(1)?,
                content_type: row.get(2)?,
                size: row.get(3)?,
                chunks_received: row.get(4)?,
                complete: row.get(5)?,
                created_at: row.get(6)?,
                updated_at: row.get(7)?,
            })
        },
    ) {
        Ok(upload) => Ok(HttpResponse::Ok().json(upload)),
        Err(rusqlite::Error::QueryReturnedNoRows) => {
            Ok(HttpResponse::NotFound().json(serde_json::json!({
                "error": "Upload not found"
            })))
        }
        Err(e) => {
            error!("Database error getting upload status: {}", e);
            Err(actix_web::error::ErrorInternalServerError(e))
        }
    }
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    env_logger::init_from_env(env_logger::Env::new().default_filter_or("info"));

    let upload_dir = std::env::var("UPLOAD_DIR").unwrap_or_else(|_| "./uploads".to_string());
    let db_path = std::env::var("DB_PATH").unwrap_or_else(|_| "./uploads.db".to_string());

    // Create upload directory
    std::fs::create_dir_all(&upload_dir)?;

    // Initialize database
    let db = init_db(&db_path).await.map_err(|e| {
        error!("Failed to initialize database: {}", e);
        std::io::Error::new(std::io::ErrorKind::Other, e)
    })?;

    let app_state = web::Data::new(AppState {
        db: Mutex::new(db),
        upload_dir: upload_dir.clone(),
    });

    info!("Starting server at http://127.0.0.1:8080");

    HttpServer::new(move || {
        App::new()
            .app_data(app_state.clone())
            .wrap(middleware::Logger::default())
            .route("/upload", web::post().to(upload))
            .route("/upload/{id}", web::get().to(get_upload_status))
    })
    .bind("127.0.0.1:8080")?
    .run()
    .await
}
