```src/components/JsonSchemaEditor.tsx
import React, { useState, useEffect, useCallback } from 'react';
import MonacoEditor from '@monaco-editor/react';
import { editor } from 'monaco-editor';
import Ajv from 'ajv';
import TreeView from './TreeView';
import Toolbar from './Toolbar';
import './JsonSchemaEditor.css';
import { EditorState, SchemaNode } from '../types';
import { parseSchema, generateJsonFromSchema } from '../utils/schemaUtils';

const ajv = new Ajv({ allErrors: true });

const JsonSchemaEditor: React.FC = () => {
  const [schema, setSchema] = useState<any>({ type: 'object', properties: {} });
  const [jsonOutput, setJsonOutput] = useState<string>('{}');
  const [editorState, setEditorState] = useState<EditorState>({
    history: [{ schema: { type: 'object', properties: {} }, json: '{}' }],
    currentIndex: 0,
  });
  const [validationErrors, setValidationErrors] = useState<string[]>([]);
  const [hoveredNode, setHoveredNode] = useState<string | null>(null);
  const [schemaTree, setSchemaTree] = useState<SchemaNode[]>([]);

  useEffect(() => {
    setSchemaTree(parseSchema(schema));
  }, [schema]);

  const validateJson = useCallback((json: string, schema: any) => {
    try {
      const parsedJson = JSON.parse(json);
      const validate = ajv.compile(schema);
      const valid = validate(parsedJson);
      if (!valid && validate.errors) {
        setValidationErrors(validate.errors.map(err => 
          `${err.instancePath} ${err.message}`
        ));
      } else {
        setValidationErrors([]);
      }
    } catch (err) {
      setValidationErrors([`Invalid JSON: ${err instanceof Error ? err.message : String(err)}`]);
    }
  }, []);

  useEffect(() => {
    validateJson(jsonOutput, schema);
  }, [jsonOutput, schema, validateJson]);

  const handleSchemaChange = (value: string | undefined) => {
    if (!value) return;

    try {
      const newSchema = JSON.parse(value);
      setSchema(newSchema);
      const newJson = generateJsonFromSchema(newSchema);
      setJsonOutput(JSON.stringify(newJson, null, 2));

      // Save to history for undo/redo
      const newHistory = editorState.history.slice(0, editorState.currentIndex + 1);
      newHistory.push({ schema: newSchema, json: JSON.stringify(newJson, null, 2) });
      setEditorState({
        history: newHistory,
        currentIndex: newHistory.length - 1,
      });
    } catch (err) {
      console.error("Invalid schema:", err);
    }
  };

  const handleNodeHover = (path: string) => {
    setHoveredNode(path);
  };

  const handleUndo = () => {
    if (editorState.currentIndex > 0) {
      const newIndex = editorState.currentIndex - 1;
      const prevState = editorState.history[newIndex];
      setSchema(prevState.schema);
      setJsonOutput(prevState.json);
      setEditorState({ ...editorState, currentIndex: newIndex });
    }
  };

  const handleRedo = () => {
    if (editorState.currentIndex < editorState.history.length - 1) {
      const newIndex = editorState.currentIndex + 1;
      const nextState = editorState.history[newIndex];
      setSchema(nextState.schema);
      setJsonOutput(nextState.json);
      setEditorState({ ...editorState, currentIndex: newIndex });
    }
  };

  const handleEditorDidMount = (editor: editor.IStandaloneCodeEditor) => {
    // Set up autocomplete suggestions
    editor.getModel()?.updateOptions({ tabSize: 2 });
  };

  return (
    <div className="json-schema-editor">
      <Toolbar 
        canUndo={editorState.currentIndex > 0}
        canRedo={editorState.currentIndex < editorState.history.length - 1}
        onUndo={handleUndo}
        onRedo={handleRedo}
      />
      <div className="editor-container">
        <div className="tree-panel">
          <TreeView 
            nodes={schemaTree} 
            onNodeHover={handleNodeHover}
            hoveredNode={hoveredNode}
          />
        </div>
        <div className="monaco-container">
          <div className="editor-header">Schema</div>
          <MonacoEditor
            height="100%"
            language="json"
            value={JSON.stringify(schema, null, 2)}
            onChange={handleSchemaChange}
            onMount={handleEditorDidMount}
            options={{
              minimap: { enabled: false },
              scrollBeyondLastLine: false,
              automaticLayout: true,
            }}
          />
        </div>
        <div className="monaco-container">
          <div className="editor-header">JSON Output</div>
          <MonacoEditor
            height="100%"
            language="json"
            value={jsonOutput}
            options={{
              readOnly: true,
              minimap: { enabled: false },
              scrollBeyondLastLine: false,
              automaticLayout: true,
            }}
          />
        </div>
      </div>
      {validationErrors.length > 0 && (
        <div className="validation-errors">
          <h3>Validation Errors</h3>
          <ul>
            {validationErrors.map((error, index) => (
              <li key={index}>{error}</li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
};

export default JsonSchemaEditor;
