import React from 'react';
import { FiChevronRight, FiChevronDown, FiType, FiHash, FiAlignLeft, FiCalendar, FiList, FiGrid } from 'react-icons/fi';
import { SchemaNode } from '../types';
import './TreeView.css';

interface TreeViewProps {
  nodes: SchemaNode[];
  onNodeHover: (path: string) => void;
  hoveredNode: string | null;
}

const getTypeIcon = (type: string) => {
  switch (type) {
    case 'string': return <FiAlignLeft />;
    case 'number': return <FiHash />;
    case 'integer': return <FiHash />;
    case 'boolean': return <FiType />;
    case 'object': return <FiGrid />;
    case 'array': return <FiList />;
    case 'date': return <FiCalendar />;
    default: return <FiType />;
  }
};

const TreeNodeComponent: React.FC<{
  node: SchemaNode;
  level: number;
  onNodeHover: (path: string) => void;
  hoveredNode: string | null;
}> = ({ node, level, onNodeHover, hoveredNode }) => {
  const [expanded, setExpanded] = React.useState(level < 2);

  const handleToggle = () => {
    setExpanded(!expanded);
  };

  const handleMouseEnter = () => {
    onNodeHover(node.path);
  };

  const handleMouseLeave = () => {
    onNodeHover('');
  };

  const isHovered = hoveredNode === node.path;

  return (
    <div className="tree-node">
      <div 
        className={`node-header ${isHovered ? 'hovered' : ''}`}
        style={{ paddingLeft: `${level * 20}px` }}
        onMouseEnter={handleMouseEnter}
        onMouseLeave={handleMouseLeave}
      >
        {node.children.length > 0 && (
          <span className="toggle-icon" onClick={handleToggle}>
            {expanded ? <FiChevronDown /> : <FiChevronRight />}
          </span>
        )}
        <span className="type-icon">{getTypeIcon(node.type)}</span>
        <span className="node-name">{node.name}</span>
        <span className="node-type">{node.type}</span>
        {node.description && (
          <span className="node-tooltip" title={node.description}>ℹ️</span>
        )}
      </div>
      {expanded && node.children.length > 0 && (
        <div className="node-children">
          {node.children.map((child, index) => (
            <TreeNodeComponent 
              key={index} 
              node={child} 
              level={level + 1} 
              onNodeHover={onNodeHover}
              hoveredNode={hoveredNode}
            />
          ))}
        </div>
      )}
    </div>
  );
};

const TreeView: React.FC<TreeViewProps> = ({ nodes, onNodeHover, hoveredNode }) => {
  return (
    <div className="tree-view">
      <div className="tree-header">
        <h3>Schema Structure</h3>
      </div>
      <div className="tree-content">
        {nodes.map((node, index) => (
          <TreeNodeComponent 
            key={index} 
            node={node} 
            level={0} 
            onNodeHover={onNodeHover}
            hoveredNode={hoveredNode}
          />
        ))}
      </div>
    </div>
  );
};

export default TreeView;
