```src/utils/schemaUtils.ts
import { SchemaNode } from '../types';

export const parseSchema = (schema: any, path: string = '', name: string = 'root'): SchemaNode[] => {
  if (!schema) return [];

  // Handle case where schema is just a type definition
  if (typeof schema === 'string') {
    return [
      {
        name,
        type: schema,
        path,
        required: false,
        children: []
      }
    ];
  }

  // Handle the case where schema is a reference
  if (schema.$ref) {
    return [
      {
        name,
        type: 'ref',
        description: `Reference to ${schema.$ref}`,
        path,
        required: false,
        children: []
      }
    ];
  }

  // For root schema or nested objects
  if (schema.type === 'object' && schema.properties) {
    const node: SchemaNode = {
      name,
      type: 'object',
      description: schema.description,
      path,
      required: false,
      children: [],
      properties: schema.properties
    };

    const requiredProps = schema.required || [];

    for (const propName in schema.properties) {
      const propPath = path ? `${path}.${propName}` : propName;
      const propSchema = schema.properties[propName];
      const isRequired = requiredProps.includes(propName);

      const childNodes = parseSchema(propSchema, propPath, propName).map(child => {
        child.required = isRequired;
        return child;
      });

      node.children.push(...childNodes);
    }

    return [node];
  }

  // For arrays
  if (schema.type === 'array' && schema.items) {
    const node: SchemaNode = {
      name,
      type: 'array',
      description: schema.description,
      path,
      required: false,
      children: []
    };

    const itemPath = `${path}[0]`;
    const childNodes = parseSchema(schema.items, itemPath, 'items');
    node.children.push(...childNodes);

    return [node];
  }

  // For primitive types
  return [
    {
      name,
      type: schema.type || 'unknown',
      description: schema.description,
      path,
      required: false,
      children: []
    }
  ];
};

export const generateJsonFromSchema = (schema: any): any => {
  if (!schema || !schema.type) {
    return null;
  }

  switch (schema.type) {
    case 'object':
      const obj: Record<string, any> = {};
      if (schema.properties) {
        for (const propName in schema.properties) {
          obj[propName] = generateJsonFromSchema(schema.properties[propName]);
        }
      }
      return obj;

    case 'array':
      if (schema.items) {
        return [generateJsonFromSchema(schema.items)];
      }
      return [];

    case 'string':
      return schema.default || schema.examples?.[0] || "";

    case 'number':
    case 'integer':
      return schema.default || schema.examples?.[0] || 0;

    case 'boolean':
      return schema.default || false;

    case 'null':
      return null;

    default:
      return null;
  }
};
