	"github.com/gorilla/mux"
	"github.com/jmoiron/sqlx"
	"golang.org/x/time/rate"
)

// Configuration
type Config struct {
	ClientID          string
	ClientSecret      string
	RedirectURI       string
	AuthServerURL     string
	TokenServerURL    string
	Port              string
	TLSCert           string
	TLSKey            string
	DSN               string
	JWTSecret         []byte
	RateLimitRequests int
	RateLimitPeriod   time.Duration
}

// DB models
type Client struct {
	ID           string    `db:"id"`
	Secret       string    `db:"secret"`
	RedirectURIs string    `db:"redirect_uris"`
	CreatedAt    time.Time `db:"created_at"`
}

type AuthRequest struct {
	State          string    `db:"state"`
	CodeChallenge  string    `db:"code_challenge"`
	CodeVerifier   string    `db:"code_verifier"`
	ClientID       string    `db:"client_id"`
	RedirectURI    string    `db:"redirect_uri"`
	Scope          string    `db:"scope"`
	CodeChallengeMethod string `db:"code_challenge_method"`
	Code           string    `db:"code"`
	ExpiresAt      time.Time `db:"expires_at"`
	Used           bool      `db:"used"`
	UserID         string    `db:"user_id"`
}

type Token struct {
	AccessToken  string    `db:"access_token" json:"access_token"`
	RefreshToken string    `db:"refresh_token" json:"refresh_token,omitempty"`
	TokenType    string    `db:"token_type" json:"token_type"`
	ExpiresIn    int       `db:"expires_in" json:"expires_in"`
	Scope        string    `db:"scope" json:"scope"`
	UserID       string    `db:"user_id" json:"-"`
	ClientID     string    `db:"client_id" json:"-"`
	ExpiresAt    time.Time `db:"expires_at" json:"-"`
	Revoked      bool      `db:"revoked" json:"-"`
}

type AuditLog struct {
	ID        int64     `db:"id"`
	Action    string    `db:"action"`
	Actor     string    `db:"actor"`
	Resource  string    `db:"resource"`
	Timestamp time.Time `db:"timestamp"`
	IP        string    `db:"ip"`
	UserAgent string    `db:"user_agent"`
	Success   bool      `db:"success"`
	Details   string    `db:"details"`
}

var (
	config  Config
	db      *sqlx.DB
	limiter = make(map[string]*rate.Limiter)
	mu      sync.Mutex
)

func main() {
	// Load configuration from environment
	config = Config{
		ClientID:          os.Getenv("CLIENT_ID"),
		ClientSecret:      os.Getenv("CLIENT_SECRET"),
		RedirectURI:       os.Getenv("REDIRECT_URI"),
		AuthServerURL:     os.Getenv("AUTH_SERVER_URL"),
		TokenServerURL:    os.Getenv("TOKEN_SERVER_URL"),
		Port:              os.Getenv("PORT"),
		TLSCert:           os.Getenv("TLS_CERT"),
		TLSKey:            os.Getenv("TLS_KEY"),
		DSN:               os.Getenv("DATABASE_DSN"),
		JWTSecret:         []byte(os.Getenv("JWT_SECRET")),
		RateLimitRequests: 100,
		RateLimitPeriod:   time.Minute,
	}

	// Initialize database
	initDB()

	// Setup router
	r := mux.NewRouter()

	// OAuth endpoints
	r.HandleFunc("/authorize", rateLimitMiddleware(tlsMiddleware(authorizeHandler))).Methods("GET")
	r.HandleFunc("/token", rateLimitMiddleware(tlsMiddleware(tokenHandler))).Methods("POST")
	r.HandleFunc("/revoke", rateLimitMiddleware(tlsMiddleware(revokeHandler))).Methods("POST")

	// Set up TLS
	server := &http.Server{
		Addr:         ":" + config.Port,
		Handler:      r,
		TLSConfig:    &tls.Config{MinVersion: tls.VersionTLS12},
		ReadTimeout:  15 * time.Second,
		WriteTimeout: 15 * time.Second,
		IdleTimeout:  60 * time.Second,
	}

	log.Printf("Starting OAuth server on port %s", config.Port)
	log.Fatal(server.ListenAndServeTLS(config.TLSCert, config.TLSKey))
}

func initDB() {
	var err error
	db, err = sqlx.Connect("mysql", config.DSN)
	if err != nil {
		log.Fatalf("Could not connect to database: %v", err)
	}

	// Initialize tables
	initSchema := `
	CREATE TABLE IF NOT EXISTS clients (
		id VARCHAR(255) PRIMARY KEY,
		secret VARCHAR(255) NOT NULL,
		redirect_uris TEXT NOT NULL,
		created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
	);

	CREATE TABLE IF NOT EXISTS auth_requests (
		state VARCHAR(255) NOT NULL,
		code_challenge VARCHAR(255) NOT NULL,
		code_verifier VARCHAR(255) NOT NULL,
		client_id VARCHAR(255) NOT NULL,
		redirect_uri VARCHAR(255) NOT NULL,
		scope VARCHAR(255) NOT NULL,
		code_challenge_method VARCHAR(20) NOT NULL,
		code VARCHAR(255) NOT NULL PRIMARY KEY,
		expires_at TIMESTAMP NOT NULL,
		used BOOLEAN DEFAULT FALSE,
		user_id VARCHAR(255) NOT NULL
	);

	CREATE TABLE IF NOT EXISTS tokens (
		access_token VARCHAR(2048) PRIMARY KEY,
		refresh_token VARCHAR(2048) UNIQUE,
		token_type VARCHAR(20) NOT NULL,
		expires_in INT NOT NULL,
		scope VARCHAR(255) NOT NULL,
		user_id VARCHAR(255) NOT NULL,
		client_id VARCHAR(255) NOT NULL,
		expires_at TIMESTAMP NOT NULL,
		revoked BOOLEAN DEFAULT FALSE
	);

	CREATE TABLE IF NOT EXISTS audit_logs (
		id BIGINT AUTO_INCREMENT PRIMARY KEY,
		action VARCHAR(50) NOT NULL,
		actor VARCHAR(255) NOT NULL,
		resource VARCHAR(255) NOT NULL,
		timestamp TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
		ip VARCHAR(45) NOT NULL,
		user_agent VARCHAR(255) NOT NULL,
		success BOOLEAN NOT NULL,
		details TEXT
	);`

	_, err = db.Exec(initSchema)
	if err != nil {
		log.Fatalf("Could not initialize database schema: %v", err)
	}
}

// Middleware
func tlsMiddleware(next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if r.TLS == nil {
			w.Header().Add("Strict-Transport-Security", "max-age=63072000; includeSubDomains")
			http.Error(w, "TLS Required", http.StatusBadRequest)
			logAudit("tls_enforcement", "anonymous", "endpoint", r, false, "TLS required but not used")
			return
		}
		next(w, r)
	}
}

func rateLimitMiddleware(next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		ip := getClientIP(r)

		mu.Lock()
		if _, exists := limiter[ip]; !exists {
			limiter[ip] = rate.NewLimiter(rate.Limit(config.RateLimitRequests)/config.RateLimitPeriod.Minutes(), config.RateLimitRequests)
		}
		ratelimiter := limiter[ip]
		mu.Unlock()

		if !ratelimiter.Allow() {
			http.Error(w, "Rate limit exceeded", http.StatusTooManyRequests)
			logAudit("rate_limit_exceeded", "anonymous", "endpoint", r, false, "Rate limit exceeded from IP: "+ip)
			return
		}
		next(w, r)
	}
}

// OAuth handlers
func authorizeHandler(w http.ResponseWriter, r *http.Request) {
	clientID := r.URL.Query().Get("client_id")
	redirectURI := r.URL.Query().Get("redirect_uri")
	state := r.URL.Query().Get("state")
	responseType := r.URL.Query().Get("response_type")
	scope := r.URL.Query().Get("scope")
	codeChallenge := r.URL.Query().Get("code_challenge")
	codeChallengeMethod := r.URL.Query().Get("code_challenge_method")

	// Validate parameters
	if clientID == "" || redirectURI == "" || state == "" || responseType != "code" {
		http.Error(w, "Invalid request parameters", http.StatusBadRequest)
		logAudit("authorize_request", clientID, "authorization", r, false, "Invalid request parameters")
		return
	}

	// PKCE is required
	if codeChallenge == "" || codeChallengeMethod == "" {
		http.Error(w, "PKCE required", http.StatusBadRequest)
		logAudit("authorize_request", clientID, "authorization", r, false, "PKCE parameters missing")
		return
	}

	if codeChallengeMethod != "S256" {
		http.Error(w, "Only S256 code challenge method is supported", http.StatusBadRequest)
		logAudit("authorize_request", clientID, "authorization", r, false, "Unsupported code challenge method")
		return
	}

	// Validate client
	var client Client
	err := db.Get(&client, "SELECT * FROM clients WHERE id = ?", clientID)
	if err != nil {
		http.Error(w, "Invalid client", http.StatusBadRequest)
		logAudit("authorize_request", clientID, "authorization", r, false, "Invalid client ID")
		return
	}

	// Validate redirect URI against registered URIs
	validURIs := strings.Split(client.RedirectURIs, ",")
	validRedirect := false
	for _, uri := range validURIs {
		if uri == redirectURI {
			validRedirect = true
			break
		}
	}

	if !validRedirect {
		http.Error(w, "Invalid redirect URI", http.StatusBadRequest)
		logAudit("authorize_request", clientID, "authorization", r, false, "Invalid redirect URI")
		return
	}

	// In a real app, you would authenticate the user here
	// For this example, we'll assume the user is authenticated with ID "user123"
	userID := "user123"

	// Generate authorization code
	code, codeVerifier, err := generateCode()
	if err != nil {
		http.Error(w, "Server error", http.StatusInternalServerError)
		logAudit("authorize_request", clientID, "authorization", r, false, fmt.Sprintf("Error generating code: %v", err))
		return
	}

	// Save auth request
	authRequest := AuthRequest{
		State:               state,
		CodeChallenge:       codeChallenge,
		CodeVerifier:        codeVerifier,
		ClientID:            clientID,
		RedirectURI:         redirectURI,
		Scope:               scope,
		CodeChallengeMethod: codeChallengeMethod,
		Code:                code,
		ExpiresAt:           time.Now().Add(10 * time.Minute),
		Used:                false,
		UserID:              userID,
	}

	_, err = db.NamedExec(`
		INSERT INTO auth_requests (
			state, code_challenge, code_verifier, client_id, redirect_uri, 
			scope, code_challenge_method, code, expires_at, used, user_id
		) VALUES (
			:state, :code_challenge, :code_verifier, :client_id, :redirect_uri,
			:scope, :code_challenge_method, :code, :expires_at, :used, :user_id
		)`, authRequest)

	if err != nil {
		http.Error(w, "Server error", http.StatusInternalServerError)
		logAudit("authorize_request", clientID, "authorization", r, false, fmt.Sprintf("Error saving auth request: %v", err))
		return
	}

	// Redirect with code
	redirectURL := fmt.Sprintf("%s?code=%s&state=%s", redirectURI, code, state)
	logAudit("authorize_request", clientID, "authorization", r, true, fmt.Sprintf("Authorization granted for user %s", userID))
	http.Redirect(w, r, redirectURL, http.StatusFound)
}

func tokenHandler(w http.ResponseWriter, r *http.Request) {
	err := r.ParseForm()
	if err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		logAudit("token_request", "anonymous", "token", r, false, "Error parsing form")
		return
	}

	grantType := r.Form.Get("grant_type")
	code := r.Form.Get("code")
	redirectURI := r.Form.Get("redirect_uri")
	clientID := r.Form.Get("client_id")
	codeVerifier := r.Form.Get("code_verifier")

	// Validate parameters
	if grantType != "authorization_code" || code == "" || redirectURI == "" || clientID == "" || codeVerifier == "" {
		http.Error(w, "Invalid request parameters", http.StatusBadRequest)
		logAudit("token_request", clientID, "token", r, false, "Invalid request parameters")
		return
	}

	// Validate code and client
	var authRequest AuthRequest
	err = db.Get(&authRequest, "SELECT * FROM auth_requests WHERE code = ? AND client_id = ? AND expires_at > ?", 
		code, clientID, time.Now())

	if err != nil {
		http.Error(w, "Invalid code", http.StatusBadRequest)
		logAudit("token_request", clientID, "token", r, false, "Invalid or expired code")
		return
	}

	// Validate redirect URI
	if authRequest.RedirectURI != redirectURI {
		http.Error(w, "Invalid redirect URI", http.StatusBadRequest)
		logAudit("token_request", clientID, "token", r, false, "Redirect URI mismatch")
		return
	}

	// Validate code verifier with PKCE
	h := sha256.New()
	h.Write([]byte(codeVerifier))
	calculatedChallenge := base64.RawURLEncoding.EncodeToString(h.Sum(nil))

	if calculatedChallenge != authRequest.CodeChallenge {
		http.Error(w, "Invalid code verifier", http.StatusBadRequest)
		logAudit("token_request", clientID, "token", r, false, "Code verifier doesn't match challenge")
		return
	}

	// Check if code was already used
	if authRequest.Used {
		http.Error(w, "Code already used", http.StatusBadRequest)
		logAudit("token_request", clientID, "token", r, false, "Attempted reuse of authorization code")
		return
	}

	// Mark code as used
	_, err = db.Exec("UPDATE auth_requests SET used = true WHERE code = ?", code)
	if err != nil {
		http.Error(w, "Server error", http.StatusInternalServerError)
		logAudit("token_request", clientID, "token", r, false, fmt.Sprintf("Database error: %v", err))
		return
	}

	// Generate tokens
	accessToken, refreshToken, err := generateTokens(authRequest.UserID, clientID, authRequest.Scope)
	if err != nil {
		http.Error(w, "Server error", http.StatusInternalServerError)
		logAudit("token_request", clientID, "token", r, false, fmt.Sprintf("Error generating tokens: %v", err))
		return
	}

	// Create token response
	token := Token{
		AccessToken:  accessToken,
		RefreshToken: refreshToken,
		TokenType:    "Bearer",
		ExpiresIn:    3600,
		Scope:        authRequest.Scope,
		UserID:       authRequest.UserID,
		ClientID:     clientID,
		ExpiresAt:    time.Now().Add(time.Hour),
		Revoked:      false,
	}

	// Save token to database
	_, err = db.NamedExec(`
		INSERT INTO tokens (
			access_token, refresh_token, token_type, expires_in, 
			scope, user_id, client_id, expires_at, revoked
		) VALUES (
			:access_token, :refresh_token, :token_type, :expires_in,
			:scope, :user_id, :client_id, :expires_at, :revoked
		)`, token)

	if err != nil {
		http.Error(w, "Server error", http.StatusInternalServerError)
		logAudit("token_request", clientID, "token", r, false, fmt.Sprintf("Error saving token: %v", err))
		return
	}

	// Return token response
	w.Header().Set("Content-Type", "application/json")
	w.Header().Set("Cache-Control", "no-store")
	w.Header().Set("Pragma", "no-cache")

	err = json.NewEncoder(w).Encode(token)
	if err != nil {
		http.Error(w, "Server error", http.StatusInternalServerError)
		logAudit("token_request", clientID, "token", r, false, fmt.Sprintf("Error encoding response: %v", err))
		return
	}

	logAudit("token_request", clientID, "token", r, true, fmt.Sprintf("Tokens issued for user %s", authRequest.UserID))
}

func revokeHandler(w http.ResponseWriter, r *http.Request) {
	err := r.ParseForm()
	if err != nil {
		http.Error(w, "Invalid request", http.StatusBadRequest)
		logAudit("revoke_request", "anonymous", "token", r, false, "Error parsing form")
		return
	}

	token := r.Form.Get("token")
	tokenTypeHint := r.Form.Get("token_type_hint")
	clientID := r.Form.Get("client_id")

	if token == "" || clientID == "" {
		http.Error(w, "Invalid request parameters", http.StatusBadRequest)
		logAudit("revoke_request", clientID, "token", r, false, "Missing token or client_id")
		return
	}

	var tokenRecord Token
	var query string

	// Use token type hint to optimize the query if provided
	if tokenTypeHint == "access_token" {
		query = "SELECT * FROM tokens WHERE access_token = ? AND client_id = ?"
	} else if tokenTypeHint == "refresh_token" {
		query = "SELECT * FROM tokens WHERE refresh_token = ? AND client_id = ?"
	} else {
		// Try both if hint not provided or invalid
		query = "SELECT * FROM tokens WHERE (access_token = ? OR refresh_token = ?) AND client_id = ?"
		err = db.Get(&tokenRecord, query, token, token, clientID)
		if err != nil {
			// Token not found or invalid, but per OAuth 2.0 spec, still return success
			w.WriteHeader(http.StatusOK)
			logAudit("revoke_request", clientID, "token", r, false, "Token not found")
			return
		}
	}

	if tokenTypeHint == "access_token" || tokenTypeHint == "refresh_token" {
		err = db.Get(&tokenRecord, query, token, clientID)
		if err != nil {
			// Token not found or invalid, but per OAuth 2.0 spec, still return success
			w.WriteHeader(http.StatusOK)
			logAudit("revoke_request", clientID, "token", r, false, "Token not found")
			return
		}
	}

	// Revoke token
	_, err = db.Exec("UPDATE tokens SET revoked = true WHERE access_token = ? OR refresh_token = ?", 
		tokenRecord.AccessToken, tokenRecord.RefreshToken)

	if err != nil {
		http.Error(w, "Server error", http.StatusInternalServerError)
		logAudit("revoke_request", clientID, "token", r, false, fmt.Sprintf("Database error: %v", err))
		return
	}

	w.WriteHeader(http.StatusOK)
	logAudit("revoke_request", clientID, "token", r, true, "Token revoked successfully")
}

// Helper functions
func generateCode() (string, string, error) {
	// Generate code verifier
	verifierBytes := make([]byte, 32)
	_, err := rand.Read(verifierBytes)
	if err != nil {
		return "", "", err
	}
	codeVerifier := base64.RawURLEncoding.EncodeToString(verifierBytes)

	// Generate authorization code
	codeBytes := make([]byte, 32)
	_, err = rand.Read(codeBytes)
	if err != nil {
		return "", "", err
	}
	code := base64.RawURLEncoding.EncodeToString(codeBytes)

	return code, codeVerifier, nil
}

func generateTokens(userID, clientID, scope string) (string, string, error) {
	// Generate access token
	accessTokenClaims := jwt.MapClaims{
		"sub":   userID,
		"aud":   clientID,
		"scope": scope,
		"exp":   time.Now().Add(time.Hour).Unix(),
		"iat":   time.Now().Unix(),
		"jti":   generateRandomString(16),
	}

	accessToken := jwt.NewWithClaims(jwt.SigningMethodHS256, accessTokenClaims)
	accessTokenSigned, err := accessToken.SignedString(config.JWTSecret)
	if err != nil {
		return "", "", err
	}

	// Generate refresh token
	refreshTokenClaims := jwt.MapClaims{
		"sub":   userID,
		"aud":   clientID,
		"exp":   time.Now().Add(30 * 24 * time.Hour).Unix(),
		"iat":   time.Now().Unix(),
		"jti":   generateRandomString(16),
	}

	refreshToken := jwt.NewWithClaims(jwt.SigningMethodHS256, refreshTokenClaims)
	refreshTokenSigned, err := refreshToken.SignedString(config.JWTSecret)
	if err != nil {
		return "", "", err
	}

	return accessTokenSigned, refreshTokenSigned, nil
}

func generateRandomString(length int) string {
	b := make([]byte, length)
	_, err := rand.Read(b)
	if err != nil {
		return ""
	}
	return base64.RawURLEncoding.EncodeToString(b)
}

func getClientIP(r *http.Request) string {
	forwardedFor := r.Header.Get("X-Forwarded-For")
	if forwardedFor != "" {
		return strings.Split(forwardedFor, ",")[0]
	}
	return r.RemoteAddr
}

func logAudit(action, actor, resource string, r *http.Request, success bool, details string) {
	auditLog := AuditLog{
		Action:    action,
		Actor:     actor,
		Resource:  resource,
		Timestamp: time.Now(),
		IP:        getClientIP(r),
		UserAgent: r.UserAgent(),
		Success:   success,
		Details:   details,
	}

	_, err := db.NamedExec(`
		INSERT INTO audit_logs (
			action, actor, resource, timestamp, ip, user_agent, success, details
		) VALUES (
			:action, :actor, :resource, :timestamp, :ip, :user_agent, :success, :details
		)`, auditLog)

	if err != nil {
		log.Printf("Failed to log audit: %v", err)
	}
}
