#include <algorithm>
#include <chrono>
#include <condition_variable>
#include <fstream>
#include <iostream>
#include <mutex>
#include <queue>
#include <string>
#include <thread>
#include <vector>
#include <filesystem>

constexpr size_t CHUNK_SIZE = 1 * 1024 * 1024 * 1024LL; // 1 GB chunks
constexpr size_t BUFFER_SIZE = 64 * 1024 * 1024;        // 64 MB buffer
constexpr size_t MAX_OPEN_FILES = 32;                   // Max files to merge at once

// Simple integer value for demonstration
struct Record {
    int64_t key;
    char padding[120]; // Make it larger to simulate real-world records (128 bytes total)

    bool operator<(const Record& other) const {
        return key < other.key;
    }
};

class ExternalMergeSort {
private:
    std::string inputFile;
    std::string outputFile;
    std::string tempDir;
    unsigned int numThreads;

    struct ChunkFile {
        std::string filename;
        std::ifstream stream;
        Record current;
        bool valid = false;

        bool operator>(const ChunkFile& other) const {
            return current.key > other.key;
        }
    };

    std::mutex mutex;
    std::condition_variable cv;
    int activeThreads = 0;

    std::vector<std::string> tempFiles;

    // Benchmark data
    std::chrono::duration<double> sortTime;
    std::chrono::duration<double> mergeTime;
    std::chrono::duration<double> ioWaitTime;

public:
    ExternalMergeSort(const std::string& input, const std::string& output, 
                     const std::string& temp, unsigned int threads)
        : inputFile(input), outputFile(output), tempDir(temp), numThreads(threads) {
        std::filesystem::create_directories(tempDir);
    }

    ~ExternalMergeSort() {
        // Clean up temp files
        for (const auto& file : tempFiles) {
            std::filesystem::remove(file);
        }
    }

    void sort() {
        auto startTime = std::chrono::high_resolution_clock::now();

        // Step 1: Split the file into sorted chunks
        splitAndSortChunks();

        auto splitEndTime = std::chrono::high_resolution_clock::now();
        sortTime = splitEndTime - startTime;

        // Step 2: Merge the sorted chunks
        mergeSortedChunks();

        auto endTime = std::chrono::high_resolution_clock::now();
        mergeTime = endTime - splitEndTime;

        reportBenchmarks();
    }

private:
    void splitAndSortChunks() {
        std::ifstream input(inputFile, std::ios::binary);
        input.rdbuf()->pubsetbuf(new char[BUFFER_SIZE], BUFFER_SIZE);

        if (!input) {
            throw std::runtime_error("Could not open input file: " + inputFile);
        }

        size_t chunkId = 0;
        std::vector<std::thread> threads;

        while (input) {
            std::vector<Record> records;
            records.reserve(CHUNK_SIZE / sizeof(Record));

            auto ioStartTime = std::chrono::high_resolution_clock::now();

            // Read a chunk of data
            for (size_t i = 0; i < CHUNK_SIZE / sizeof(Record) && input; ++i) {
                Record record;
                if (input.read(reinterpret_cast<char*>(&record), sizeof(Record))) {
                    records.push_back(record);
                }
            }

            auto ioEndTime = std::chrono::high_resolution_clock::now();
            ioWaitTime += ioEndTime - ioStartTime;

            if (records.empty()) break;

            // Wait if all threads are busy
            std::unique_lock<std::mutex> lock(mutex);
            cv.wait(lock, [this] { return activeThreads < numThreads; });
            activeThreads++;
            lock.unlock();

            // Create a temp file name
            std::string tempFile = tempDir + "/chunk_" + std::to_string(chunkId++) + ".tmp";
            tempFiles.push_back(tempFile);

            // Sort the chunk in a new thread
            threads.emplace_back([this, records, tempFile]() mutable {
                // Sort the records in memory
                std::sort(records.begin(), records.end());

                // Write sorted chunk to disk
                auto ioStartTime = std::chrono::high_resolution_clock::now();

                std::ofstream output(tempFile, std::ios::binary);
                output.rdbuf()->pubsetbuf(new char[BUFFER_SIZE], BUFFER_SIZE);
                output.write(reinterpret_cast<const char*>(records.data()), 
                           records.size() * sizeof(Record));
                output.close();

                auto ioEndTime = std::chrono::high_resolution_clock::now();

                std::lock_guard<std::mutex> lock(mutex);
                ioWaitTime += ioEndTime - ioStartTime;
                activeThreads--;
                cv.notify_one();
            });
        }

        // Wait for all threads to finish
        for (auto& thread : threads) {
            if (thread.joinable()) {
                thread.join();
            }
        }

        input.close();
    }

    void mergeSortedChunks() {
        // If we have a lot of chunks, we need to do multi-level merging
        std::vector<std::string> currentLevel = tempFiles;
        std::vector<std::string> nextLevel;

        size_t mergeId = 0;

        while (currentLevel.size() > 1) {
            nextLevel.clear();

            for (size_t i = 0; i < currentLevel.size(); i += MAX_OPEN_FILES) {
                // Take up to MAX_OPEN_FILES from the current level
                size_t end = std::min(i + MAX_OPEN_FILES, currentLevel.size());
                std::vector<std::string> filesToMerge(currentLevel.begin() + i, 
                                                     currentLevel.begin() + end);

                // Create a temp file for the merged output
                std::string mergedFile = tempDir + "/merged_" + std::to_string(mergeId++) + ".tmp";
                nextLevel.push_back(mergedFile);

                // Merge these files
                mergeFiles(filesToMerge, mergedFile);
            }

            // Next iteration will merge the files we just created
            currentLevel = nextLevel;
        }

        // Rename the final merge file to the output file
        if (!currentLevel.empty()) {
            std::filesystem::rename(currentLevel[0], outputFile);
        }
    }

    void mergeFiles(const std::vector<std::string>& files, const std::string& outputFile) {
        std::vector<ChunkFile> chunkFiles(files.size());

        // Open all input files and read first record from each
        auto ioStartTime = std::chrono::high_resolution_clock::now();

        for (size_t i = 0; i < files.size(); ++i) {
            chunkFiles[i].filename = files[i];
            chunkFiles[i].stream.open(files[i], std::ios::binary);
            chunkFiles[i].stream.rdbuf()->pubsetbuf(new char[BUFFER_SIZE / files.size()], 
                                                  BUFFER_SIZE / files.size());

            if (chunkFiles[i].stream.read(reinterpret_cast<char*>(&chunkFiles[i].current), 
                                        sizeof(Record))) {
                chunkFiles[i].valid = true;
            }
        }

        // Set up priority queue for merging
        std::priority_queue<std::reference_wrapper<ChunkFile>, 
                          std::vector<std::reference_wrapper<ChunkFile>>, 
                          std::greater<std::reference_wrapper<ChunkFile>>> pq;

        for (auto& cf : chunkFiles) {
            if (cf.valid) {
                pq.push(std::ref(cf));
            }
        }

        // Open output file
        std::ofstream output(outputFile, std::ios::binary);
        output.rdbuf()->pubsetbuf(new char[BUFFER_SIZE], BUFFER_SIZE);

        auto ioEndTime = std::chrono::high_resolution_clock::now();
        ioWaitTime += ioEndTime - ioStartTime;

        // Merge
        while (!pq.empty()) {
            ChunkFile& current = pq.top();

            // Write the current smallest record to output
            output.write(reinterpret_cast<const char*>(&current.current), sizeof(Record));

            pq.pop();

            // Read the next record from the file
            if (current.stream.read(reinterpret_cast<char*>(&current.current), sizeof(Record))) {
                pq.push(std::ref(current));
            }
        }

        // Close files
        output.close();
        for (auto& cf : chunkFiles) {
            cf.stream.close();
        }
    }

    void reportBenchmarks() {
        std::cout << "Benchmark Results:" << std::endl;
        std::cout << "Sort Phase Time: " << sortTime.count() << " seconds" << std::endl;
        std::cout << "Merge Phase Time: " << mergeTime.count() << " seconds" << std::endl;
        std::cout << "Total I/O Wait Time: " << ioWaitTime.count() << " seconds" << std::endl;
        std::cout << "Total Time: " << (sortTime + mergeTime).count() << " seconds" << std::endl;

        size_t inputSize = std::filesystem::file_size(outputFile);
        double throughput = inputSize / (1024.0 * 1024.0 * 1024.0) / (sortTime + mergeTime).count();
        std::cout << "Throughput: " << throughput << " GB/s" << std::endl;

        double ioPercentage = ioWaitTime.count() / (sortTime + mergeTime).count() * 100.0;
        std::cout << "I/O Wait Time: " << ioPercentage << "% of total time" << std::endl;
    }
};

int main(int argc, char** argv) {
    if (argc < 4) {
        std::cerr << "Usage: " << argv[0] << " <input_file> <output_file> <temp_dir> [num_threads]" << std::endl;
        return 1;
    }

    std::string inputFile = argv[1];
    std::string outputFile = argv[2];
    std::string tempDir = argv[3];
    unsigned int numThreads = (argc > 4) ? std::stoi(argv[4]) : std::thread::hardware_concurrency();

    try {
        ExternalMergeSort sorter(inputFile, outputFile, tempDir, numThreads);
        sorter.sort();
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
        return 1;
    }

    return 0;
}
```

```cpp:generate_test_data.cpp
#include <fstream>
#include <iostream>
#include <random>
#include <chrono>
#include <cstdint>

struct Record {
    int64_t key;
    char padding[120]; // Make it 128 bytes total
};

int main(int argc, char** argv) {
    if (argc < 3) {
        std::cerr << "Usage: " << argv[0] << " <output_file> <size_in_gb>" << std::endl;
        return 1;
    }

    std::string outputFile = argv[1];
    double sizeInGB = std::stod(argv[2]);

    size_t numRecords = static_cast<size_t>(sizeInGB * 1024 * 1024 * 1024 / sizeof(Record));

    std::mt19937_64 rng(std::chrono::system_clock::now().time_since_epoch().count());
    std::uniform_int_distribution<int64_t> dist;

    std::ofstream output(outputFile, std::ios::binary);
    if (!output) {
        std::cerr << "Failed to open output file: " << outputFile << std::endl;
        return 1;
    }

    // Use a buffer for writing
    char* buffer = new char[64 * 1024 * 1024]; // 64 MB buffer
    output.rdbuf()->pubsetbuf(buffer, 64 * 1024 * 1024);

    std::cout << "Generating " << numRecords << " records (" << sizeInGB << " GB)..." << std::endl;

    auto startTime = std::chrono::high_resolution_clock::now();

    for (size_t i = 0; i < numRecords; ++i) {
        Record record;
        record.key = dist(rng);

        // Zero out the padding
        std::memset(record.padding, 0, sizeof(record.padding));

        output.write(reinterpret_cast<const char*>(&record), sizeof(Record));

        if (i % (numRecords / 100) == 0) {
            double progress = static_cast<double>(i) / numRecords * 100.0;
            std::cout << "\rProgress: " << progress << "%" << std::flush;
        }
    }

    output.close();
    delete[] buffer;

    auto endTime = std::chrono::high_resolution_clock::now();
    std::chrono::duration<double> elapsed = endTime - startTime;

    std::cout << "\nGenerated " << sizeInGB << " GB in " << elapsed.count() << " seconds" << std::endl;
    std::cout << "Throughput: " << (sizeInGB / elapsed.count()) << " GB/s" << std::endl;

    return 0;
}
