from abc import ABC, abstractmethod
import heapq
from typing import Dict, List, Tuple, TypeVar, Generic, Set, Callable, Optional, Any

T = TypeVar('T')

class Graph(Generic[T]):
    def __init__(self):
        self.adjacency_list = {}

    def add_node(self, node: T) -> None:
        if node not in self.adjacency_list:
            self.adjacency_list[node] = []

    def add_edge(self, source: T, target: T, weight: float) -> None:
        self.add_node(source)
        self.add_node(target)
        self.adjacency_list[source].append((target, weight))

    def get_neighbors(self, node: T) -> List[Tuple[T, float]]:
        return self.adjacency_list.get(node, [])

    def get_nodes(self) -> List[T]:
        return list(self.adjacency_list.keys())


class SearchAlgorithm(ABC, Generic[T]):
    @abstractmethod
    def name(self) -> str:
        pass

    @abstractmethod
    def find_path(self, graph: Graph[T], start: T, goal: T, 
                 heuristic: Optional[Callable[[T, T], float]] = None) -> Tuple[List[T], float]:
        pass


class SearchRegistry:
    _algorithms = {}

    @classmethod
    def register(cls, algorithm_class):
        instance = algorithm_class()
        cls._algorithms[instance.name()] = algorithm_class
        return algorithm_class

    @classmethod
    def get_algorithm(cls, name: str) -> SearchAlgorithm:
        if name not in cls._algorithms:
            raise ValueError(f"Algorithm '{name}' not found")
        return cls._algorithms[name]()

    @classmethod
    def list_algorithms(cls) -> List[str]:
        return list(cls._algorithms.keys())
