from ..core import SearchAlgorithm, Graph, SearchRegistry
from typing import List, Tuple, TypeVar, Optional, Callable
import heapq

T = TypeVar('T')

@SearchRegistry.register
class Dijkstra(SearchAlgorithm[T]):
    def name(self) -> str:
        return "dijkstra"

    def find_path(self, graph: Graph[T], start: T, goal: T, 
                 heuristic: Optional[Callable[[T, T], float]] = None) -> Tuple[List[T], float]:
        open_set = [(0, start)]
        closed_set = set()
        costs = {start: 0}
        came_from = {}

        while open_set:
            current_cost, current = heapq.heappop(open_set)

            if current == goal:
                path = []
                while current in came_from:
                    path.append(current)
                    current = came_from[current]
                path.append(start)
                path.reverse()
                return path, current_cost

            if current in closed_set:
                continue

            closed_set.add(current)

            for neighbor, weight in graph.get_neighbors(current):
                if neighbor in closed_set:
                    continue

                tentative_cost = costs[current] + weight

                if neighbor not in costs or tentative_cost < costs[neighbor]:
                    costs[neighbor] = tentative_cost
                    came_from[neighbor] = current
                    heapq.heappush(open_set, (tentative_cost, neighbor))

        return [], float('inf')  # No path found
