from ..core import SearchAlgorithm, Graph, SearchRegistry
from typing import List, Tuple, TypeVar, Optional, Callable
import heapq

T = TypeVar('T')

@SearchRegistry.register
class AStar(SearchAlgorithm[T]):
    def name(self) -> str:
        return "a_star"

    def find_path(self, graph: Graph[T], start: T, goal: T, 
                 heuristic: Optional[Callable[[T, T], float]] = None) -> Tuple[List[T], float]:
        if heuristic is None:
            raise ValueError("A* algorithm requires a heuristic function")

        open_set = [(0, start)]
        closed_set = set()
        g_score = {start: 0}
        f_score = {start: heuristic(start, goal)}
        came_from = {}

        while open_set:
            _, current = heapq.heappop(open_set)

            if current == goal:
                path = []
                while current in came_from:
                    path.append(current)
                    current = came_from[current]
                path.append(start)
                path.reverse()
                return path, g_score[goal]

            if current in closed_set:
                continue

            closed_set.add(current)

            for neighbor, weight in graph.get_neighbors(current):
                if neighbor in closed_set:
                    continue

                tentative_g_score = g_score[current] + weight

                if neighbor not in g_score or tentative_g_score < g_score[neighbor]:
                    came_from[neighbor] = current
                    g_score[neighbor] = tentative_g_score
                    f_score[neighbor] = g_score[neighbor] + heuristic(neighbor, goal)
                    heapq.heappush(open_set, (f_score[neighbor], neighbor))

        return [], float('inf')  # No path found
