from ..core import SearchAlgorithm, Graph, SearchRegistry
from typing import List, Tuple, TypeVar, Dict, Optional, Callable

T = TypeVar('T')

@SearchRegistry.register
class BellmanFord(SearchAlgorithm[T]):
    def name(self) -> str:
        return "bellman_ford"

    def find_path(self, graph: Graph[T], start: T, goal: T, 
                 heuristic: Optional[Callable[[T, T], float]] = None) -> Tuple[List[T], float]:
        nodes = graph.get_nodes()
        distances = {node: float('inf') for node in nodes}
        distances[start] = 0
        predecessors = {node: None for node in nodes}

        # Relax edges |V|-1 times
        for _ in range(len(nodes) - 1):
            for node in nodes:
                for neighbor, weight in graph.get_neighbors(node):
                    if distances[node] + weight < distances[neighbor]:
                        distances[neighbor] = distances[node] + weight
                        predecessors[neighbor] = node

        # Check for negative-weight cycles
        for node in nodes:
            for neighbor, weight in graph.get_neighbors(node):
                if distances[node] + weight < distances[neighbor]:
                    raise ValueError("Graph contains a negative-weight cycle")

        # Build path
        if distances[goal] == float('inf'):
            return [], float('inf')  # No path found

        path = []
        current = goal
        while current:
            path.append(current)
            current = predecessors[current]

        path.reverse()
        return path, distances[goal]
