import java.io.*;
import java.nio.charset.StandardCharsets;
import java.nio.file.*;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.*;
import java.util.concurrent.*;
import java.util.logging.*;
import java.util.regex.*;

public class PIIDetector {
    private static final Logger LOGGER = Logger.getLogger(PIIDetector.class.getName());
    private static final int MAX_REGEX_TIME_MS = 500;
    private static final int N_GRAM_SIZE = 3;
    private static final double CONFIDENCE_THRESHOLD = 0.7;

    // Patterns with reasonable limits to avoid ReDoS
    private static final Map<String, Pattern> PII_PATTERNS = new HashMap<>();
    static {
        // Limit repetitions and use atomic groups where possible
        PII_PATTERNS.put("EMAIL", Pattern.compile("(?i)[a-z0-9._%+-]{1,64}@[a-z0-9.-]{1,255}\\.[a-z]{2,}"));
        PII_PATTERNS.put("SSN", Pattern.compile("\\b(?:\\d{3}-\\d{2}-\\d{4}|\\d{9})\\b"));
        PII_PATTERNS.put("PHONE", Pattern.compile("\\b(?:\\+?\\d{1,3}[-.\\s]?)?(?:\\(\\d{1,4}\\)[-.\\s]?)?\\d{1,4}[-.\\s]?\\d{1,4}[-.\\s]?\\d{1,9}\\b"));
        PII_PATTERNS.put("CC", Pattern.compile("\\b(?:4[0-9]{12}(?:[0-9]{3})?|5[1-5][0-9]{14}|3[47][0-9]{13}|3(?:0[0-5]|[68][0-9])[0-9]{11}|6(?:011|5[0-9]{2})[0-9]{12}|(?:2131|1800|35\\d{3})\\d{11})\\b"));
        PII_PATTERNS.put("IP", Pattern.compile("\\b(?:(?:25[0-5]|2[0-4][0-9]|[01]?[0-9][0-9]?)\\.){3}(?:25[0-5]|2[0-4][0-9]|[01]?[0-9][0-9]?)\\b"));
    }

    private final Map<String, Set<String>> nGramDictionary = new ConcurrentHashMap<>();
    private final ExecutorService executor = Executors.newFixedThreadPool(
            Runtime.getRuntime().availableProcessors());

    public PIIDetector() {
        setupLogger();
        loadNGramDictionary();
    }

    private void setupLogger() {
        try {
            FileHandler fileHandler = new FileHandler("pii_detection.log", true);
            fileHandler.setFormatter(new SimpleFormatter());
            LOGGER.addHandler(fileHandler);
            LOGGER.setLevel(Level.INFO);
        } catch (IOException e) {
            System.err.println("Failed to setup logger: " + e.getMessage());
        }
    }

    private void loadNGramDictionary() {
        // In a real implementation, load dictionaries for different PII types
        // This is a simplified example
        nGramDictionary.put("NAME", new HashSet<>());
        nGramDictionary.put("ADDRESS", new HashSet<>());
        // Load actual n-grams from files or databases
    }

    public String maskText(String text) {
        if (text == null || text.isEmpty()) {
            return text;
        }

        String maskedText = text;
        Map<String, List<DetectionResult>> allDetections = new HashMap<>();

        // Regex-based detection with timeout protection
        for (Map.Entry<String, Pattern> entry : PII_PATTERNS.entrySet()) {
            String piiType = entry.getKey();
            Pattern pattern = entry.getValue();

            List<DetectionResult> detections = detectWithTimeout(text, piiType, pattern);
            if (!detections.isEmpty()) {
                allDetections.put(piiType, detections);
            }
        }

        // N-gram based detection
        Map<String, List<DetectionResult>> nGramDetections = detectWithNGrams(text);
        for (Map.Entry<String, List<DetectionResult>> entry : nGramDetections.entrySet()) {
            allDetections.computeIfAbsent(entry.getKey(), k -> new ArrayList<>())
                         .addAll(entry.getValue());
        }

        // Sort all detections by starting position in descending order to mask from end to start
        List<DetectionResult> sortedDetections = new ArrayList<>();
        for (List<DetectionResult> detections : allDetections.values()) {
            sortedDetections.addAll(detections);
        }
        sortedDetections.sort((a, b) -> Integer.compare(b.start, a.start));

        // Apply masking
        StringBuilder sb = new StringBuilder(maskedText);
        for (DetectionResult result : sortedDetections) {
            if (result.confidence >= CONFIDENCE_THRESHOLD) {
                String hash = hashPII(maskedText.substring(result.start, result.end));
                sb.replace(result.start, result.end, "[" + result.type + "_MASKED:" + hash + "]");

                // Log the detection securely
                LOGGER.info(String.format("PII detected: type=%s, confidence=%.2f, hash=%s", 
                                         result.type, result.confidence, hash));
            }
        }

        return sb.toString();
    }

    private List<DetectionResult> detectWithTimeout(String text, String piiType, Pattern pattern) {
        List<DetectionResult> results = new ArrayList<>();

        Future<List<DetectionResult>> future = executor.submit(() -> {
            List<DetectionResult> detections = new ArrayList<>();
            Matcher matcher = pattern.matcher(text);

            while (matcher.find()) {
                String match = matcher.group();
                // Calculate confidence based on match characteristics
                double confidence = calculateConfidence(match, piiType);

                detections.add(new DetectionResult(
                    piiType, 
                    matcher.start(), 
                    matcher.end(), 
                    confidence
                ));
            }
            return detections;
        });

        try {
            results = future.get(MAX_REGEX_TIME_MS, TimeUnit.MILLISECONDS);
        } catch (TimeoutException e) {
            future.cancel(true);
            LOGGER.warning("Regex timeout for pattern: " + piiType);
        } catch (Exception e) {
            LOGGER.severe("Error in regex detection: " + e.getMessage());
        }

        return results;
    }

    private Map<String, List<DetectionResult>> detectWithNGrams(String text) {
        Map<String, List<DetectionResult>> results = new HashMap<>();
        String[] words = text.split("\\s+");

        for (int i = 0; i < words.length; i++) {
            String word = words[i];

            // Skip very short words
            if (word.length() < 3) continue;

            // Generate n-grams for the word
            Set<String> wordNGrams = generateNGrams(word);

            // Check each PII dictionary
            for (Map.Entry<String, Set<String>> entry : nGramDictionary.entrySet()) {
                String piiType = entry.getKey();
                Set<String> dictionary = entry.getValue();

                // Calculate n-gram match ratio
                int matchCount = 0;
                for (String ngram : wordNGrams) {
                    if (dictionary.contains(ngram)) {
                        matchCount++;
                    }
                }

                if (wordNGrams.size() > 0) {
                    double matchRatio = (double) matchCount / wordNGrams.size();

                    if (matchRatio > 0.5) {  // Threshold for n-gram matching
                        // Find word position in original text
                        int pos = 0;
                        for (int j = 0; j < i; j++) {
                            pos += words[j].length() + 1;  // +1 for the space
                        }

                        DetectionResult result = new DetectionResult(
                            piiType,
                            pos,
                            pos + word.length(),
                            matchRatio
                        );

                        results.computeIfAbsent(piiType, k -> new ArrayList<>()).add(result);
                    }
                }
            }
        }

        return results;
    }

    private Set<String> generateNGrams(String word) {
        Set<String> ngrams = new HashSet<>();
        word = word.toLowerCase();

        for (int i = 0; i <= word.length() - N_GRAM_SIZE; i++) {
            ngrams.add(word.substring(i, i + N_GRAM_SIZE));
        }

        return ngrams;
    }

    private double calculateConfidence(String match, String piiType) {
        // Base confidence starts high for regex matches
        double confidence = 0.8;

        // Adjust based on various heuristics
        switch (piiType) {
            case "EMAIL":
                // Check domain validity, presence of TLD
                confidence += match.matches(".*@(gmail|yahoo|hotmail|outlook).*") ? 0.1 : 0;
                confidence -= match.length() < 10 ? 0.2 : 0;
                break;

            case "SSN":
                // Valid SSN characteristics
                confidence += match.contains("-") ? 0.05 : 0;
                confidence -= match.equals("123456789") ? 0.5 : 0; // Common fake
                break;

            case "PHONE":
                // Phone patterns validation
                confidence += match.contains("(") && match.contains(")") ? 0.05 : 0;
                confidence -= match.replaceAll("[^0-9]", "").length() < 7 ? 0.3 : 0;
                break;

            case "CC":
                // Apply Luhn algorithm for credit cards
                confidence += validateLuhnAlgorithm(match.replaceAll("[^0-9]", "")) ? 0.15 : -0.4;
                break;

            case "IP":
                // Check for private IPs which might be less sensitive
                confidence -= match.startsWith("192.168.") || match.startsWith("10.") ? 0.1 : 0;
                break;
        }

        // Bound confidence between 0 and 1
        return Math.max(0, Math.min(1, confidence));
    }

    private boolean validateLuhnAlgorithm(String digits) {
        if (digits.length() < 13 || digits.length() > 19) return false;

        int sum = 0;
        boolean alternate = false;

        for (int i = digits.length() - 1; i >= 0; i--) {
            int n = Integer.parseInt(digits.substring(i, i + 1));
            if (alternate) {
                n *= 2;
                if (n > 9) {
                    n = (n % 10) + 1;
                }
            }
            sum += n;
            alternate = !alternate;
        }

        return (sum % 10 == 0);
    }

    private String hashPII(String pii) {
        try {
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            byte[] hash = digest.digest(pii.getBytes(StandardCharsets.UTF_8));
            StringBuilder hexString = new StringBuilder();

            for (byte b : hash) {
                String hex = Integer.toHexString(0xff & b);
                if (hex.length() == 1) hexString.append('0');
                hexString.append(hex);
            }

            return hexString.toString().substring(0, 8); // Return first 8 chars of hash
        } catch (NoSuchAlgorithmException e) {
            LOGGER.severe("Hashing algorithm not available: " + e.getMessage());
            return "********";
        }
    }

    public void processFile(String inputPath, String outputPath) throws IOException {
        try {
            List<String> lines = Files.readAllLines(Paths.get(inputPath));
            List<String> maskedLines = new ArrayList<>();

            for (String line : lines) {
                maskedLines.add(maskText(line));
            }

            Files.write(Paths.get(outputPath), maskedLines);
            LOGGER.info("Processed file: " + inputPath + " -> " + outputPath);
        } catch (IOException e) {
            LOGGER.severe("Error processing file: " + e.getMessage());
            throw e;
        }
    }

    public void shutdown() {
        executor.shutdown();
        try {
            if (!executor.awaitTermination(5, TimeUnit.SECONDS)) {
                executor.shutdownNow();
            }
        } catch (InterruptedException e) {
            executor.shutdownNow();
            Thread.currentThread().interrupt();
        }
    }

    private static class DetectionResult {
        final String type;
        final int start;
        final int end;
        final double confidence;

        DetectionResult(String type, int start, int end, double confidence) {
            this.type = type;
            this.start = start;
            this.end = end;
            this.confidence = confidence;
        }
    }

    public static void main(String[] args) {
        if (args.length != 2) {
            System.out.println("Usage: java PIIDetector <input_file> <output_file>");
            return;
        }

        PIIDetector detector = new PIIDetector();
        try {
            detector.processFile(args[0], args[1]);
        } catch (IOException e) {
            System.err.println("Error: " + e.getMessage());
        } finally {
            detector.shutdown();
        }
    }
}
