/// Represents a knapsack problem configuration
pub struct Problem<T> {
    pub items: Vec<T>,
    pub capacity: usize,
}

impl<T: Item> Problem<T> {
    pub fn new(items: Vec<T>, capacity: usize) -> Self {
        Self { items, capacity }
    }

    pub fn solve<S: Solver<T>>(&self, solver: S) -> Solution<T> {
        solver.solve(self)
    }
}

/// Represents a solution to a knapsack problem
pub struct Solution<T> {
    pub items: Vec<T>,
    pub total_value: usize,
    pub total_weight: usize,
}

impl<T: Item> Solution<T> {
    pub fn new(items: Vec<T>) -> Self {
        let total_value = items.iter().map(|item| item.value()).sum();
        let total_weight = items.iter().map(|item| item.weight()).sum();
        Self { items, total_value, total_weight }
    }

    pub fn empty() -> Self {
        Self { items: Vec::new(), total_value: 0, total_weight: 0 }
    }
}
