```rust:src/solvers/dynamic_programming.rs
use crate::{Item, Problem, Solution, solvers::Solver};

pub struct DynamicProgramming;

impl<T: Item> Solver<T> for DynamicProgramming {
    fn solve(&self, problem: &Problem<T>) -> Solution<T> {
        if problem.items.is_empty() || problem.capacity == 0 {
            return Solution::empty();
        }

        let n = problem.items.len();
        let capacity = problem.capacity;

        // Create the DP table
        let mut dp = vec![vec![0; capacity + 1]; n + 1];

        // Fill the DP table
        for i in 1..=n {
            let item = &problem.items[i - 1];
            for w in 0..=capacity {
                if item.weight() <= w {
                    dp[i][w] = std::cmp::max(
                        dp[i-1][w],
                        dp[i-1][w - item.weight()] + item.value()
                    );
                } else {
                    dp[i][w] = dp[i-1][w];
                }
            }
        }

        // Reconstruct the solution
        let mut selected_items = Vec::new();
        let mut w = capacity;
        for i in (1..=n).rev() {
            if dp[i][w] != dp[i-1][w] {
                selected_items.push(problem.items[i-1].clone());
                w -= problem.items[i-1].weight();
            }
        }

        Solution::new(selected_items)
    }
}
