use crate::{Item, Problem, Solution, solvers::Solver};
use std::cmp;
use std::collections::BinaryHeap;
use std::cmp::Ordering;

pub struct BranchAndBound;

#[derive(Clone, Debug)]
struct Node<T: Item> {
    level: usize,
    value: usize,
    weight: usize,
    bound: f64,
    items: Vec<T>,
}

impl<T: Item> PartialEq for Node<T> {
    fn eq(&self, other: &Self) -> bool {
        self.bound == other.bound
    }
}

impl<T: Item> Eq for Node<T> {}

impl<T: Item> PartialOrd for Node<T> {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        other.bound.partial_cmp(&self.bound)
    }
}

impl<T: Item> Ord for Node<T> {
    fn cmp(&self, other: &Self) -> Ordering {
        other.bound.partial_cmp(&self.bound).unwrap_or(Ordering::Equal)
    }
}

impl<T: Item> Solver<T> for BranchAndBound {
    fn solve(&self, problem: &Problem<T>) -> Solution<T> {
        if problem.items.is_empty() || problem.capacity == 0 {
            return Solution::empty();
        }

        // Sort items by value density
        let mut sorted_items = problem.items.clone();
        sorted_items.sort_by(|a, b| b.value_density().partial_cmp(&a.value_density()).unwrap());

        let mut queue = BinaryHeap::new();
        let mut best_solution = Node {
            level: 0,
            value: 0,
            weight: 0,
            bound: 0.0,
            items: Vec::new(),
        };

        // Root node
        let mut root = Node {
            level: 0,
            value: 0,
            weight: 0,
            bound: 0.0,
            items: Vec::new(),
        };
        root.bound = self.compute_bound(&root, problem.capacity, &sorted_items);
        queue.push(root);

        // Branch and bound
        while let Some(node) = queue.pop() {
            if node.bound < best_solution.value as f64 {
                continue;
            }

            if node.level == problem.items.len() {
                if node.value > best_solution.value {
                    best_solution = node;
                }
                continue;
            }

            // Include current item
            let current_item = &sorted_items[node.level];
            if node.weight + current_item.weight() <= problem.capacity {
                let mut new_items = node.items.clone();
                new_items.push(current_item.clone());

                let mut new_node = Node {
                    level: node.level + 1,
                    value: node.value + current_item.value(),
                    weight: node.weight + current_item.weight(),
                    bound: 0.0,
                    items: new_items,
                };
                new_node.bound = self.compute_bound(&new_node, problem.capacity, &sorted_items);

                if new_node.bound > best_solution.value as f64 {
                    queue.push(new_node);
                }

                if new_node.value > best_solution.value {
                    best_solution = new_node.clone();
                }
            }

            // Exclude current item
            let mut exclude_node = Node {
                level: node.level + 1,
                value: node.value,
                weight: node.weight,
                bound: 0.0,
                items: node.items.clone(),
            };
            exclude_node.bound = self.compute_bound(&exclude_node, problem.capacity, &sorted_items);

            if exclude_node.bound > best_solution.value as f64 {
                queue.push(exclude_node);
            }
        }

        Solution::new(best_solution.items)
    }
}

impl BranchAndBound {
    fn compute_bound<T: Item>(&self, node: &Node<T>, capacity: usize, items: &[T]) -> f64 {
        if node.weight >= capacity {
            return 0.0;
        }

        let mut bound = node.value as f64;
        let mut weight = node.weight;
        let mut level = node.level;

        while level < items.len() && weight + items[level].weight() <= capacity {
            weight += items[level].weight();
            bound += items[level].value() as f64;
            level += 1;
        }

        if level < items.len() {
            bound += (capacity - weight) as f64 * items[level].value_density();
        }

        bound
    }
}
