use crate::{Item, Problem, Solution, solvers::Solver};

pub struct Greedy;

impl<T: Item> Solver<T> for Greedy {
    fn solve(&self, problem: &Problem<T>) -> Solution<T> {
        if problem.items.is_empty() || problem.capacity == 0 {
            return Solution::empty();
        }

        // Sort items by value density
        let mut items = problem.items.clone();
        items.sort_by(|a, b| b.value_density().partial_cmp(&a.value_density()).unwrap());

        let mut selected_items = Vec::new();
        let mut remaining_capacity = problem.capacity;

        for item in items {
            if item.weight() <= remaining_capacity {
                selected_items.push(item.clone());
                remaining_capacity -= item.weight();
            }

            if remaining_capacity == 0 {
                break;
            }
        }

        Solution::new(selected_items)
    }
}
