use knapsack::{Problem, Item, Solution, DynamicProgramming, BranchAndBound, Greedy, SimpleItem, Solver};
use proptest::prelude::*;

proptest! {
    // Test that all solvers respect capacity constraints
    #[test]
    fn all_solvers_respect_capacity(items in vec_of_items(5..20), capacity in 10..100usize) {
        let problem = Problem::new(items, capacity);

        let dp_solution = problem.solve(DynamicProgramming);
        let bb_solution = problem.solve(BranchAndBound);
        let greedy_solution = problem.solve(Greedy);

        assert!(dp_solution.total_weight <= capacity, "DP solution exceeds capacity");
        assert!(bb_solution.total_weight <= capacity, "Branch and Bound solution exceeds capacity");
        assert!(greedy_solution.total_weight <= capacity, "Greedy solution exceeds capacity");
    }

    // Test edge case: empty items
    #[test]
    fn empty_items_gives_empty_solution(capacity in 0..100usize) {
        let problem = Problem::<SimpleItem>::new(vec![], capacity);

        let dp_solution = problem.solve(DynamicProgramming);
        let bb_solution = problem.solve(BranchAndBound);
        let greedy_solution = problem.solve(Greedy);

        assert_eq!(dp_solution.items.len(), 0);
        assert_eq!(bb_solution.items.len(), 0);
        assert_eq!(greedy_solution.items.len(), 0);
    }

    // Test edge case: zero capacity
    #[test]
    fn zero_capacity_gives_empty_solution(items in vec_of_items(1..20)) {
        let problem = Problem::new(items, 0);

        let dp_solution = problem.solve(DynamicProgramming);
        let bb_solution = problem.solve(BranchAndBound);
        let greedy_solution = problem.solve(Greedy);

        assert_eq!(dp_solution.items.len(), 0);
        assert_eq!(bb_solution.items.len(), 0);
        assert_eq!(greedy_solution.items.len(), 0);
    }

    // Test that DP and B&B give optimal (and identical) solutions
    #[test]
    fn dp_and_bb_are_optimal_and_identical(items in vec_of_items(1..10), capacity in 1..50usize) {
        let problem = Problem::new(items, capacity);

        let dp_solution = problem.solve(DynamicProgramming);
        let bb_solution = problem.solve(BranchAndBound);

        assert_eq!(dp_solution.total_value, bb_solution.total_value, 
            "DP and Branch and Bound should give solutions with the same value");
    }
}

// Helper function to generate random items
fn vec_of_items(size_range: std::ops::Range<usize>) -> impl Strategy<Value = Vec<SimpleItem>> {
    prop::collection::vec(
        (1..100usize, 1..20usize, 1..100usize),
        size_range
    ).prop_map(|v| {
        v.into_iter()
            .enumerate()
            .map(|(id, (value, weight, _))| SimpleItem::new(id, weight, value))
            .collect()
    })
}
