```go:main.go
package main

import (
	"fmt"
	"log"
	"math/rand"
	"os"
	"sync"
	"time"
)

// Server states
const (
	Follower = iota
	Candidate
	Leader
)

// Configuration parameters
const (
	HeartbeatInterval  = 100 * time.Millisecond
	ElectionTimeoutMin = 150 * time.Millisecond
	ElectionTimeoutMax = 300 * time.Millisecond
)

// LogEntry represents a single entry in the log
type LogEntry struct {
	Term    int
	Command string
}

// RaftServer represents a node in the Raft cluster
type RaftServer struct {
	mu sync.Mutex

	id        int
	peers     []int
	isActive  bool
	partition map[int]bool // Tracks network partitions

	// Persistent state
	currentTerm int
	votedFor    int
	log         []LogEntry

	// Volatile state
	commitIndex int
	lastApplied int
	state       int
	leader      int

	// Leader state
	nextIndex  map[int]int
	matchIndex map[int]int

	// Channels
	voteResponses    chan bool
	heartbeatReset   chan bool
	electionTimeout  time.Duration
	appendEntryReset chan bool

	// Communication channels
	requestVoteCh      map[int]chan RequestVoteArgs
	requestVoteRespCh  map[int]chan RequestVoteReply
	appendEntriesCh    map[int]chan AppendEntriesArgs
	appendEntriesRespCh map[int]chan AppendEntriesReply

	// Logging
	logger *log.Logger
}

// RequestVoteArgs contains arguments for RequestVote RPC
type RequestVoteArgs struct {
	Term         int
	CandidateID  int
	LastLogIndex int
	LastLogTerm  int
}

// RequestVoteReply contains results from RequestVote RPC
type RequestVoteReply struct {
	Term        int
	VoteGranted bool
}

// AppendEntriesArgs contains arguments for AppendEntries RPC
type AppendEntriesArgs struct {
	Term         int
	LeaderID     int
	PrevLogIndex int
	PrevLogTerm  int
	Entries      []LogEntry
	LeaderCommit int
}

// AppendEntriesReply contains results from AppendEntries RPC
type AppendEntriesReply struct {
	Term      int
	Success   bool
	NextIndex int
}

// Cluster represents the entire Raft cluster
type Cluster struct {
	servers []*RaftServer
	logger  *log.Logger
}

// NewRaftServer creates a new Raft server
func NewRaftServer(id int, peers []int, logger *log.Logger) *RaftServer {
	s := &RaftServer{
		id:                id,
		peers:             peers,
		isActive:          true,
		partition:         make(map[int]bool),
		currentTerm:       0,
		votedFor:          -1,
		log:               make([]LogEntry, 1), // Start with dummy entry
		commitIndex:       0,
		lastApplied:       0,
		state:             Follower,
		leader:            -1,
		nextIndex:         make(map[int]int),
		matchIndex:        make(map[int]int),
		voteResponses:     make(chan bool, len(peers)),
		heartbeatReset:    make(chan bool, 1),
		appendEntryReset:  make(chan bool, 1),
		requestVoteCh:     make(map[int]chan RequestVoteArgs),
		requestVoteRespCh: make(map[int]chan RequestVoteReply),
		appendEntriesCh:   make(map[int]chan AppendEntriesArgs),
		appendEntriesRespCh: make(map[int]chan AppendEntriesReply),
		logger:            logger,
	}

	// Initialize communication channels
	for _, peer := range peers {
		s.requestVoteCh[peer] = make(chan RequestVoteArgs, 100)
		s.requestVoteRespCh[peer] = make(chan RequestVoteReply, 100)
		s.appendEntriesCh[peer] = make(chan AppendEntriesArgs, 100)
		s.appendEntriesRespCh[peer] = make(chan AppendEntriesReply, 100)
	}

	// Initialize election timeout
	s.resetElectionTimeout()

	return s
}

// resetElectionTimeout resets the election timeout with a random duration
func (s *RaftServer) resetElectionTimeout() {
	rand.Seed(time.Now().UnixNano() + int64(s.id))
	s.electionTimeout = ElectionTimeoutMin + time.Duration(rand.Int63n(int64(ElectionTimeoutMax-ElectionTimeoutMin)))
}

// Start initiates the Raft server operations
func (s *RaftServer) Start() {
	s.logger.Printf("Server %d starting as Follower\n", s.id)

	// Start listen loops for each peer
	for _, peer := range s.peers {
		go s.listenForRequestVote(peer)
		go s.listenForRequestVoteResponse(peer)
		go s.listenForAppendEntries(peer)
		go s.listenForAppendEntriesResponse(peer)
	}

	// Main server loop
	go func() {
		for {
			if !s.isActive {
				time.Sleep(100 * time.Millisecond)
				continue
			}

			switch s.state {
			case Follower:
				s.runFollower()
			case Candidate:
				s.runCandidate()
			case Leader:
				s.runLeader()
			}
		}
	}()
}

// runFollower handles the follower state
func (s *RaftServer) runFollower() {
	timer := time.NewTimer(s.electionTimeout)
	defer timer.Stop()

	for s.state == Follower && s.isActive {
		select {
		case <-s.heartbeatReset:
			timer.Reset(s.electionTimeout)
		case <-timer.C:
			s.mu.Lock()
			s.logger.Printf("Server %d: election timeout, converting to candidate\n", s.id)
			s.state = Candidate
			s.mu.Unlock()
		}
	}
}

// runCandidate handles the candidate state
func (s *RaftServer) runCandidate() {
	s.mu.Lock()
	s.currentTerm++
	s.votedFor = s.id
	votesReceived := 1 // Vote for self
	s.resetElectionTimeout()
	s.mu.Unlock()

	s.logger.Printf("Server %d: starting election for term %d\n", s.id, s.currentTerm)

	// Request votes from all peers
	s.requestVotes()

	timer := time.NewTimer(s.electionTimeout)
	defer timer.Stop()

	for s.state == Candidate && s.isActive {
		select {
		case granted := <-s.voteResponses:
			if granted {
				votesReceived++
				if votesReceived > (len(s.peers)+1)/2 {
					s.mu.Lock()
					s.state = Leader
					s.leader = s.id
					s.mu.Unlock()
					s.logger.Printf("Server %d: won election for term %d with %d votes\n", s.id, s.currentTerm, votesReceived)

					// Initialize leader state
					for _, peer := range s.peers {
						s.nextIndex[peer] = len(s.log)
						s.matchIndex[peer] = 0
					}
				}
			}
		case <-timer.C:
			s.mu.Lock()
			s.logger.Printf("Server %d: election timeout, starting new election\n", s.id)
			s.state = Candidate // Start new election
			s.mu.Unlock()
			return
		case <-s.heartbeatReset:
			s.mu.Lock()
			s.logger.Printf("Server %d: received heartbeat, reverting to follower\n", s.id)
			s.state = Follower
			s.mu.Unlock()
			return
		}
	}
}

// runLeader handles the leader state
func (s *RaftServer) runLeader() {
	s.logger.Printf("Server %d: became leader for term %d\n", s.id, s.currentTerm)

	// Send initial heartbeats
	s.sendHeartbeats()

	ticker := time.NewTicker(HeartbeatInterval)
	defer ticker.Stop()

	for s.state == Leader && s.isActive {
		select {
		case <-ticker.C:
			s.sendHeartbeats()
		case <-s.appendEntryReset:
			// Continue being leader
		}
	}
}

// requestVotes sends RequestVote RPCs to all peers
func (s *RaftServer) requestVotes() {
	s.mu.Lock()
	lastLogIndex := len(s.log) - 1
	lastLogTerm := 0
	if lastLogIndex >= 0 {
		lastLogTerm = s.log[lastLogIndex].Term
	}
	args := RequestVoteArgs{
		Term:         s.currentTerm,
		CandidateID:  s.id,
		LastLogIndex: lastLogIndex,
		LastLogTerm:  lastLogTerm,
	}
	s.mu.Unlock()

	for _, peer := range s.peers {
		if s.partition[peer] {
			continue // Skip if there's a network partition
		}
		go func(peer int) {
			s.requestVoteCh[peer] <- args
		}(peer)
	}
}

// sendHeartbeats sends AppendEntries RPCs to all peers (may be empty as heartbeats)
func (s *RaftServer) sendHeartbeats() {
	s.mu.Lock()
	defer s.mu.Unlock()

	for _, peer := range s.peers {
		if s.partition[peer] {
			continue // Skip if there's a network partition
		}

		prevLogIndex := s.nextIndex[peer] - 1
		prevLogTerm := 0
		if prevLogIndex >= 0 && prevLogIndex < len(s.log) {
			prevLogTerm = s.log[prevLogIndex].Term
		}

		entries := []LogEntry{}
		if s.nextIndex[peer] < len(s.log) {
			entries = s.log[s.nextIndex[peer]:]
		}

		args := AppendEntriesArgs{
			Term:         s.currentTerm,
			LeaderID:     s.id,
			PrevLogIndex: prevLogIndex,
			PrevLogTerm:  prevLogTerm,
			Entries:      entries,
			LeaderCommit: s.commitIndex,
		}

		go func(peer int) {
			s.appendEntriesCh[peer] <- args
		}(peer)
	}
}

// listenForRequestVote handles incoming RequestVote RPCs
func (s *RaftServer) listenForRequestVote(peer int) {
	for args := range s.requestVoteCh[peer] {
		s.mu.Lock()

		reply := RequestVoteReply{
			Term:        s.currentTerm,
			VoteGranted: false,
		}

		if args.Term < s.currentTerm {
			// Reply false if term < currentTerm
			s.mu.Unlock()
			if !s.partition[peer] {
				s.requestVoteRespCh[peer] <- reply
			}
			continue
		}

		if args.Term > s.currentTerm {
			// If RPC request contains term T > currentTerm: set currentTerm = T, convert to follower
			s.currentTerm = args.Term
			s.state = Follower
			s.votedFor = -1
			s.leader = -1
			reply.Term = s.currentTerm
		}

		lastLogIndex := len(s.log) - 1
		lastLogTerm := 0
		if lastLogIndex >= 0 {
			lastLogTerm = s.log[lastLogIndex].Term
		}

		// If votedFor is null or candidateId, and candidate's log is at least as up-to-date as receiver's log, grant vote
		if (s.votedFor == -1 || s.votedFor == args.CandidateID) &&
			(args.LastLogTerm > lastLogTerm || 
				(args.LastLogTerm == lastLogTerm && args.LastLogIndex >= lastLogIndex)) {
			s.votedFor = args.CandidateID
			reply.VoteGranted = true
			s.logger.Printf("Server %d: granted vote to %d for term %d\n", s.id, args.CandidateID, args.Term)
		}

		s.mu.Unlock()

		if !s.partition[peer] {
			s.requestVoteRespCh[peer] <- reply
		}
	}
}

// listenForRequestVoteResponse handles responses to RequestVote RPCs
func (s *RaftServer) listenForRequestVoteResponse(peer int) {
	for reply := range s.requestVoteRespCh[peer] {
		s.mu.Lock()

		if reply.Term > s.currentTerm {
			// If RPC response contains term T > currentTerm: set currentTerm = T, convert to follower
			s.currentTerm = reply.Term
			s.state = Follower
			s.votedFor = -1
			s.leader = -1
			s.mu.Unlock()
			continue
		}

		if s.state == Candidate && reply.Term == s.currentTerm {
			s.voteResponses <- reply.VoteGranted
		}

		s.mu.Unlock()
	}
}

// listenForAppendEntries handles incoming AppendEntries RPCs
func (s *RaftServer) listenForAppendEntries(peer int) {
	for args := range s.appendEntriesCh[peer] {
		s.mu.Lock()

		reply := AppendEntriesReply{
			Term:    s.currentTerm,
			Success: false,
		}

		if args.Term < s.currentTerm {
			// Reply false if term < currentTerm
			s.mu.Unlock()
			if !s.partition[peer] {
				s.appendEntriesRespCh[peer] <- reply
			}
			continue
		}

		// If AppendEntries RPC received from new leader: convert to follower
		if args.Term >= s.currentTerm {
			if args.Term > s.currentTerm {
				s.currentTerm = args.Term
				s.votedFor = -1
			}

			s.state = Follower
			s.leader = args.LeaderID
			s.heartbeatReset <- true
		}

		// Reply false if log doesn't contain an entry at prevLogIndex whose term matches prevLogTerm
		if args.PrevLogIndex >= len(s.log) || 
			(args.PrevLogIndex >= 0 && s.log[args.PrevLogIndex].Term != args.PrevLogTerm) {
			if args.PrevLogIndex >= len(s.log) {
				reply.NextIndex = len(s.log)
			} else {
				// Find the first index of the conflicting term
				term := s.log[args.PrevLogIndex].Term
				index := args.PrevLogIndex
				for index > 0 && s.log[index-1].Term == term {
					index--
				}
				reply.NextIndex = index
			}
			s.mu.Unlock()
			if !s.partition[peer] {
				s.appendEntriesRespCh[peer] <- reply
			}
			continue
		}

		// If an existing entry conflicts with a new one (same index but different terms),
		// delete the existing entry and all that follow it
		newEntries := make([]LogEntry, 0)
		newEntriesIndex := 0

		for i := args.PrevLogIndex + 1; i < len(s.log) && newEntriesIndex < len(args.Entries); i++ {
			if i >= len(s.log) || s.log[i].Term != args.Entries[newEntriesIndex].Term {
				s.log = s.log[:i]
				break
			}
			newEntriesIndex++
		}

		// Append any new entries not already in the log
		if newEntriesIndex < len(args.Entries) {
			newEntries = args.Entries[newEntriesIndex:]
			s.log = append(s.log, newEntries...)
			s.logger.Printf("Server %d: appended %d new entries from leader %d\n", s.id, len(newEntries), args.LeaderID)
		}

		// Update commit index if leaderCommit > commitIndex
		if args.LeaderCommit > s.commitIndex {
			s.commitIndex = min(args.LeaderCommit, len(s.log)-1)
			s.applyCommittedEntries()
		}

		reply.Success = true
		reply.NextIndex = len(s.log)

		s.mu.Unlock()

		if !s.partition[peer] {
			s.appendEntriesRespCh[peer] <- reply
		}
	}
}

// listenForAppendEntriesResponse handles responses to AppendEntries RPCs
func (s *RaftServer) listenForAppendEntriesResponse(peer int) {
	for reply := range s.appendEntriesRespCh[peer] {
		s.mu.Lock()

		if reply.Term > s.currentTerm {
			// If RPC response contains term T > currentTerm: set currentTerm = T, convert to follower
			s.currentTerm = reply.Term
			s.state = Follower
			s.votedFor = -1
			s.leader = -1
			s.mu.Unlock()
			continue
		}

		if s.state == Leader && reply.Term == s.currentTerm {
			if reply.Success {
				// Update nextIndex and matchIndex for follower
				s.matchIndex[peer] = reply.NextIndex - 1
				s.nextIndex[peer] = reply.NextIndex

				// Check if we can commit any entries
				s.updateCommitIndex()
			} else {
				// Decrement nextIndex and retry
				s.nextIndex[peer] = reply.NextIndex
				s.logger.Printf("Server %d: AppendEntries to %d failed, setting nextIndex=%d\n", s.id, peer, s.nextIndex[peer])
			}
		}

		s.mu.Unlock()
	}
}

// updateCommitIndex checks if we can commit any entries
func (s *RaftServer) updateCommitIndex() {
	// Find the highest matchIndex that is replicated on a majority of servers
	for n := s.commitIndex + 1; n < len(s.log); n++ {
		if s.log[n].Term != s.currentTerm {
			continue
		}

		count := 1 // Leader has the entry
		for _, peer := range s.peers {
			if s.matchIndex[peer] >= n {
				count++
			}
		}

		if count > (len(s.peers)+1)/2 {
			s.commitIndex = n
			s.applyCommittedEntries()
		}
	}
}

// applyCommittedEntries applies all committed but not yet applied log entries
func (s *RaftServer) applyCommittedEntries() {
	for s.lastApplied < s.commitIndex {
		s.lastApplied++
		entry := s.log[s.lastApplied]
		s.logger.Printf("Server %d: applying command %s from term %d\n", s.id, entry.Command, entry.Term)
		// In a real implementation, we would apply the command to the state machine here
	}
}

// AppendCommand adds a command to the log (client API)
func (s *RaftServer) AppendCommand(command string) bool {
	s.mu.Lock()
	defer s.mu.Unlock()

	if s.state != Leader {
		return false
	}

	// Append to leader's log
	entry := LogEntry{
		Term:    s.currentTerm,
		Command: command,
	}
	s.log = append(s.log, entry)
	s.matchIndex[s.id] = len(s.log) - 1
	s.logger.Printf("Server %d: received new command: %s\n", s.id, command)

	return true
}

// Crash simulates a server crash
func (s *RaftServer) Crash() {
	s.mu.Lock()
	defer s.mu.Unlock()

	if !s.isActive {
		return
	}

	s.logger.Printf("Server %d: CRASHED\n", s.id)
	s.isActive = false
}

// Restart simulates a server restart
func (s *RaftServer) Restart() {
	s.mu.Lock()
	defer s.mu.Unlock()

	if s.isActive {
		return
	}

	s.logger.Printf("Server %d: RESTARTED\n", s.id)
	s.isActive = true
	s.state = Follower
	s.leader = -1
	s.resetElectionTimeout()
}

// CreatePartition creates a network partition between this server and peer
func (s *RaftServer) CreatePartition(peer int) {
	s.mu.Lock()
	defer s.mu.Unlock()

	s.partition[peer] = true
	s.logger.Printf("Server %d: NETWORK PARTITION with %d created\n", s.id, peer)
}

// HealPartition heals a network partition between this server and peer
func (s *RaftServer) HealPartition(peer int) {
	s.mu.Lock()
	defer s.mu.Unlock()

	s.partition[peer] = false
	s.logger.Printf("Server %d: NETWORK PARTITION with %d healed\n", s.id, peer)
}

// CreateCluster creates a new Raft cluster with the specified number of servers
func CreateCluster(numServers int) *Cluster {
	logFile, err := os.Create("raft_simulation.log")
	if err != nil {
		panic(err)
	}

	logger := log.New(logFile, "", log.Ldate|log.Ltime|log.Lmicroseconds)
	logger.Println("Starting Raft cluster simulation")

	servers := make([]*RaftServer, numServers)

	// Create all server IDs
	serverIDs := make([]int, numServers)
	for i := 0; i < numServers; i++ {
		serverIDs[i] = i
	}

	// Create and start each server
	for i := 0; i < numServers; i++ {
		peers := make([]int, 0)
		for j := 0; j < numServers; j++ {
			if j != i {
				peers = append(peers, j)
			}
		}

		servers[i] = NewRaftServer(i, peers, logger)
		servers[i].Start()
	}

	return &Cluster{
		servers: servers,
		logger:  logger,
	}
}

// RunFaultInjectionTests runs a series of fault injection tests on the cluster
func (c *Cluster) RunFaultInjectionTests() {
	c.logger.Println("Starting fault injection tests")

	// Wait for a leader to be elected
	time.Sleep(1 * time.Second)

	// Find the current leader
	leader := -1
	for i, server := range c.servers {
		server.mu.Lock()
		if server.state == Leader {
			leader = i
		}
		server.mu.Unlock()

		if leader != -1 {
			break
		}
	}

	if leader == -1 {
		c.logger.Println("No leader elected, extending timeout")
		time.Sleep(2 * time.Second)
		for i, server := range c.servers {
			server.mu.Lock()
			if server.state == Leader {
				leader = i
			}
			server.mu.Unlock()

			if leader != -1 {
				break
			}
		}
	}

	c.logger.Printf("Initial leader is Server %d\n", leader)

	// Test 1: Add some commands
	for i := 0; i < 5; i++ {
		cmd := fmt.Sprintf("command-%d", i)
		c.servers[leader].AppendCommand(cmd)
		time.Sleep(100 * time.Millisecond)
	}

	// Test 2: Crash the leader
	c.logger.Println("TEST: Crashing the leader")
	c.servers[leader].Crash()

	// Wait for a new leader to be elected
	time.Sleep(2 * time.Second)

	// Find the new leader
	newLeader := -1
	for i, server := range c.servers {
		if i == leader {
			continue
		}

		server.mu.Lock()
		if server.state == Leader {
			newLeader = i
		}
		server.mu.Unlock()

		if newLeader != -1 {
			break
		}
	}

	if newLeader != -1 {
		c.logger.Printf("New leader is Server %d\n", newLeader)

		// Add some more commands
		for i := 5; i < 10; i++ {
			cmd := fmt.Sprintf("command-%d", i)
			c.servers[newLeader].AppendCommand(cmd)
			time.Sleep(100 * time.Millisecond)
		}
	} else {
		c.logger.Println("No new leader elected after crash")
	}

	// Test 3: Restart the crashed leader
	c.logger.Println("TEST: Restarting the crashed leader")
	c.servers[leader].Restart()
	time.Sleep(1 * time.Second)

	// Test 4: Create a network partition
	c.logger.Println("TEST: Creating network partition")
	if newLeader != -1 {
		// Partition the cluster so the new leader is isolated
		partitionedServers := []int{newLeader}
		for i := 0; i < len(c.servers); i++ {
			if i != newLeader {
				c.servers[newLeader].CreatePartition(i)
				c.servers[i].CreatePartition(newLeader)
			}
		}

		// Wait for a new leader in the majority partition
		time.Sleep(2 * time.Second)

		// Find the new leader in the majority partition
		majorityLeader := -1
		for i, server := range c.servers {
			if contains(partitionedServers, i) {
				continue
			}

			server.mu.Lock()
			if server.state == Leader {
				majorityLeader = i
			}
			server.mu.Unlock()

			if majorityLeader != -1 {
				break
			}
		}

