package wordcount

import akka.actor.typed.{ActorRef, ActorSystem, Behavior}
import akka.actor.typed.scaladsl.{Behaviors, Routers}
import akka.actor.typed.receptionist.{Receptionist, ServiceKey}
import akka.stream.{Materializer, OverflowStrategy}
import akka.stream.scaladsl.{Sink, Source}
import akka.util.Timeout

import scala.concurrent.{ExecutionContext, Future}
import scala.concurrent.duration._
import scala.io.Source
import scala.util.{Failure, Success}
import java.util.concurrent.atomic.AtomicInteger

// Messages for the MapReduce system
sealed trait MapReduceMessage
final case class MapTask(id: String, text: String, replyTo: ActorRef[ReduceTask]) extends MapReduceMessage
final case class ReduceTask(id: String, mappedData: Map[String, Int]) extends MapReduceMessage
final case class ReduceResult(id: String, wordCounts: Map[String, Int]) extends MapReduceMessage
final case class FinalResult(wordCounts: Map[String, Int]) extends MapReduceMessage

// Worker actor that performs the map operation
object MapWorker {
  def apply(): Behavior[MapTask] = Behaviors.receive { (context, message) =>
    context.log.info(s"Processing map task ${message.id}")

    // Map operation: split text into words and count
    val wordCounts = message.text
      .split("\\W+")
      .filter(_.nonEmpty)
      .map(_.toLowerCase)
      .groupBy(identity)
      .view.mapValues(_.length)
      .toMap

    // Send result back to coordinator
    message.replyTo ! ReduceTask(message.id, wordCounts)
    Behaviors.same
  }
}

// Worker actor that performs the reduce operation
object ReduceWorker {
  def apply(coordinator: ActorRef[ReduceResult]): Behavior[ReduceTask] = Behaviors.receive { (context, message) =>
    context.log.info(s"Processing reduce task ${message.id}")

    // Send result back to coordinator
    coordinator ! ReduceResult(message.id, message.mappedData)
    Behaviors.same
  }
}

// Coordinator actor that distributes tasks and aggregates results
object MapReduceCoordinator {
  private case class TaskStatus(pending: Int, results: Map[String, Int] = Map.empty)

  val MapperServiceKey = ServiceKey[MapTask]("mapper")
  val ReducerServiceKey = ServiceKey[ReduceTask]("reducer")

  def apply(client: ActorRef[FinalResult]): Behavior[MapReduceMessage] = {
    Behaviors.setup { context =>
      val reducerRef = context.spawn(ReduceWorker(context.self), "reducer")
      context.system.receptionist ! Receptionist.Register(ReducerServiceKey, reducerRef)

      var taskStatus = TaskStatus(0)

      Behaviors.receiveMessage {
        case task: MapTask =>
          taskStatus = taskStatus.copy(pending = taskStatus.pending + 1)
          // Forward to available map workers
          context.spawnAnonymous(Router(task))
          Behaviors.same

        case result: ReduceResult =>
          context.log.info(s"Received reduce result for ${result.id}")

          // Merge the new results with existing ones
          val newResults = mergeWordCounts(taskStatus.results, result.wordCounts)
          val newPending = taskStatus.pending - 1
          taskStatus = TaskStatus(newPending, newResults)

          // If all tasks are completed, send final result
          if (newPending == 0) {
            client ! FinalResult(newResults)
          }

          Behaviors.same

        case _ => Behaviors.same
      }
    }
  }

  private def mergeWordCounts(map1: Map[String, Int], map2: Map[String, Int]): Map[String, Int] = {
    (map1.keySet ++ map2.keySet).map { word =>
      word -> (map1.getOrElse(word, 0) + map2.getOrElse(word, 0))
    }.toMap
  }

  private case class Router(task: MapTask) extends Behavior[Nothing] {
    override def apply(context: akka.actor.typed.scaladsl.ActorContext[Nothing]): Behavior[Nothing] = {
      context.system.receptionist ! Receptionist.Find(
        MapperServiceKey,
        context.messageAdapter[Receptionist.Listing] {
          case MapperServiceKey.Listing(workers) =>
            if (workers.nonEmpty) {
              // Round-robin distribution
              val selected = workers.toList(scala.util.Random.nextInt(workers.size))
              selected ! task
            } else {
              // If no workers available, process locally
              context.spawnAnonymous(MapWorker()) ! task
            }
            task // Just to have some return value, will be ignored
        }
      )
      Behaviors.stopped
    }
  }
}

// Main class to set up and run the MapReduce system
object WordCountMapReduce {
  def main(args: Array[String]): Unit = {
    // Create ActorSystem
    val system = ActorSystem[FinalResult](
      Behaviors.setup { context =>
        // Create coordinator waiting for the final result
        val coordinator = context.spawn(MapReduceCoordinator(context.self), "coordinator")

        // Create a pool of map workers
        val workerPoolSize = scala.math.min(50, Runtime.getRuntime.availableProcessors() * 2)
        for (i <- 0 until workerPoolSize) {
          val worker = context.spawn(MapWorker(), s"map-worker-$i")
          context.system.receptionist ! Receptionist.Register(MapReduceCoordinator.MapperServiceKey, worker)
        }

        // Process input files with backpressure
        implicit val materializer: Materializer = Materializer(context)
        implicit val ec: ExecutionContext = context.executionContext

        // Example: process multiple text chunks with backpressure
        val inputFiles = args.toList match {
          case Nil => List("sample-text.txt") // Default sample
          case files => files
        }

        val taskCounter = new AtomicInteger(0)

        // Create a source of map tasks with backpressure
        Source(inputFiles)
          .mapAsync(4) { filename =>
            Future {
              val source = Source.fromFile(filename)
              val content = source.getLines().mkString(" ")
              source.close()
              content
            }
          }
          .map { content =>
            // Split large files into chunks
            content.grouped(10000).zipWithIndex.map { case (chunk, idx) =>
              val taskId = s"task-${taskCounter.getAndIncrement()}-$idx"
              MapTask(taskId, chunk, coordinator)
            }.toList
          }
          .mapConcat(identity)
          .buffer(16, OverflowStrategy.backpressure) // Implement backpressure
          .runWith(Sink.foreach(coordinator ! _))

        // Behavior to handle the final result
        Behaviors.receiveMessage { result =>
          context.log.info(s"Final word count: ${result.wordCounts.size} unique words")
          // Print top 10 most frequent words
          result.wordCounts.toList.sortBy(-_._2).take(10).foreach { case (word, count) =>
            context.log.info(s"$word: $count")
          }
          Behaviors.stopped
        }
      },
      "MapReduceSystem"
    )

    // The system will terminate when all processing is complete
  }
}
