package wordcount

import akka.actor.typed.ActorSystem
import akka.actor.typed.scaladsl.Behaviors
import akka.cluster.typed.{Cluster, ClusterSingleton, SingletonActor}
import akka.actor.typed.receptionist.{Receptionist, ServiceKey}
import com.typesafe.config.ConfigFactory

object ClusterNode {
  def main(args: Array[String]): Unit = {
    val port = if (args.length > 0) args(0).toInt else 0
    val role = if (args.length > 1) args(1) else "worker"

    val config = ConfigFactory.parseString(
      s"""
         |akka.remote.artery.canonical.port = $port
         |akka.cluster.roles = ["$role"]
         |""".stripMargin)
      .withFallback(ConfigFactory.load("cluster"))

    role match {
      case "master" => startMaster(config)
      case _ => startWorker(config)
    }
  }

  def startMaster(config: com.typesafe.config.Config): Unit = {
    val system = ActorSystem[FinalResult](
      Behaviors.setup { context =>
        val cluster = Cluster(context.system)

        // Create the coordinator as a singleton in the cluster
        val coordinatorSingleton = ClusterSingleton(context.system).init(
          SingletonActor(MapReduceCoordinator(context.self), "coordinator")
            .withStopMessage(null)
        )

        // Same result handling as in the local version
        Behaviors.receiveMessage { result =>
          context.log.info(s"Final word count: ${result.wordCounts.size} unique words")
          result.wordCounts.toList.sortBy(-_._2).take(10).foreach { case (word, count) =>
            context.log.info(s"$word: $count")
          }
          Behaviors.stopped
        }
      },
      "MapReduceCluster",
      config
    )
  }

  def startWorker(config: com.typesafe.config.Config): Unit = {
    val system = ActorSystem[Nothing](
      Behaviors.setup[Nothing] { context =>
        val cluster = Cluster(context.system)

        // Create a pool of map workers
        val workerPoolSize = Runtime.getRuntime.availableProcessors()
        for (i <- 0 until workerPoolSize) {
          val worker = context.spawn(MapWorker(), s"map-worker-$i")
          context.system.receptionist ! Receptionist.Register(MapReduceCoordinator.MapperServiceKey, worker)
        }

        // Create a reduce worker
        val reducer = context.spawn(ReduceWorker(null), "reducer")
        context.system.receptionist ! Receptionist.Register(MapReduceCoordinator.ReducerServiceKey, reducer)

        context.log.info(s"Worker node started with $workerPoolSize workers")
        Behaviors.empty
      },
      "WorkerNode",
      config
    )
  }
}
