        .attr("y", d => height - yScale(d) - 5)
        .attr("text-anchor", "middle")
        .text(d => d);

    texts.exit().remove();
}

function setupEventListeners() {
    document.getElementById("generate-array").addEventListener("click", generateArray);
    document.getElementById("start").addEventListener("click", startSorting);
    document.getElementById("pause").addEventListener("click", togglePause);
    document.getElementById("step").addEventListener("click", stepForward);
    document.getElementById("speed").addEventListener("input", (e) => {
        animationSpeed = e.target.value;
    });
    document.getElementById("algorithm-select").addEventListener("change", (e) => {
        sortingAlgorithm = e.target.value;
        resetAnimation();
    });
}

function resetAnimation() {
    isPlaying = false;
    isPaused = false;
    animationQueue = [];
    currentAnimationIndex = 0;
    d3.selectAll(".array-bar").attr("class", "array-bar");
    updateAnnotation("Select an algorithm and press Start");
}

function startSorting() {
    if (isPlaying && !isPaused) return;

    if (currentAnimationIndex === 0 || currentAnimationIndex >= animationQueue.length) {
        // Generate new animation steps
        animationQueue = [];
        currentAnimationIndex = 0;

        const arrayCopy = [...array];
        switch (sortingAlgorithm) {
            case "mergeSort":
                mergeSort(arrayCopy, 0, arrayCopy.length - 1);
                break;
            case "quickSort":
                quickSort(arrayCopy, 0, arrayCopy.length - 1);
                break;
            case "heapSort":
                heapSort(arrayCopy);
                break;
        }
    }

    isPlaying = true;
    isPaused = false;

    playAnimations();
}

function togglePause() {
    if (!isPlaying) return;
    isPaused = !isPaused;
    if (!isPaused) {
        playAnimations();
    }
}

function stepForward() {
    if (currentAnimationIndex >= animationQueue.length) return;

    if (!isPlaying) {
        startSorting();
        isPaused = true;
    } else {
        executeAnimation(animationQueue[currentAnimationIndex++]);
    }
}

function playAnimations() {
    if (!isPlaying || isPaused || currentAnimationIndex >= animationQueue.length) return;

    executeAnimation(animationQueue[currentAnimationIndex++]);

    if (currentAnimationIndex < animationQueue.length) {
        setTimeout(playAnimations, 1000 - animationSpeed * 9);
    } else {
        isPlaying = false;
        updateAnnotation("Sorting completed!");
    }
}

function executeAnimation(animation) {
    const { type, indices, newArray, annotation } = animation;

    d3.selectAll(".array-bar").attr("class", "array-bar");

    if (type === "compare") {
        indices.forEach(i => {
            d3.selectAll(".array-bar").filter((d, j) => j === i).attr("class", "array-bar comparing");
        });
    } else if (type === "swap" || type === "update") {
        renderArray(newArray);
        indices.forEach(i => {
            d3.selectAll(".array-bar").filter((d, j) => j === i).attr("class", "array-bar comparing");
        });
    } else if (type === "pivot") {
        indices.forEach(i => {
            d3.selectAll(".array-bar").filter((d, j) => j === i).attr("class", "array-bar pivot");
        });
    } else if (type === "sorted") {
        indices.forEach(i => {
            d3.selectAll(".array-bar").filter((d, j) => j === i).attr("class", "array-bar sorted");
        });
    }

    updateAnnotation(annotation);
}

function updateAnnotation(text) {
    document.getElementById("current-step").innerText = text;
}

// SORTING ALGORITHMS

// Merge Sort
function mergeSort(arr, l, r) {
    if (l >= r) return;

    const m = Math.floor((l + r) / 2);

    animationQueue.push({
        type: "compare",
        indices: [l, r],
        newArray: [...arr],
        annotation: `Dividing array from index ${l} to ${r} at midpoint ${m}`
    });

    mergeSort(arr, l, m);
    mergeSort(arr, m + 1, r);

    merge(arr, l, m, r);
}

function merge(arr, l, m, r) {
    const n1 = m - l + 1;
    const n2 = r - m;

    const L = arr.slice(l, m + 1);
    const R = arr.slice(m + 1, r + 1);

    animationQueue.push({
        type: "compare",
        indices: Array.from({ length: r - l + 1 }, (_, i) => l + i),
        newArray: [...arr],
        annotation: `Merging subarrays: [${L}] and [${R}]`
    });

    let i = 0, j = 0, k = l;

    while (i < n1 && j < n2) {
        if (L[i] <= R[j]) {
            arr[k] = L[i];
            i++;
        } else {
            arr[k] = R[j];
            j++;
        }

        animationQueue.push({
            type: "update",
            indices: [k],
            newArray: [...arr],
            annotation: `Comparing ${L[i - 1] || L[i]} and ${R[j - 1] || R[j]}, placing ${arr[k]} at index ${k}`
        });

        k++;
    }

    while (i < n1) {
        arr[k] = L[i];

        animationQueue.push({
            type: "update",
            indices: [k],
            newArray: [...arr],
            annotation: `Remaining elements from left subarray, placing ${L[i]} at index ${k}`
        });

        i++;
        k++;
    }

    while (j < n2) {
        arr[k] = R[j];

        animationQueue.push({
            type: "update",
            indices: [k],
            newArray: [...arr],
            annotation: `Remaining elements from right subarray, placing ${R[j]} at index ${k}`
        });

        j++;
        k++;
    }

    animationQueue.push({
        type: "sorted",
        indices: Array.from({ length: r - l + 1 }, (_, i) => l + i),
        newArray: [...arr],
        annotation: `Merged subarray from index ${l} to ${r}`
    });
}

// Quick Sort
function quickSort(arr, low, high) {
    if (low < high) {
        const pi = partition(arr, low, high);

        quickSort(arr, low, pi - 1);
        quickSort(arr, pi + 1, high);
    }
}

function partition(arr, low, high) {
    const pivot = arr[high];

    animationQueue.push({
        type: "pivot",
        indices: [high],
        newArray: [...arr],
        annotation: `Choosing pivot: ${pivot} at index ${high}`
    });

    let i = low - 1;

    for (let j = low; j < high; j++) {
        animationQueue.push({
            type: "compare",
            indices: [j, high],
            newArray: [...arr],
            annotation: `Comparing element ${arr[j]} with pivot ${pivot}`
        });

        if (arr[j] < pivot) {
            i++;

            // Swap arr[i] and arr[j]
            [arr[i], arr[j]] = [arr[j], arr[i]];

            animationQueue.push({
                type: "swap",
                indices: [i, j],
                newArray: [...arr],
                annotation: `${arr[j]} is less than pivot ${pivot}, swapping indices ${i} and ${j}`
            });
        }
    }

    // Swap arr[i+1] and arr[high]
    [arr[i + 1], arr[high]] = [arr[high], arr[i + 1]];

    animationQueue.push({
        type: "swap",
        indices: [i + 1, high],
        newArray: [...arr],
        annotation: `Placing pivot ${pivot} at its correct position (index ${i + 1})`
    });

    animationQueue.push({
        type: "sorted",
        indices: [i + 1],
        newArray: [...arr],
        annotation: `Pivot ${pivot} is now at its sorted position`
    });

    return i + 1;
}

// Heap Sort
function heapSort(arr) {
    const n = arr.length;

    // Build max heap
    for (let i = Math.floor(n / 2) - 1; i >= 0; i--) {
        heapify(arr, n, i);
    }

    animationQueue.push({
        type: "compare",
        indices: Array.from({ length: n }, (_, i) => i),
        newArray: [...arr],
        annotation: "Max heap built"
    });

    // Extract elements from heap
    for (let i = n - 1; i > 0; i--) {
        // Swap root with last element
        [arr[0], arr[i]] = [arr[i], arr[0]];

        animationQueue.push({
            type: "swap",
            indices: [0, i],
            newArray: [...arr],
            annotation: `Moving largest element ${arr[i]} to the end (index ${i})`
        });

        // Call heapify on reduced heap
        heapify(arr, i, 0);

        animationQueue.push({
            type: "sorted",
            indices: [i],
            newArray: [...arr],
            annotation: `Element ${arr[i]} is now at its sorted position`
        });
    }
}

function heapify(arr, n, i) {
    let largest = i;
    const left = 2 * i + 1;
    const right = 2 * i + 2;

    animationQueue.push({
        type: "compare",
        indices: [i, left < n ? left : i, right < n ? right : i],
        newArray: [...arr],
        annotation: `Heapifying at index ${i}`
    });

    // If left child is larger than root
    if (left < n && arr[left] > arr[largest]) {
        largest = left;
    }

    // If right child is larger than largest so far
    if (right < n && arr[right] > arr[largest]) {
        largest = right;
    }

    // If largest is not root
    if (largest !== i) {
        [arr[i], arr[largest]] = [arr[largest], arr[i]];

        animationQueue.push({
            type: "swap",
            indices: [i, largest],
            newArray: [...arr],
            annotation: `Swapping ${arr[i]} and ${arr[largest]} during heapify`
        });

        // Recursively heapify the affected sub-tree
        heapify(arr, n, largest);
    }
}

