#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <string.h>
#include <immintrin.h>
#include <time.h>
#include <fftw3.h>
#include <x86intrin.h>

#define N (1 << 20)  // 1 million points
#define PI 3.14159265358979323846

typedef struct {
    float real;
    float imag;
} complex_t;

// Cache-optimized FFT implementation
void fft_optimized(complex_t* x, int n) {
    // Bit-reversal permutation
    int i, j, k;
    for (i = 0, j = 0; i < n; i++) {
        if (j > i) {
            complex_t temp = x[i];
            x[i] = x[j];
            x[j] = temp;
        }
        k = n >> 1;
        while (k <= j) {
            j -= k;
            k >>= 1;
        }
        j += k;
    }

    // Cooley-Tukey decimation-in-time radix-2 FFT
    for (int s = 1; s <= log2(n); s++) {
        int m = 1 << s;
        int m2 = m >> 1;

        // Precompute twiddle factors for vectorization
        complex_t* twiddles = (complex_t*)_mm_malloc(m2 * sizeof(complex_t), 32);
        for (int k = 0; k < m2; k++) {
            float theta = -2.0f * PI * k / m;
            twiddles[k].real = cosf(theta);
            twiddles[k].imag = sinf(theta);
        }

        // Process in blocks for cache efficiency
        #pragma omp parallel for
        for (int i = 0; i < n; i += m) {
            for (int j = 0; j < m2; j += 4) {
                if (j + 4 <= m2) {
                    // SIMD processing of 4 butterflies at once
                    __m256 wr = _mm256_setr_ps(
                        twiddles[j].real, twiddles[j+1].real, 
                        twiddles[j+2].real, twiddles[j+3].real,
                        twiddles[j].real, twiddles[j+1].real, 
                        twiddles[j+2].real, twiddles[j+3].real
                    );

                    __m256 wi = _mm256_setr_ps(
                        twiddles[j].imag, twiddles[j+1].imag, 
                        twiddles[j+2].imag, twiddles[j+3].imag,
                        twiddles[j].imag, twiddles[j+1].imag, 
                        twiddles[j+2].imag, twiddles[j+3].imag
                    );

                    for (int k = 0; k < 4; k++) {
                        int idx1 = i + j + k;
                        int idx2 = idx1 + m2;

                        float tr = x[idx2].real * twiddles[j+k].real - x[idx2].imag * twiddles[j+k].imag;
                        float ti = x[idx2].real * twiddles[j+k].imag + x[idx2].imag * twiddles[j+k].real;

                        x[idx2].real = x[idx1].real - tr;
                        x[idx2].imag = x[idx1].imag - ti;
                        x[idx1].real = x[idx1].real + tr;
                        x[idx1].imag = x[idx1].imag + ti;
                    }
                } else {
                    // Handle remaining elements
                    for (int k = j; k < m2; k++) {
                        int idx1 = i + k;
                        int idx2 = idx1 + m2;

                        float tr = x[idx2].real * twiddles[k].real - x[idx2].imag * twiddles[k].imag;
                        float ti = x[idx2].real * twiddles[k].imag + x[idx2].imag * twiddles[k].real;

                        x[idx2].real = x[idx1].real - tr;
                        x[idx2].imag = x[idx1].imag - ti;
                        x[idx1].real = x[idx1].real + tr;
                        x[idx1].imag = x[idx1].imag + ti;
                    }
                }
            }
        }

        _mm_free(twiddles);
    }
}

int main() {
    // Allocate aligned memory for better SIMD performance
    complex_t* data = (complex_t*)_mm_malloc(N * sizeof(complex_t), 32);
    complex_t* fftw_in = (complex_t*)_mm_malloc(N * sizeof(complex_t), 32);
    fftwf_complex* fftw_data = (fftwf_complex*)fftwf_malloc(sizeof(fftwf_complex) * N);

    // Initialize with random data
    for (int i = 0; i < N; i++) {
        data[i].real = (float)rand() / RAND_MAX;
        data[i].imag = (float)rand() / RAND_MAX;
        fftw_in[i] = data[i];
        fftw_data[i][0] = data[i].real;
        fftw_data[i][1] = data[i].imag;
    }

    // Measure our optimized FFT performance
    unsigned long long start_cycles, end_cycles;
    clock_t start, end;
    double cpu_time_used;

    start = clock();
    start_cycles = _rdtsc();
    fft_optimized(data, N);
    end_cycles = _rdtsc();
    end = clock();

    cpu_time_used = ((double) (end - start)) / CLOCKS_PER_SEC * 1000; // ms
    printf("Optimized FFT execution time: %.2f ms\n", cpu_time_used);
    printf("CPU cycles: %llu\n", end_cycles - start_cycles);

    // Compare with FFTW
    fftwf_plan plan = fftwf_plan_dft_1d(N, fftw_data, fftw_data, FFTW_FORWARD, FFTW_MEASURE);

    start = clock();
    start_cycles = _rdtsc();
    fftwf_execute(plan);
    end_cycles = _rdtsc();
    end = clock();

    cpu_time_used = ((double) (end - start)) / CLOCKS_PER_SEC * 1000; // ms
    printf("FFTW execution time: %.2f ms\n", cpu_time_used);
    printf("FFTW CPU cycles: %llu\n", end_cycles - start_cycles);

    // Verify correctness (simplified)
    double error = 0.0;
    for (int i = 0; i < N; i++) {
        error += sqrt(pow(data[i].real - fftw_data[i][0], 2) + pow(data[i].imag - fftw_data[i][1], 2));
    }
    printf("Average error per element: %e\n", error / N);

    // Cleanup
    fftwf_destroy_plan(plan);
    fftwf_free(fftw_data);
    _mm_free(data);
    _mm_free(fftw_in);

    return 0;
}
