#pragma once
#include "point.hpp"
#include <algorithm>

namespace geometry {

class ConvexHull {
public:
    // Graham scan algorithm
    static Points compute(Points points) {
        if (points.size() <= 2) return points;

        // Find point with lowest y-coordinate
        auto pivot = std::min_element(points.begin(), points.end(),
            [](const Point& a, const Point& b) {
                return a.y < b.y || (a.y == b.y && a.x < b.x);
            });

        // Put pivot at first position
        std::swap(points[0], *pivot);
        Point p0 = points[0];

        // Sort points by polar angle
        std::sort(points.begin() + 1, points.end(),
            [&p0](const Point& a, const Point& b) {
                double cross = (a - p0).cross(b - p0);
                if (std::abs(cross) < 1e-9)
                    return a.dist2(p0) < b.dist2(p0);
                return cross > 0;
            });

        // Build convex hull
        Points hull;
        for (const auto& p : points) {
            while (hull.size() >= 2 && 
                   (hull.back() - hull[hull.size() - 2]).cross(p - hull.back()) <= 0) {
                hull.pop_back();
            }
            hull.push_back(p);
        }

        return hull;
    }
};

} // namespace geometry
