#pragma once
#include "point.hpp"
#include <vector>
#include <set>
#include <tuple>

namespace geometry {

struct Triangle {
    int a, b, c;  // Indices to points

    Triangle(int a, int b, int c) : a(a), b(b), c(c) {}

    bool operator==(const Triangle& other) const {
        return std::tie(a, b, c) == std::tie(other.a, other.b, other.c);
    }

    bool operator<(const Triangle& other) const {
        return std::tie(a, b, c) < std::tie(other.a, other.b, other.c);
    }
};

struct Edge {
    int a, b;  // Indices to points

    Edge(int a, int b) : a(std::min(a, b)), b(std::max(a, b)) {}

    bool operator==(const Edge& other) const {
        return a == other.a && b == other.b;
    }

    bool operator<(const Edge& other) const {
        return std::tie(a, b) < std::tie(other.a, other.b);
    }
};

class DelaunayTriangulation {
public:
    static std::vector<Triangle> compute(const Points& points) {
        if (points.size() < 3) return {};

        // Create super-triangle
        double minX = points[0].x, minY = points[0].y;
        double maxX = minX, maxY = minY;

        for (const auto& p : points) {
            minX = std::min(minX, p.x);
            minY = std::min(minY, p.y);
            maxX = std::max(maxX, p.x);
            maxY = std::max(maxY, p.y);
        }

        double dx = maxX - minX;
        double dy = maxY - minY;
        double dmax = std::max(dx, dy);
        double xmid = (minX + maxX) / 2;
        double ymid = (minY + maxY) / 2;

        Points allPoints = points;
        allPoints.push_back(Point(xmid - 20 * dmax, ymid - dmax));
        allPoints.push_back(Point(xmid, ymid + 20 * dmax));
        allPoints.push_back(Point(xmid + 20 * dmax, ymid - dmax));

        std::vector<Triangle> triangles;
        triangles.emplace_back(points.size(), points.size() + 1, points.size() + 2);

        // Add points one by one
        for (int i = 0; i < points.size(); i++) {
            std::set<Edge> edges;

            // Find triangles that contain the point in their circumcircle
            auto it = triangles.begin();
            while (it != triangles.end()) {
                if (isInCircumcircle(allPoints, *it, i)) {
                    edges.insert(Edge(it->a, it->b));
                    edges.insert(Edge(it->b, it->c));
                    edges.insert(Edge(it->c, it->a));
                    it = triangles.erase(it);
                } else {
                    ++it;
                }
            }

            // Remove internal edges
            for (auto it1 = edges.begin(); it1 != edges.end();) {
                auto it2 = edges.find(Edge(it1->a, it1->b));
                if (it2 != it1 && it2 != edges.end()) {
                    it1 = edges.erase(it1);
                    edges.erase(it2);
                } else {
                    ++it1;
                }
            }

            // Create new triangles
            for (const auto& edge : edges) {
                triangles.emplace_back(edge.a, edge.b, i);
            }
        }

        // Remove triangles with super-triangle vertices
        it = triangles.begin();
        while (it != triangles.end()) {
            if (it->a >= points.size() || it->b >= points.size() || it->c >= points.size()) {
                it = triangles.erase(it);
            } else {
                ++it;
            }
        }

        return triangles;
    }

private:
    static bool isInCircumcircle(const Points& points, const Triangle& t, int p) {
        const Point& a = points[t.a];
        const Point& b = points[t.b];
        const Point& c = points[t.c];
        const Point& d = points[p];

        double ax = a.x - d.x;
        double ay = a.y - d.y;
        double bx = b.x - d.x;
        double by = b.y - d.y;
        double cx = c.x - d.x;
        double cy = c.y - d.y;

        double det = (ax * (by * cx - bx * cy) - 
                      ay * (bx * cx - by * cy) + 
                      (ax * ax + ay * ay) * (bx * cy - by * cx) +
                      (bx * bx + by * by) * (cy * ax - cx * ay) +
                      (cx * cx + cy * cy) * (ay * bx - ax * by));

        return det > 0;
    }
};

} // namespace geometry
