```cpp:include/geometry/voronoi.hpp
#pragma once
#include "point.hpp"
#include "delaunay.hpp"
#include <vector>
#include <map>

namespace geometry {

struct VoronoiCell {
    int site;  // Index of the site point
    std::vector<Point> vertices;
};

class VoronoiDiagram {
public:
    static std::vector<VoronoiCell> compute(const Points& sites) {
        // Compute Delaunay triangulation
        std::vector<Triangle> triangles = DelaunayTriangulation::compute(sites);

        // Compute circumcenters
        std::map<Triangle, Point> circumcenters;
        for (const auto& t : triangles) {
            circumcenters[t] = computeCircumcenter(sites[t.a], sites[t.b], sites[t.c]);
        }

        // Build Voronoi cells
        std::map<int, VoronoiCell> cells;

        // Initialize cells for each site
        for (int i = 0; i < sites.size(); i++) {
            cells[i].site = i;
        }

        // Add Voronoi vertices to cells
        for (const auto& t : triangles) {
            Point center = circumcenters[t];

            // Add center to all three site cells
            cells[t.a].vertices.push_back(center);
            cells[t.b].vertices.push_back(center);
            cells[t.c].vertices.push_back(center);
        }

        // Sort vertices in counterclockwise order
        for (auto& [_, cell] : cells) {
            sortVerticesCounterClockwise(sites[cell.site], cell.vertices);
        }

        // Convert map to vector
        std::vector<VoronoiCell> result;
        for (const auto& [_, cell] : cells) {
            result.push_back(cell);
        }

        return result;
    }

private:
    static Point computeCircumcenter(const Point& a, const Point& b, const Point& c) {
        double d = 2 * (a.x * (b.y - c.y) + b.x * (c.y - a.y) + c.x * (a.y - b.y));

        double x = ((a.x * a.x + a.y * a.y) * (b.y - c.y) +
                    (b.x * b.x + b.y * b.y) * (c.y - a.y) +
                    (c.x * c.x + c.y * c.y) * (a.y - b.y)) / d;

        double y = ((a.x * a.x + a.y * a.y) * (c.x - b.x) +
                    (b.x * b.x + b.y * b.y) * (a.x - c.x) +
                    (c.x * c.x + c.y * c.y) * (b.x - a.x)) / d;

        return Point(x, y);
    }

    static void sortVerticesCounterClockwise(const Point& center, std::vector<Point>& vertices) {
        std::sort(vertices.begin(), vertices.end(), [&center](const Point& a, const Point& b) {
            double angleA = std::atan2(a.y - center.y, a.x - center.x);
            double angleB = std::atan2(b.y - center.y, b.x - center.x);
            return angleA < angleB;
        });
    }
};

} // namespace geometry
