#include "geometry/delaunay.hpp"
#include <gtest/gtest.h>
#include <random>
#include <set>

using namespace geometry;

// Helper function to check if a point is inside a triangle
bool isInsideTriangle(const Point& p, const Point& a, const Point& b, const Point& c) {
    double area = 0.5 * std::abs((b.x - a.x) * (c.y - a.y) - (c.x - a.x) * (b.y - a.y));
    double area1 = 0.5 * std::abs((a.x - p.x) * (b.y - p.y) - (b.x - p.x) * (a.y - p.y));
    double area2 = 0.5 * std::abs((b.x - p.x) * (c.y - p.y) - (c.x - p.x) * (b.y - p.y));
    double area3 = 0.5 * std::abs((c.x - p.x) * (a.y - p.y) - (a.x - p.x) * (c.y - p.y));

    return std::abs(area - (area1 + area2 + area3)) < 1e-9;
}

TEST(DelaunayTest, SimpleTriangle) {
    Points points = {
        {0, 0}, {1, 0}, {0, 1}
    };

    std::vector<Triangle> triangulation = DelaunayTriangulation::compute(points);

    ASSERT_EQ(triangulation.size(), 1);
    EXPECT_EQ(triangulation[0].a, 0);
    EXPECT_EQ(triangulation[0].b, 1);
    EXPECT_EQ(triangulation[0].c, 2);
}

TEST(DelaunayTest, Square) {
    Points points = {
        {0, 0}, {1, 0}, {0, 1}, {1, 1}
    };

    std::vector<Triangle> triangulation = DelaunayTriangulation::compute(points);

    ASSERT_EQ(triangulation.size(), 2);

    // Check that each edge appears exactly once or twice
    std::set<Edge> edges;
    for (const auto& t : triangulation) {
        edges.insert(Edge(t.a, t.b));
        edges.insert(Edge(t.b, t.c));
        edges.insert(Edge(t.c, t.a));
    }

    // Diagonal should appear exactly once
    EXPECT_EQ(edges.count(Edge(0, 3)), 1);
    EXPECT_EQ(edges.count(Edge(1, 2)), 1);
}

TEST(DelaunayTest, RandomPoints) {
    std::random_device rd;
    std::mt19937 gen(rd());
    std::uniform_real_distribution<> dis(0.0, 100.0);

    Points points;
    for (int i = 0; i < 20; i++) {
        points.push_back({dis(gen), dis(gen)});
    }

    std::vector<Triangle> triangulation = DelaunayTriangulation::compute(points);

    // Check Delaunay property: no point is inside the circumcircle of any triangle
    for (const auto& t : triangulation) {
        const Point& a = points[t.a];
        const Point& b = points[t.b];
        const Point& c = points[t.c];

        // Compute circumcenter
        double d = 2 * (a.x * (b.y - c.y) + b.x * (c.y - a.y) + c.x * (a.y - b.y));
        double ux = ((a.x * a.x + a.y * a.y) * (b.y - c.y) +
                    (b.x * b.x + b.y * b.y) * (c.y - a.y) +
                    (c.x * c.x + c.y * c.y) * (a.y - b.y)) / d;
        double uy = ((a.x * a.x + a.y * a.y) * (c.x - b.x) +
                    (b.x * b.x + b.y * b.y) * (a.x - c.x) +
                    (c.x * c.x + c.y * c.y) * (b.x - a.x)) / d;

        Point center(ux, uy);
        double radius = center.dist(a);

        // Check that no other point is inside this circle
        for (int i = 0; i < points.size(); i++) {
            if (i != t.a && i != t.b && i != t.c) {
                EXPECT_GE(center.dist(points[i]), radius - 1e-9);
            }
        }
    }
}
