        {0, 0}, {1, 0}
    };

    std::vector<VoronoiCell> cells = VoronoiDiagram::compute(sites);

    ASSERT_EQ(cells.size(), 2);

    // Check that the dividing line is at x = 0.5
    bool foundMidpoint = false;
    for (const auto& cell : cells) {
        for (const auto& vertex : cell.vertices) {
            if (std::abs(vertex.x - 0.5) < 1e-9) {
                foundMidpoint = true;
                break;
            }
        }
    }

    EXPECT_TRUE(foundMidpoint);
}

TEST(VoronoiTest, ThreePoints) {
    Points sites = {
        {0, 0}, {1, 0}, {0, 1}
    };

    std::vector<VoronoiCell> cells = VoronoiDiagram::compute(sites);

    ASSERT_EQ(cells.size(), 3);

    // Check that the circumcenter is at (0.5, 0.5)
    bool foundCircumcenter = false;
    for (const auto& cell : cells) {
        for (const auto& vertex : cell.vertices) {
            if (std::abs(vertex.x - 0.5) < 1e-9 && std::abs(vertex.y - 0.5) < 1e-9) {
                foundCircumcenter = true;
                break;
            }
        }
    }

    EXPECT_TRUE(foundCircumcenter);
}

TEST(VoronoiTest, RandomPoints) {
    std::random_device rd;
    std::mt19937 gen(rd());
    std::uniform_real_distribution<> dis(0.0, 100.0);

    Points sites;
    for (int i = 0; i < 10; i++) {
        sites.push_back({dis(gen), dis(gen)});
    }

    std::vector<VoronoiCell> cells = VoronoiDiagram::compute(sites);

    ASSERT_EQ(cells.size(), 10);

    // Check that each cell contains its site
    for (const auto& cell : cells) {
        const Point& site = sites[cell.site];

        // For each other site, check that it's closer to its own cell
        for (int i = 0; i < sites.size(); i++) {
            if (i == cell.site) continue;

            const Point& otherSite = sites[i];
            double dist = site.dist(otherSite);

            // Find the midpoint
            Point midpoint((site.x + otherSite.x) / 2, (site.y + otherSite.y) / 2);

            // The midpoint should be on the boundary between the cells
            // This is a simplified test - a more rigorous test would check
            // if the boundary plane between the sites contains the midpoint
            EXPECT_NEAR(site.dist(midpoint), otherSite.dist(midpoint), 1e-9);
        }
    }
}
