#pragma once

#include <atomic>
#include <cstdint>
#include <functional>
#include <memory>
#include <unordered_map>
#include <vector>

// Forward declarations
struct Order;
struct OrderBook;
struct MatchingResult;

// Types
using OrderId = uint64_t;
using Price = uint64_t;
using Quantity = uint32_t;
using TimeStamp = uint64_t;

// Order side
enum class Side : uint8_t {
    BUY,
    SELL
};

// Order type
enum class OrderType : uint8_t {
    LIMIT,
    MARKET
};

// Order structure
struct Order {
    OrderId id;
    Side side;
    OrderType type;
    Price price;
    Quantity quantity;
    Quantity filled;
    TimeStamp timestamp;

    bool is_complete() const { return filled >= quantity; }
};

// Match result
struct Trade {
    OrderId buy_id;
    OrderId sell_id;
    Price price;
    Quantity quantity;
    TimeStamp timestamp;
};

struct MatchingResult {
    std::vector<Trade> trades;
    std::vector<OrderId> completed_orders;
};

// Order book for a single instrument
class OrderBook {
public:
    OrderBook();
    ~OrderBook();

    // Disallow copying
    OrderBook(const OrderBook&) = delete;
    OrderBook& operator=(const OrderBook&) = delete;

    // Add order to the book
    void add_order(const Order& order);

    // Cancel order
    bool cancel_order(OrderId order_id);

    // Match orders
    MatchingResult match_orders();

private:
    // Price level structure
    struct PriceLevel {
        std::vector<Order> orders;
        std::atomic<size_t> size{0};
    };

    // Pre-allocated price levels
    std::vector<PriceLevel> buy_levels_;
    std::vector<PriceLevel> sell_levels_;

    // Order ID to position mapping
    std::unordered_map<OrderId, std::pair<Side, Price>> order_map_;

    // Best bid/ask tracking
    std::atomic<Price> best_bid_{0};
    std::atomic<Price> best_ask_{std::numeric_limits<Price>::max()};

    // Memory pool for trade results
    std::vector<Trade> trade_pool_;
    size_t trade_pool_index_;

    // Order matching implementation
    MatchingResult match_limit_orders();
};

// Main matching engine
class OrderMatchingEngine {
public:
    OrderMatchingEngine(size_t num_threads);
    ~OrderMatchingEngine();

    // Initialize the engine
    void initialize();

    // Process an incoming order
    MatchingResult process_order(const Order& order);

    // Cancel an existing order
    bool cancel_order(OrderId order_id);

    // Run benchmark
    void run_benchmark(size_t num_orders);

private:
    // Thread pool for order processing
    std::vector<std::thread> threads_;

    // Order books per instrument (simplified for this example)
    OrderBook order_book_;

    // Thread coordination
    std::atomic<bool> running_{false};

    // Pin thread to CPU core
    void pin_thread_to_core(int thread_id);
};
