```cpp:order_matching_engine.cpp
#include "order_matching_engine.h"
#include <algorithm>
#include <chrono>
#include <iostream>
#include <random>
#include <thread>
#include <pthread.h>

// Cache line size (64 bytes on most CPUs)
constexpr size_t CACHE_LINE_SIZE = 64;

// Preallocated pool sizes
constexpr size_t MAX_PRICE_LEVELS = 10000;
constexpr size_t MAX_TRADES_PER_MATCH = 1000;

// CPU affinity
void OrderMatchingEngine::pin_thread_to_core(int thread_id) {
    cpu_set_t cpuset;
    CPU_ZERO(&cpuset);
    CPU_SET(thread_id % std::thread::hardware_concurrency(), &cpuset);
    pthread_setaffinity_np(pthread_self(), sizeof(cpu_set_t), &cpuset);
}

// Order Book implementation
OrderBook::OrderBook() {
    // Pre-allocate price levels
    buy_levels_.resize(MAX_PRICE_LEVELS);
    sell_levels_.resize(MAX_PRICE_LEVELS);

    // Pre-allocate trade results pool
    trade_pool_.resize(MAX_TRADES_PER_MATCH);
    trade_pool_index_ = 0;
}

OrderBook::~OrderBook() = default;

void OrderBook::add_order(const Order& order) {
    auto& levels = (order.side == Side::BUY) ? buy_levels_ : sell_levels_;

    // Hash price to index
    size_t index = order.price % levels.size();

    // Add to level
    auto& level = levels[index];
    size_t pos = level.size.fetch_add(1, std::memory_order_relaxed);
    if (pos < level.orders.size()) {
        level.orders[pos] = order;
    } else {
        level.orders.push_back(order);
    }

    // Update best prices
    if (order.side == Side::BUY) {
        Price current_best = best_bid_.load(std::memory_order_relaxed);
        while (order.price > current_best) {
            if (best_bid_.compare_exchange_weak(current_best, order.price)) {
                break;
            }
        }
    } else {
        Price current_best = best_ask_.load(std::memory_order_relaxed);
        while (order.price < current_best) {
            if (best_ask_.compare_exchange_weak(current_best, order.price)) {
                break;
            }
        }
    }

    // Update order map
    order_map_[order.id] = {order.side, order.price};
}

bool OrderBook::cancel_order(OrderId order_id) {
    auto it = order_map_.find(order_id);
    if (it == order_map_.end()) {
        return false;
    }

    Side side = it->second.first;
    Price price = it->second.second;
    auto& levels = (side == Side::BUY) ? buy_levels_ : sell_levels_;
    size_t index = price % levels.size();

    auto& level = levels[index];
    auto& orders = level.orders;

    for (size_t i = 0; i < level.size; ++i) {
        if (orders[i].id == order_id) {
            // Mark as filled to effectively cancel
            orders[i].filled = orders[i].quantity;
            order_map_.erase(order_id);
            return true;
        }
    }

    return false;
}

MatchingResult OrderBook::match_orders() {
    return match_limit_orders();
}

MatchingResult OrderBook::match_limit_orders() {
    MatchingResult result;
    trade_pool_index_ = 0;

    Price bid = best_bid_.load(std::memory_order_relaxed);
    Price ask = best_ask_.load(std::memory_order_relaxed);

    // If no overlap, no matching possible
    if (bid < ask) {
        return result;
    }

    // Match orders
    for (Price price = bid; price >= ask && price <= bid; --price) {
        size_t buy_index = price % buy_levels_.size();
        size_t sell_index = price % sell_levels_.size();

        auto& buy_level = buy_levels_[buy_index];
        auto& sell_level = sell_levels_[sell_index];

        size_t buy_size = buy_level.size.load(std::memory_order_relaxed);
        size_t sell_size = sell_level.size.load(std::memory_order_relaxed);

        for (size_t i = 0; i < buy_size; ++i) {
            auto& buy_order = buy_level.orders[i];

            if (buy_order.is_complete()) {
                continue;
            }

            for (size_t j = 0; j < sell_size; ++j) {
                auto& sell_order = sell_level.orders[j];

                if (sell_order.is_complete()) {
                    continue;
                }

                if (buy_order.price >= sell_order.price) {
                    // Calculate match quantity
                    Quantity remaining_buy = buy_order.quantity - buy_order.filled;
                    Quantity remaining_sell = sell_order.quantity - sell_order.filled;
                    Quantity match_qty = std::min(remaining_buy, remaining_sell);

                    // Update filled amounts
                    buy_order.filled += match_qty;
                    sell_order.filled += match_qty;

                    // Record trade
                    if (trade_pool_index_ < trade_pool_.size()) {
                        auto& trade = trade_pool_[trade_pool_index_++];
                        trade.buy_id = buy_order.id;
                        trade.sell_id = sell_order.id;
                        trade.price = price;
                        trade.quantity = match_qty;
                        trade.timestamp = std::chrono::high_resolution_clock::now().time_since_epoch().count();
                        result.trades.push_back(trade);
                    }

                    // Check for completed orders
                    if (buy_order.is_complete()) {
                        result.completed_orders.push_back(buy_order.id);
                        break; // Move to next buy order
                    }

                    if (sell_order.is_complete()) {
                        result.completed_orders.push_back(sell_order.id);
                        continue; // Try next sell order with current buy
                    }
                }
            }
        }
    }

    // Update best bid/ask
    // Would need more complex logic for production

    return result;
}

// Matching Engine implementation
OrderMatchingEngine::OrderMatchingEngine(size_t num_threads) {
    threads_.resize(num_threads);
}

OrderMatchingEngine::~OrderMatchingEngine() {
    running_ = false;
    for (auto& thread : threads_) {
        if (thread.joinable()) {
            thread.join();
        }
    }
}

void OrderMatchingEngine::initialize() {
    running_ = true;

    // Start worker threads
    for (size_t i = 0; i < threads_.size(); ++i) {
        threads_[i] = std::thread([this, i]() {
            // Pin thread to CPU core
            pin_thread_to_core(i);

            // Thread processing loop would go here
            while (running_.load(std::memory_order_relaxed)) {
                // In a real system, would process from a queue
                std::this_thread::yield();
            }
        });
    }
}

MatchingResult OrderMatchingEngine::process_order(const Order& order) {
    // Add order to book
    order_book_.add_order(order);

    // Try to match
    return order_book_.match_orders();
}

bool OrderMatchingEngine::cancel_order(OrderId order_id) {
    return order_book_.cancel_order(order_id);
}

void OrderMatchingEngine::run_benchmark(size_t num_orders) {
    std::random_device rd;
    std::mt19937 gen(rd());
    std::uniform_int_distribution<> side_dist(0, 1);
    std::uniform_int_distribution<> price_dist(9000, 11000);
    std::uniform_int_distribution<> qty_dist(1, 100);

    std::vector<Order> orders;
    orders.reserve(num_orders);

    // Generate random orders
    for (size_t i = 0; i < num_orders; ++i) {
        Order order;
        order.id = i + 1;
        order.side = side_dist(gen) ? Side::BUY : Side::SELL;
        order.type = OrderType::LIMIT;
        order.price = price_dist(gen);
        order.quantity = qty_dist(gen);
        order.filled = 0;
        order.timestamp = std::chrono::high_resolution_clock::now().time_since_epoch().count();
        orders.push_back(order);
    }

    // Measure processing time
    auto start = std::chrono::high_resolution_clock::now();

    size_t matches = 0;
    for (const auto& order : orders) {
        auto result = process_order(order);
        matches += result.trades.size();
    }

    auto end = std::chrono::high_resolution_clock::now();
    auto duration = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();

    double avg_latency = static_cast<double>(duration) / num_orders;

    std::cout << "Benchmark results:" << std::endl;
    std::cout << "  Orders processed: " << num_orders << std::endl;
    std::cout << "  Matches found: " << matches << std::endl;
    std::cout << "  Total time: " << duration / 1000000.0 << " ms" << std::endl;
    std::cout << "  Avg. latency: " << avg_latency << " ns (" << avg_latency / 1000.0 << " µs)" << std::endl;
    std::cout << "  Throughput: " << (num_orders * 1000000000.0) / duration << " orders/sec" << std::endl;
}
