```java:src/main/java/com/payment/api/service/TokenizationService.java
package com.payment.api.service;

import org.springframework.stereotype.Service;
import javax.crypto.Mac;
import javax.crypto.spec.SecretKeySpec;
import java.security.SecureRandom;
import java.util.Base64;
import java.util.HashMap;
import java.util.Map;
import java.util.UUID;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class TokenizationService {

    private static final String HMAC_SHA256 = "HmacSHA256";
    private final Map<String, String> tokenMap = new ConcurrentHashMap<>();
    private final String tokenizationKey = System.getenv("TOKENIZATION_KEY");

    public String generateToken(String lastFourDigits, String expirationDate) {
        String token = UUID.randomUUID().toString();
        // Store only non-sensitive data with the token
        tokenMap.put(token, lastFourDigits + ":" + expirationDate);
        return token;
    }

    public Map<String, String> getTokenMetadata(String token) {
        String metadata = tokenMap.get(token);
        if (metadata == null) {
            return null;
        }

        String[] parts = metadata.split(":");
        Map<String, String> result = new HashMap<>();
        result.put("lastFourDigits", parts[0]);
        result.put("expirationDate", parts[1]);
        return result;
    }

    public String generateHmac(String data) {
        try {
            SecretKeySpec secretKeySpec = new SecretKeySpec(tokenizationKey.getBytes(), HMAC_SHA256);
            Mac mac = Mac.getInstance(HMAC_SHA256);
            mac.init(secretKeySpec);
            return Base64.getEncoder().encodeToString(mac.doFinal(data.getBytes()));
        } catch (Exception e) {
            throw new RuntimeException("Failed to generate HMAC", e);
        }
    }

    public boolean verifyHmac(String data, String expectedHmac) {
        String calculatedHmac = generateHmac(data);
        return calculatedHmac.equals(expectedHmac);
    }
}
