import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.Map;

@RestController
@RequestMapping("/api")
public class PaymentController {

    @Autowired
    private TokenizationService tokenizationService;

    @PostMapping("/public/tokenize")
    public ResponseEntity<Map<String, String>> tokenize(@RequestBody @Valid Map<String, String> request) {
        // Client should only send last four digits and expiration date
        // The actual tokenization happens on the client side
        String lastFourDigits = request.get("lastFourDigits");
        String expirationDate = request.get("expirationDate");

        String token = tokenizationService.generateToken(lastFourDigits, expirationDate);

        return ResponseEntity.ok(Map.of(
            "token", token,
            "lastFourDigits", lastFourDigits
        ));
    }

    @GetMapping("/payment/{token}")
    public ResponseEntity<Map<String, String>> getTokenInfo(@PathVariable String token) {
        Map<String, String> metadata = tokenizationService.getTokenMetadata(token);
        if (metadata == null) {
            return ResponseEntity.notFound().build();
        }
        return ResponseEntity.ok(metadata);
    }
}
