class PaymentTokenizer {
    constructor(publicKey) {
        this.publicKey = publicKey;
    }

    validateCardNumber(cardNumber) {
        // Luhn algorithm for credit card validation
        const digits = cardNumber.replace(/\D/g, '');
        let sum = 0;
        let shouldDouble = false;

        for (let i = digits.length - 1; i >= 0; i--) {
            let digit = parseInt(digits.charAt(i));

            if (shouldDouble) {
                digit *= 2;
                if (digit > 9) digit -= 9;
            }

            sum += digit;
            shouldDouble = !shouldDouble;
        }

        return sum % 10 === 0;
    }

    validateExpirationDate(month, year) {
        const currentDate = new Date();
        const currentYear = currentDate.getFullYear() % 100;
        const currentMonth = currentDate.getMonth() + 1;

        if (year < currentYear) return false;
        if (year === currentYear && month < currentMonth) return false;

        return true;
    }

    async tokenize(cardData) {
        // Validate card data
        if (!this.validateCardNumber(cardData.cardNumber)) {
            throw new Error('Invalid card number');
        }

        const month = parseInt(cardData.expirationMonth, 10);
        const year = parseInt(cardData.expirationYear, 10);

        if (!this.validateExpirationDate(month, year)) {
            throw new Error('Card expired');
        }

        // Extract last four digits - only data sent to server
        const lastFour = cardData.cardNumber.slice(-4);
        const expirationDate = `${cardData.expirationMonth}/${cardData.expirationYear}`;

        // In a real implementation, we would use a secure tokenization service
        // For this example, we'll just send the last four digits to our server
        const response = await fetch('/api/public/tokenize', {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({
                lastFourDigits: lastFour,
                expirationDate: expirationDate
            })
        });

        if (!response.ok) {
            throw new Error('Tokenization failed');
        }

        return await response.json();
    }
}

