class MockNetworkAdapter {
  constructor() {
    this.isOnline = true;
    this.isFlaky = false;
    this.syncedData = [];
    this.pendingSync = [];
  }

  static instance = new MockNetworkAdapter();

  static async reset() {
    this.instance.isOnline = true;
    this.instance.isFlaky = false;
    this.instance.syncedData = [];
    this.instance.pendingSync = [];
  }

  static async setOnline(online) {
    this.instance.isOnline = online;

    if (online && this.instance.pendingSync.length > 0) {
      await this.instance.processPendingSync();
    }
  }

  static async setFlakyConnection(flaky) {
    this.instance.isFlaky = flaky;
  }

  static async getSyncedData() {
    return this.instance.syncedData;
  }

  async sync(data) {
    if (!this.isOnline) {
      this.pendingSync.push(data);
      return { success: false, status: 'offline' };
    }

    if (this.isFlaky) {
      return new Promise((resolve) => {
        const delay = Math.random() * 5000 + 1000;
        setTimeout(async () => {
          const success = Math.random() > 0.3;
          if (success) {
            this.syncedData.push(data);
            resolve({ success: true, status: 'synced' });
          } else {
            this.pendingSync.push(data);
            resolve({ success: false, status: 'network-error' });
          }
        }, delay);
      });
    }

    this.syncedData.push(data);
    return { success: true, status: 'synced' };
  }

  async processPendingSync() {
    const pending = [...this.pendingSync];
    this.pendingSync = [];

    for (const data of pending) {
      await this.sync(data);
    }
  }
}

export default MockNetworkAdapter;
