export default class DataSyncService {
  constructor(networkAdapter, storageAdapter) {
    this.networkAdapter = networkAdapter;
    this.storageAdapter = storageAdapter;
    this.syncQueue = [];
    this.isOnline = true;
    this.listeners = [];
  }

  setNetworkStatus(online) {
    this.isOnline = online;
    if (online) {
      this.processSyncQueue();
    }
  }

  async saveData(data) {
    const id = data.id || Date.now().toString();
    const itemWithId = { ...data, id };

    await this.storageAdapter.saveItem(id, itemWithId);

    this.enqueueSyncItem(itemWithId);
    return itemWithId;
  }

  async getData(id) {
    return this.storageAdapter.getItem(id);
  }

  async getAllData() {
    return this.storageAdapter.getAllItems();
  }

  enqueueSyncItem(item) {
    this.syncQueue.push(item);
    this.notifyStatusChange('pending');

    if (this.isOnline) {
      this.processSyncQueue();
    }
  }

  async processSyncQueue() {
    if (this.syncQueue.length === 0) return;

    const item = this.syncQueue.shift();
    try {
      const result = await this.networkAdapter.sync(item);
      if (result.success) {
        this.notifyStatusChange('success');
      } else {
        this.syncQueue.push(item);
        this.notifyStatusChange('failed');
        setTimeout(() => this.processSyncQueue(), 5000);
      }
    } catch (error) {
      this.syncQueue.push(item);
      this.notifyStatusChange('error');
      setTimeout(() => this.processSyncQueue(), 5000);
    }
  }

  addStatusListener(listener) {
    this.listeners.push(listener);
    return () => {
      this.listeners = this.listeners.filter(l => l !== listener);
    };
  }

  notifyStatusChange(status) {
    this.listeners.forEach(listener => listener(status));
  }
}
