use std::{collections::HashSet, fs, path::Path, sync::Arc, time::Duration};
use tokio::{
    io::{AsyncReadExt, AsyncWriteExt},
    net::{TcpListener, TcpStream},
    sync::{Mutex, RwLock},
    time,
};
use serde::{Deserialize, Serialize};
use log::{error, info, warn};
use warp::Filter;

#[derive(Debug, Clone, Serialize, Deserialize, PartialEq, Eq, Hash)]
struct TelemetryMessage {
    id: String,
    device_id: String,
    timestamp: u64,
    payload: Vec<u8>,
}

struct WriteAheadLog {
    path: String,
    file: Mutex<fs::File>,
}

impl WriteAheadLog {
    fn new(path: &str) -> std::io::Result<Self> {
        let file = fs::OpenOptions::new()
            .create(true)
            .append(true)
            .open(path)?;

        Ok(Self {
            path: path.to_string(),
            file: Mutex::new(file),
        })
    }

    async fn append(&self, message: &TelemetryMessage) -> std::io::Result<()> {
        let serialized = bincode::serialize(message).map_err(|e| {
            std::io::Error::new(std::io::ErrorKind::Other, e)
        })?;

        let mut file = self.file.lock().await;
        file.write_all(&(serialized.len() as u32).to_le_bytes())?;
        file.write_all(&serialized)?;
        file.sync_all()?;

        Ok(())
    }

    async fn recover(&self) -> std::io::Result<Vec<TelemetryMessage>> {
        let mut messages = Vec::new();
        let contents = fs::read(&self.path)?;
        let mut position = 0;

        while position + 4 <= contents.len() {
            let size_bytes = [
                contents[position],
                contents[position + 1],
                contents[position + 2],
                contents[position + 3],
            ];
            let size = u32::from_le_bytes(size_bytes) as usize;
            position += 4;

            if position + size > contents.len() {
                break;
            }

            let message_data = &contents[position..position + size];
            match bincode::deserialize::<TelemetryMessage>(message_data) {
                Ok(message) => messages.push(message),
                Err(e) => error!("Failed to deserialize message: {}", e),
            }
            position += size;
        }

        Ok(messages)
    }
}

struct TelemetryService {
    wal: Arc<WriteAheadLog>,
    processed_messages: Arc<RwLock<HashSet<String>>>,
    remote_endpoint: String,
    connection: Arc<Mutex<Option<TcpStream>>>,
    health: Arc<RwLock<bool>>,
}

impl TelemetryService {
    async fn new(remote_endpoint: &str, wal_path: &str) -> std::io::Result<Self> {
        let wal = Arc::new(WriteAheadLog::new(wal_path)?);
        let processed_messages = Arc::new(RwLock::new(HashSet::new()));

        // Recover messages from WAL
        let recovered = wal.recover().await?;
        for message in &recovered {
            processed_messages.write().await.insert(message.id.clone());
        }

        let service = Self {
            wal,
            processed_messages,
            remote_endpoint: remote_endpoint.to_string(),
            connection: Arc::new(Mutex::new(None)),
            health: Arc::new(RwLock::new(false)),
        };

        Ok(service)
    }

    async fn connect(&self) -> std::io::Result<()> {
        let mut connection = self.connection.lock().await;

        match TcpStream::connect(&self.remote_endpoint).await {
            Ok(stream) => {
                info!("Connected to remote endpoint: {}", self.remote_endpoint);
                *connection = Some(stream);
                *self.health.write().await = true;
                Ok(())
            }
            Err(e) => {
                error!("Failed to connect: {}", e);
                *self.health.write().await = false;
                Err(e)
            }
        }
    }

    async fn reconnect_loop(&self) {
        loop {
            if self.connection.lock().await.is_none() {
                if let Err(e) = self.connect().await {
                    warn!("Reconnection attempt failed: {}", e);
                }
            }
            time::sleep(Duration::from_secs(5)).await;
        }
    }

    async fn ingest_message(&self, message: TelemetryMessage) -> std::io::Result<bool> {
        // Check for duplicates
        {
            let processed = self.processed_messages.read().await;
            if processed.contains(&message.id) {
                return Ok(false); // Duplicate message
            }
        }

        // Write to WAL first
        self.wal.append(&message).await?;

        // Mark as processed
        self.processed_messages.write().await.insert(message.id.clone());

        // Try to send to remote endpoint
        self.send_message(&message).await?;

        Ok(true)
    }

    async fn send_message(&self, message: &TelemetryMessage) -> std::io::Result<()> {
        let mut connection_guard = self.connection.lock().await;

        if connection_guard.is_none() {
            if let Err(e) = self.connect().await {
                return Err(e);
            }
            connection_guard = self.connection.lock().await;
        }

        if let Some(stream) = &mut *connection_guard {
            let serialized = bincode::serialize(message).map_err(|e| {
                std::io::Error::new(std::io::ErrorKind::Other, e)
            })?;

            match stream.write_all(&serialized).await {
                Ok(_) => Ok(()),
                Err(e) => {
                    error!("Failed to send message: {}", e);
                    *connection_guard = None;
                    *self.health.write().await = false;
                    Err(e)
                }
            }
        } else {
            Err(std::io::Error::new(
                std::io::ErrorKind::NotConnected,
                "Not connected to remote endpoint",
            ))
        }
    }

    async fn start_health_endpoint(&self, port: u16) {
        let health = self.health.clone();

        let health_route = warp::path("health")
            .and(warp::get())
            .map(move || {
                let is_healthy = *health.read().blocking_lock();
                if is_healthy {
                    warp::reply::with_status("OK", warp::http::StatusCode::OK)
                } else {
                    warp::reply::with_status("ERROR", warp::http::StatusCode::SERVICE_UNAVAILABLE)
                }
            });

        warp::serve(health_route)
            .run(([0, 0, 0, 0], port))
            .await;
    }
}

#[tokio::main]
async fn main() -> std::io::Result<()> {
    env_logger::init();

    let remote_endpoint = std::env::var("REMOTE_ENDPOINT")
        .unwrap_or_else(|_| "127.0.0.1:9000".to_string());

    let wal_path = std::env::var("WAL_PATH")
        .unwrap_or_else(|_| "telemetry_wal.bin".to_string());

    let health_port = std::env::var("HEALTH_PORT")
        .ok()
        .and_then(|p| p.parse::<u16>().ok())
        .unwrap_or(8080);

    let service = Arc::new(TelemetryService::new(&remote_endpoint, &wal_path).await?);

    // Start background tasks
    let reconnect_service = service.clone();
    tokio::spawn(async move {
        reconnect_service.reconnect_loop().await;
    });

    let health_service = service.clone();
    tokio::spawn(async move {
        health_service.start_health_endpoint(health_port).await;
    });

    // Start listening for incoming messages
    let listener = TcpListener::bind("0.0.0.0:7000").await?;
    info!("Telemetry service listening on 0.0.0.0:7000");

    while let Ok((mut socket, addr)) = listener.accept().await {
        info!("New client connected: {}", addr);
        let service = service.clone();

        tokio::spawn(async move {
            let mut buffer = [0u8; 1024];

            loop {
                match socket.read(&mut buffer).await {
                    Ok(0) => {
                        info!("Client disconnected: {}", addr);
                        break;
                    }
                    Ok(n) => {
                        match bincode::deserialize::<TelemetryMessage>(&buffer[..n]) {
                            Ok(message) => {
                                match service.ingest_message(message).await {
                                    Ok(true) => socket.write_all(b"OK").await.unwrap_or(()),
                                    Ok(false) => socket.write_all(b"DUPLICATE").await.unwrap_or(()),
                                    Err(e) => {
                                        error!("Error ingesting message: {}", e);
                                        socket.write_all(b"ERROR").await.unwrap_or(());
                                    }
                                }
                            }
                            Err(e) => {
                                error!("Failed to deserialize message: {}", e);
                                socket.write_all(b"INVALID_FORMAT").await.unwrap_or(());
                            }
                        }
                    }
                    Err(e) => {
                        error!("Error reading from socket: {}", e);
                        break;
                    }
                }
            }
        });
    }

    Ok(())
}
