```javascript:load-test.js
const { Worker, isMainThread, parentPort } = require('worker_threads');
const { io } = require('socket.io-client');
const crypto = require('crypto');

const WORKERS = 10;
const CLIENTS_PER_WORKER = 1000;
const TARGET_URL = 'ws://localhost:3000';

if (isMainThread) {
  console.log(`Starting load test with ${WORKERS} workers, ${CLIENTS_PER_WORKER} clients per worker`);
  console.log(`Target: ${WORKERS * CLIENTS_PER_WORKER} total concurrent connections`);

  const results = {
    connected: 0,
    messages: 0,
    errors: 0,
    responseTime: []
  };

  // Start monitoring
  const startTime = Date.now();

  // Create workers
  for (let i = 0; i < WORKERS; i++) {
    const worker = new Worker(__filename);

    worker.on('message', (msg) => {
      if (msg.type === 'connected') {
        results.connected++;
      } else if (msg.type === 'message') {
        results.messages++;
        results.responseTime.push(msg.responseTime);
      } else if (msg.type === 'error') {
        results.errors++;
      }

      // Print progress
      if (results.connected % 1000 === 0) {
        console.log(`Connected: ${results.connected}, Messages: ${results.messages}, Errors: ${results.errors}`);
      }

      // Check if test is complete
      if (results.connected === WORKERS * CLIENTS_PER_WORKER) {
        const duration = (Date.now() - startTime) / 1000;
        const avgResponseTime = results.responseTime.reduce((a, b) => a + b, 0) / results.responseTime.length;

        console.log('\n===== LOAD TEST RESULTS =====');
        console.log(`Total connections: ${results.connected}`);
        console.log(`Messages sent/received: ${results.messages}`);
        console.log(`Errors: ${results.errors}`);
        console.log(`Test duration: ${duration.toFixed(2)} seconds`);
        console.log(`Connection rate: ${(results.connected / duration).toFixed(2)} connections/second`);
        console.log(`Average response time: ${avgResponseTime.toFixed(2)} ms`);
        console.log('============================\n');

        process.exit(0);
      }
    });
  }
} else {
  // Worker thread code
  setTimeout(() => {
    // Connect clients with some delay to prevent burst
    for (let i = 0; i < CLIENTS_PER_WORKER; i++) {
      setTimeout(() => {
        createClient(i);
      }, i * 10);
    }
  }, Math.random() * 1000);

  function createClient(id) {
    const socket = io(TARGET_URL, {
      transports: ['websocket'],
      reconnection: false
    });

    const room = `room-${Math.floor(id / 100)}`; // Group users into rooms

    socket.on('connect', () => {
      parentPort.postMessage({ type: 'connected' });
      socket.emit('join-room', room);

      // Send a message occasionally
      if (id % 10 === 0) {
        setTimeout(() => {
          const startTime = Date.now();
          socket.emit('send-message', {
            room,
            message: `Test message ${crypto.randomBytes(8).toString('hex')}`,
            sender: `user-${id}`
          });

          socket.on('new-message', () => {
            const responseTime = Date.now() - startTime;
            parentPort.postMessage({ type: 'message', responseTime });
          });
        }, 1000 + Math.random() * 5000);
      }
    });

    socket.on('connect_error', () => {
      parentPort.postMessage({ type: 'error' });
    });
  }
}
