```typescript:src/app/services/dashboard.service.ts
import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { BehaviorSubject, Observable, of, throwError } from 'rxjs';
import { catchError, delay, map, tap } from 'rxjs/operators';
import { Widget, Layout } from '../models/widget.model';

@Injectable({
  providedIn: 'root'
})
export class DashboardService {
  private readonly API_URL = 'api/dashboard';
  private layoutSubject = new BehaviorSubject<Layout | null>(null);
  private networkStatus = new BehaviorSubject<boolean>(navigator.onLine);

  constructor(private http: HttpClient) {
    window.addEventListener('online', () => this.networkStatus.next(true));
    window.addEventListener('offline', () => this.networkStatus.next(false));
    this.loadSavedLayout();
  }

  get layout$(): Observable<Layout | null> {
    return this.layoutSubject.asObservable();
  }

  get isOnline$(): Observable<boolean> {
    return this.networkStatus.asObservable();
  }

  loadSavedLayout(): void {
    const saved = localStorage.getItem('dashboard_layout');
    if (saved) {
      this.layoutSubject.next(JSON.parse(saved));
    } else {
      this.getDefaultLayout().subscribe();
    }
  }

  getDefaultLayout(): Observable<Layout> {
    return this.http.get<Layout>(`${this.API_URL}/layout/default`).pipe(
      delay(800), // Simulate network delay
      tap(layout => {
        this.layoutSubject.next(layout);
        this.saveLayout(layout);
      }),
      catchError(err => {
        console.error('Failed to load default layout', err);
        return of(this.getOfflineLayout());
      })
    );
  }

  saveLayout(layout: Layout): void {
    layout.updatedAt = new Date();
    localStorage.setItem('dashboard_layout', JSON.stringify(layout));

    if (navigator.onLine) {
      this.http.put(`${this.API_URL}/layout/${layout.id}`, layout).pipe(
        catchError(err => {
          console.warn('Failed to save layout to server, saved locally', err);
          return throwError(err);
        })
      ).subscribe();
    }
  }

  updateWidgetPosition(widget: Widget): void {
    const currentLayout = this.layoutSubject.value;
    if (!currentLayout) return;

    const index = currentLayout.widgets.findIndex(w => w.id === widget.id);
    if (index >= 0) {
      currentLayout.widgets[index] = {...widget};
      this.layoutSubject.next({...currentLayout});
      this.saveLayout(currentLayout);
    }
  }

  private getOfflineLayout(): Layout {
    return {
      id: 'offline',
      name: 'Offline Layout',
      widgets: [
        {
          id: 'offline-widget',
          name: 'Offline Mode',
          type: 'info',
          cols: 12,
          rows: 1,
          x: 0,
          y: 0
        }
      ],
      createdAt: new Date(),
      updatedAt: new Date()
    };
  }
}
