import { Component, OnInit, OnDestroy, HostListener } from '@angular/core';
import { GridsterConfig, GridsterItem } from 'angular-gridster2';
import { Subscription } from 'rxjs';
import { DashboardService } from '../../services/dashboard.service';
import { Widget, Layout } from '../../models/widget.model';
import { MatSnackBar } from '@angular/material/snack-bar';

@Component({
  selector: 'app-dashboard',
  templateUrl: './dashboard.component.html',
  styleUrls: ['./dashboard.component.scss']
})
export class DashboardComponent implements OnInit, OnDestroy {
  options: GridsterConfig;
  widgets: Widget[] = [];
  loading = true;
  private subscription = new Subscription();

  constructor(
    private dashboardService: DashboardService,
    private snackBar: MatSnackBar
  ) {}

  ngOnInit(): void {
    this.initGridster();
    this.loadDashboard();
  }

  @HostListener('window:keydown', ['$event'])
  handleKeyboardShortcut(event: KeyboardEvent): void {
    // Ctrl/Cmd + S to save layout
    if ((event.ctrlKey || event.metaKey) && event.key === 's') {
      event.preventDefault();
      this.saveCurrentLayout();
      this.snackBar.open('Dashboard layout saved', 'Dismiss', { duration: 3000 });
    }

    // Ctrl/Cmd + Z to undo layout changes
    if ((event.ctrlKey || event.metaKey) && event.key === 'z') {
      event.preventDefault();
      this.loadDashboard();
      this.snackBar.open('Dashboard layout restored', 'Dismiss', { duration: 3000 });
    }
  }

  private initGridster(): void {
    this.options = {
      gridType: 'fit',
      compactType: 'compactUp',
      margin: 10,
      outerMargin: true,
      outerMarginTop: 50,
      outerMarginRight: 10,
      outerMarginBottom: 10,
      outerMarginLeft: 10,
      mobileBreakpoint: 640,
      minCols: 12,
      maxCols: 12,
      minRows: 6,
      maxRows: 100,
      maxItemCols: 12,
      minItemCols: 1,
      maxItemRows: 100,
      minItemRows: 1,
      maxItemArea: 2500,
      minItemArea: 1,
      defaultItemCols: 4,
      defaultItemRows: 3,
      draggable: {
        enabled: true,
        ignoreContent: true,
        dropOverItems: false,
        dragHandleClass: 'drag-handle'
      },
      resizable: {
        enabled: true
      },
      itemChangeCallback: (item) => {
        this.updateWidgetPosition(item as Widget);
      },
      itemResizeCallback: (item) => {
        this.updateWidgetPosition(item as Widget);
      }
    };
  }

  private loadDashboard(): void {
    this.loading = true;
    this.subscription.add(
      this.dashboardService.layout$.subscribe(layout => {
        if (layout) {
          this.widgets = [...layout.widgets];
        }
        this.loading = false;
      })
    );
  }

  private updateWidgetPosition(widget: Widget): void {
    this.dashboardService.updateWidgetPosition(widget);
  }

  private saveCurrentLayout(): void {
    const currentLayout = this.dashboardService.layout$.getValue();
    if (currentLayout) {
      currentLayout.widgets = [...this.widgets];
      this.dashboardService.saveLayout(currentLayout);
    }
  }

  ngOnDestroy(): void {
    this.subscription.unsubscribe();
  }
}
