Here's a Go implementation for adaptive bitrate transcoding in a video-streaming microservice:

```go
package main

import (
	"context"
	"fmt"
	"log"
	"os"
	"os/signal"
	"runtime"
	"sync"
	"syscall"
	"time"

	"github.com/pion/rtp"
	"github.com/pion/webrtc/v3"
	"github.com/pion/webrtc/v3/pkg/media"
	"github.com/nareix/joy4/av"
	"github.com/nareix/joy4/av/avutil"
	"github.com/nareix/joy4/cgo/ffmpeg"
	"github.com/nareix/joy4/format"
	"github.com/nareix/joy4/format/rtmp"
)

// Resolution profiles for adaptive bitrate
type Profile struct {
	Width        int
	Height       int
	Bitrate      int    // in kbps
	EncodingPreset string // ultrafast, superfast, veryfast, etc.
}

var profiles = []Profile{
	{Width: 1280, Height: 720, Bitrate: 2500, EncodingPreset: "veryfast"}, // 720p
	{Width: 854, Height: 480, Bitrate: 1000, EncodingPreset: "veryfast"},  // 480p
	{Width: 640, Height: 360, Bitrate: 600, EncodingPreset: "veryfast"},   // 360p
	{Width: 426, Height: 240, Bitrate: 300, EncodingPreset: "veryfast"},   // 240p
}

// TranscodingWorker handles video transcoding
type TranscodingWorker struct {
	id            int
	inputChan     chan *media.Sample
	outputChan    chan *TranscodedPacket
	profile       Profile
	transcoder    *ffmpeg.VideoTranscoder
	ctx           context.Context
	cancelFunc    context.CancelFunc
	wg            *sync.WaitGroup
}

// TranscodedPacket contains the transcoded data and metadata
type TranscodedPacket struct {
	Data         []byte
	Timestamp    uint32
	ProfileIndex int
}

// Initialize FFmpeg with GPU acceleration
func init() {
	ffmpeg.InitializeGPU()
	format.RegisterAll()
}

func NewTranscodingWorker(id int, profileIndex int, inputChan chan *media.Sample, outputChan chan *TranscodedPacket, wg *sync.WaitGroup) *TranscodingWorker {
	ctx, cancel := context.WithCancel(context.Background())

	profile := profiles[profileIndex]

	// Configure transcoder with zero-copy and hardware acceleration
	transcoder := ffmpeg.NewVideoTranscoder()
	transcoder.SetGPUAcceleration(true)
	transcoder.SetZeroCopy(true)
	transcoder.SetInputFormat("h264")
	transcoder.SetOutputFormat("h264")
	transcoder.SetOutputResolution(profile.Width, profile.Height)
	transcoder.SetOutputBitrate(profile.Bitrate)
	transcoder.SetEncodingPreset(profile.EncodingPreset)

	return &TranscodingWorker{
		id:         id,
		inputChan:  inputChan,
		outputChan: outputChan,
		profile:    profile,
		transcoder: transcoder,
		ctx:        ctx,
		cancelFunc: cancel,
		wg:         wg,
	}
}

func (w *TranscodingWorker) Start() {
	w.wg.Add(1)
	go func() {
		defer w.wg.Done()
		defer w.transcoder.Close()

		for {
			select {
			case <-w.ctx.Done():
				return
			case sample, ok := <-w.inputChan:
				if !ok {
					return
				}

				// Record start time for latency measurement
				startTime := time.Now()

				// Process the sample with zero-copy buffers
				result, err := w.transcoder.Transcode(sample.Data)
				if err != nil {
					log.Printf("Worker %d: Transcoding error: %v", w.id, err)
					continue
				}

				// Calculate and log latency
				latency := time.Since(startTime)
				if latency > 500*time.Millisecond {
					log.Printf("Worker %d: High latency warning: %v", w.id, latency)
				}

				// Send the transcoded packet to output channel
				profileIndex := 0
				for i, p := range profiles {
					if p.Width == w.profile.Width && p.Height == w.profile.Height {
						profileIndex = i
						break
					}
				}

				w.outputChan <- &TranscodedPacket{
					Data:         result,
					Timestamp:    sample.Timestamp,
					ProfileIndex: profileIndex,
				}
			}
		}
	}()
}

func (w *TranscodingWorker) Stop() {
	w.cancelFunc()
}

// StreamProcessor manages the transcoding pipeline
type StreamProcessor struct {
	inputChan      chan *media.Sample
	outputChans    []chan *TranscodedPacket
	workers        [][]*TranscodingWorker
	workerPoolSize int
	ctx            context.Context
	cancelFunc     context.CancelFunc
	wg             sync.WaitGroup
}

func NewStreamProcessor(workerPoolSize int) *StreamProcessor {
	ctx, cancel := context.WithCancel(context.Background())

	inputChan := make(chan *media.Sample, 100)
	outputChans := make([]chan *TranscodedPacket, len(profiles))
	workers := make([][]*TranscodingWorker, len(profiles))

	for i := range outputChans {
		outputChans[i] = make(chan *TranscodedPacket, 100)
		workers[i] = make([]*TranscodingWorker, workerPoolSize)
	}

	return &StreamProcessor{
		inputChan:      inputChan,
		outputChans:    outputChans,
		workers:        workers,
		workerPoolSize: workerPoolSize,
		ctx:            ctx,
		cancelFunc:     cancel,
	}
}

func (sp *StreamProcessor) Start() {
	// Create worker pools for each profile
	for profileIndex := range profiles {
		for i := 0; i < sp.workerPoolSize; i++ {
			worker := NewTranscodingWorker(i, profileIndex, sp.inputChan, sp.outputChans[profileIndex], &sp.wg)
			sp.workers[profileIndex][i] = worker
			worker.Start()
		}
	}

	// Start streaming handlers
	sp.wg.Add(1)
	go sp.handleInput()

	for i := range profiles {
		sp.wg.Add(1)
		go sp.handleOutput(i)
	}
}

func (sp *StreamProcessor) Stop() {
	sp.cancelFunc()

	// Stop all workers
	for _, workerPool := range sp.workers {
		for _, worker := range workerPool {
			if worker != nil {
				worker.Stop()
			}
		}
	}

	// Wait for all goroutines to complete
	sp.wg.Wait()

	// Close channels
	close(sp.inputChan)
	for _, ch := range sp.outputChans {
		close(ch)
	}
}

func (sp *StreamProcessor) handleInput() {
	defer sp.wg.Done()

	// Here would be your RTMP or other input source
	// For demonstration purposes, we're using a dummy input

	ticker := time.NewTicker(33 * time.Millisecond) // ~30fps
	defer ticker.Stop()

	for {
		select {
		case <-sp.ctx.Done():
			return
		case <-ticker.C:
			// This is a placeholder for actual video frame input
			sampleData := make([]byte, 1024*100) // dummy data

			sp.inputChan <- &media.Sample{
				Data:      sampleData,
				Timestamp: uint32(time.Now().UnixNano() / 1000000),
			}
		}
	}
}

func (sp *StreamProcessor) handleOutput(profileIndex int) {
	defer sp.wg.Done()

	profile := profiles[profileIndex]
	log.Printf("Starting output handler for profile %dx%d", profile.Width, profile.Height)

	for {
		select {
		case <-sp.ctx.Done():
			return
		case packet, ok := <-sp.outputChans[profileIndex]:
			if !ok {
				return
			}

			// Here you would send the packet to your streaming server
			// This is just a placeholder that logs the packet size
			log.Printf("Output profile %dx%d: Packet size %d bytes", 
				profile.Width, profile.Height, len(packet.Data))
		}
	}
}

func main() {
	// Use all available CPU cores for Go routines
	runtime.GOMAXPROCS(runtime.NumCPU())

	// Calculate optimal worker pool size based on available resources
	workerPoolSize := runtime.NumCPU() / 2
	if workerPoolSize < 1 {
		workerPoolSize = 1
	}

	log.Printf("Starting adaptive bitrate transcoding service with %d workers per profile", workerPoolSize)

	processor := NewStreamProcessor(workerPoolSize)
	processor.Start()

	// Wait for termination signal
	sigChan := make(chan os.Signal, 1)
	signal.Notify(sigChan, syscall.SIGINT, syscall.SIGTERM)
	<-sigChan

	log.Println("Shutting down...")
	processor.Stop()
	log.Println("Service stopped gracefully")
}
